INSERT INTO `cl_settings` (`id`, `site_name`, `logo`, `TTA1`, `TTA2`, `Affiliated1`, `Affiliated2`, `phone`, `usa_phone`, `email_primary`, `usa_email_primary`, `email_secondary`, `usa_email_secondary`, `address`, `usa_address`, `fax`, `skype`, `facebook_link`, `linkedin_link`, `youtube_link`, `twitter_link`, `google_plus`, `instagram_link`, `tiktok_link`, `meta_key`, `meta_description`, `google_map`, `google_map2`, `copyright_text`, `link1`, `link2`, `flight_link`, `flight_brief`, `flight_photo`, `text1_title`, `text1_sub_title`, `text2_title`, `text2_sub_title`, `text3_title`, `text3_sub_title`, `fp_activity`, `fp_training`, `fp_about`, `fp_about_content`, `created_at`, `updated_at`) VALUES
(1, 'Summit 8000', NULL, NULL, NULL, NULL, NULL, '9700056077,  9851015875', '+977 9851357464', 'info@summit8000.com', NULL, NULL, NULL, 'Annapurna marg-4, Chappalkharkhana, Kathmandu, Nepal', NULL, '+977 9851357464', NULL, 'https://www.facebook.com/summit8000exped', 'https://www.linkedin.com/in/summit-eight-thousand-7953223a2/', 'https://www.youtube.com/@Summit8000exped-y2t/videos', 'https://x.com/summit8000exped', 'https://instagram.com/', 'https://www.instagram.com/summit8000exped/', 'https://www.tiktok.com/@summit8000exped', 'Summit 8000 | Himalayan Expeditions by Temba Tsheri Sherpa', 'Summit 8000 is led by Temba Tsheri Sherpa, Guinness World Record holder. Join our expert Himalayan peak climbing expeditions in Nepal. Your summit starts here.', '<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d2331.296832187114!2d85.34148470544724!3d27.736729001807113!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x39eb19308870770d%3A0x5afe8afa09967b48!2sSummit%208000!5e0!3m2!1sen!2snp!4v1770185462314!5m2!1sen!2snp\" width=\"100%\" height=\"100%\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\"\r\n        referrerpolicy=\"no-referrer-when-downgrade\"></iframe>', NULL, 'Copyright © 2026, Summit 8000', NULL, NULL, NULL, 'All content on this website, including text and photographs, is the exclusive property of Summit 8000. Reproduction or use without prior written permission is strictly prohibited. © Summit 8000, 2026.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-04-03 15:30:52');
INSERT INTO `cl_team` (`id`, `name`, `uri`, `team_key`, `position`, `category`, `subcategory`, `fb_url`, `instagram_url`, `twitter_url`, `linkedin_url`, `phone`, `email`, `content`, `brief`, `status`, `ordering`, `banner`, `thumbnail`, `published`, `is_active`, `is_draft`, `is_trashed`, `is_password_protected`, `comment`, `lang`, `created_at`, `updated_at`) VALUES
(1, 'Ashish Gurung', 'ashish-gurung', '1767355180215384079', 'Chairman', '1', NULL, NULL, NULL, NULL, NULL, '+977 9849707306', 'grgashish2010@gmail.com', '<p></p><div><p>Ashish Gurung is the visionary behind Summit Solution Treks &amp; Expedition Pvt. Ltd. A veteran of Nepal’s mountaineering industry, an IFMGA certified mountain guide, Ashish Gurung is a widely respected name among climbers, guides, and adventurers. With decades of hands-on mountaineering and guiding experience, he has been at the heart of numerous successful expeditions across Nepal and beyond. </p></div><div><p>As the Chairman of Summit Solution Treks &amp; Expedition Pvt. Ltd., Ashish provides vision, stability, and inspiration. His long-standing reputation as a leader, climber, and mentor anchors the company’s values of trust, responsibility, and professionalism. Ashish is not only admired for his technical skills on the mountains but also for his ability to guide teams, nurture young climbers, and maintain a culture of safety and ethics. His experience ensures that Summit Solution remains deeply rooted in the traditions of Himalayan guiding while pushing forward with innovation.</p></div><div><p>&nbsp;</p></div><br><p></p>', NULL, '1', 1, '', '2a6463d8-15ed-4145-bf22-387f0955a75d-572MA7vE3YIHn9Orw1IktetKMfh31egjI3mzfufj.JPG', '0', '1', '0', '0', '0', '0', 'en', '2021-03-13 18:39:54', '2026-01-02 22:44:40'),
(18, 'Wivas Poudel', 'wivas-poudel', '1767355720787103530', 'Managing Director', '1', NULL, NULL, NULL, NULL, NULL, '+977 9846049273', 'poudelwivasmbbs@gmail.com', '<p></p><div><p>Wivas Poudel, the driving force behind Summit Solution, brings to the team a rare combination of mountaineering knowledge, academic research, and entrepreneurial vision. Wivas represents the new generation of tourism leaders in Nepal, individuals who are equally comfortable in the field, in research, and in management. Beyond academics, he has contributed to various training programs related to mountaineering, helping future professionals understand the complexities of Himalayan expeditions. &nbsp;</p></div><div><p>Passionate about guiding Nepal’s tourism industry towards a brighter future, Wivas is committed to blending global expedition standards with local expertise. Wivas adds a research-driven perspective to expedition planning.  As Managing Director, Wivas oversees strategy, client relations, and overall company operations. His leadership is rooted in knowledge, sustainability, and innovation, making sure every expedition is not only successful but also safe, meaningful, and environmentally conscious. With his proactive approach, Summit Solution ensures every trip is designed with clarity, safety, and client satisfaction at its core. </p></div><br><p></p>', NULL, '1', 4, '', '5815d7b5-444f-4f3d-aa8f-8cff3a2b81db-jkotSTqj2khpxzB9XJ9w5KzWYyuEUcM1ES13QAii.PNG', '0', '1', '0', '0', '0', '0', 'en', '2025-11-14 09:38:47', '2026-01-02 22:53:40'),
(19, 'Sujan Gurung', 'sujan-gurung', '1767355209627530588', 'Executive Director', '1', NULL, NULL, NULL, NULL, NULL, '+977 9867098371', 'mtgurung706@gmail.com', '<p></p><div><p>A highly skilled IFMGA certified mountaineer with years of practical guiding experience, Sujan Gurung stands at the forefront of our expeditions. Having grown up surrounded by the Himalayan culture of adventure, Sujan has developed not only the technical climbing skills but also the resilience, adaptability, and leadership qualities that make him one of the strongest pillars of our company. </p></div><div><p>Sujan has worked extensively with both domestic and international climbers, supporting successful ascents and trekking journeys across Nepal’s major regions. His practical expertise is strengthened by his academic training in mountaineering studies, giving him a scientific understanding of mountains, safety, and risk management. Clients know Sujan for his approachable personality, motivational spirit, and ability to turn challenges into opportunities. With him as Expedition Director, every climber can be assured of a well-managed, safe, and memorable journey to the Himalayas.</p></div><div><p>&nbsp;</p></div><br><p></p>', NULL, '1', 5, '', 'img-9845-rvJlkpHglG0KsSUfQfX3trBrNzHotLXdAnw98sr3.JPG', '0', '1', '0', '0', '0', '0', 'en', '2025-11-14 09:40:45', '2026-01-02 22:45:09'),
(20, 'Dipan Gurung', 'dipan-gurung', '1767355252817606160', 'Field Director', '1', NULL, NULL, NULL, NULL, NULL, '+977 9840986178', 'gurungdipan08@gmail.com', '<p></p><div><p>Dipan Gurung represents the balance between field expertise and organizational leadership. With a strong background in trekking, expedition and expedition logistics, Dipan ensures that every Summit Solution project runs smoothly from planning to execution. </p></div><div><p>Having spent years in Nepal’s tourism and mountaineering field, Dipan understands both the client’s expectations and the mountain realities. His leadership lies in bridging these two worlds: delivering services that are professional, safe, and tailored to each adventurer’s needs. Dipan is a passionate mountaineer himself, always keen to explore new peaks, routes, and opportunities. His focus on client care, operational excellence, and sustainable tourism practices makes him an indispensable leader within Summit Solution. </p></div><br><p></p>', NULL, '1', 6, '', 'img-9954-3EC8aFOUQB8Xa6LD8XFEqQhzkcdRjjkNcGbl51Kr.JPG', '0', '1', '0', '0', '0', '0', 'en', '2025-11-14 09:42:13', '2026-01-02 22:45:52');
INSERT INTO `cl_trip_activities` (`id`, `activity_parent`, `title`, `sub_title`, `template`, `uri`, `thumbnail`, `thumbnail_alt`, `banner`, `banner_alt`, `excerpt`, `content`, `external_link`, `category_video`, `meta_keyword`, `meta_description`, `ordering`, `status`, `isdefault`, `created_at`, `updated_at`) VALUES
(41, 'trekking', 'Popular Treks in Nepal', NULL, 'triplist', 'popular-treks-in-nepal', '1772110462.jpg', 'Trekking on Everest trail', '17703731035.jpg', 'Trekking on Langtang trail', NULL, '<p data-start=\"112\" data-end=\"631\">Nepal is renowned worldwide for its awe-inspiring Himalayan landscapes, rich cultural heritage, and diverse trekking opportunities. The Popular Treks in Nepal category features the most sought-after trekking routes that cater to adventurers of all levels, from beginners to seasoned mountaineers.</p>\r\n<p data-start=\"112\" data-end=\"631\">These treks offer a perfect blend of natural beauty, cultural experiences, and thrilling challenges, allowing trekkers to witness majestic peaks, glacial rivers, dense forests, and traditional villages along the way.</p>\r\n<p data-start=\"633\" data-end=\"1087\">Iconic trails like Everest Base Camp, Annapurna Base Camp, and Manaslu Circuit are known for their breathtaking mountain panoramas, while lesser-known yet equally captivating treks such as Langtang Valley and Ghorepani Poon Hill offer serene landscapes and rich local culture.</p>\r\n<p data-start=\"633\" data-end=\"1087\">Each trek provides a unique experience, including encounters with Sherpa communities, ancient monasteries, terraced farmlands, and diverse flora and fauna.</p>\r\n<p data-start=\"1089\" data-end=\"1537\">These treks are carefully curated to ensure safety, accessibility, and unforgettable experiences. Whether you are seeking a short adventure, a moderate multi-day hike, or a challenging high-altitude journey, the Popular Treks in Nepal provide options that fulfill every traveler’s dream.</p>\r\n<p data-start=\"1089\" data-end=\"1537\">Explore these iconic trails and immerse yourself in the natural beauty and cultural richness that make Nepal one of the world’s top trekking destinations.</p>', NULL, NULL, 'Popular Treks in Nepal | Top Himalayan Trekking Routes', 'Explore Nepal’s most popular treks, from Everest Base Camp to Annapurna Base Camp. Discover breathtaking Himalayan views, rich culture, and unforgettable trekking adventures.', 1, '1', NULL, '2023-07-13 07:28:34', '2026-02-26 23:39:22'),
(42, 'expedition', '8000m Peak Expeditions in Nepal', NULL, 'triplist', '8000m-peak-expeditions-in-nepal', '1772109807.jpg', 'Sunrise over Everest Peak', '177037677216.png', '8000 meter peak in Nepal', NULL, '<p data-start=\"36\" data-end=\"667\">8000m Peak Expeditions in Nepal represent the ultimate achievement in high-altitude mountaineering. Home to legendary giants like <span class=\"whitespace-normal\">Mount Everest</span>, <span class=\"whitespace-normal\">Lhotse</span>, <span class=\"whitespace-normal\">Makalu</span>, <span class=\"whitespace-normal\">Manaslu</span>, <span class=\"whitespace-normal\">Dhaulagiri</span>, <span class=\"whitespace-normal\">Annapurna I</span>, <span class=\"whitespace-normal\">Kanchenjunga</span>, and <span class=\"whitespace-normal\">Cho Oyu</span>, Nepal offers some of the most iconic and challenging summits on Earth. These expeditions demand peak physical fitness, technical skill, mental resilience, and strong logistical support.</p>\r\n<p data-start=\"669\" data-end=\"974\" data-is-last-node=\"\" data-is-only-node=\"\">Designed for experienced climbers, our 8000m expeditions provide professional guides, strategic acclimatization schedules, high-altitude Sherpa support, and full base camp management. From the Khumbu to the Annapurna and Kanchenjunga regions, each climb is a life-changing journey to the top of the world.</p>', NULL, NULL, '8000m Peak Expeditions in Nepal', 'Join 8000m peak expeditions in Nepal including Everest, Manaslu, and more. Fully guided Himalayan climbs for experienced mountaineers.', 1, '1', NULL, '2023-07-13 07:28:52', '2026-02-26 23:28:27'),
(43, 'expedition', '7000m Peak Expeditions in Nepal', NULL, 'triplist', '7000m-peak-expeditions-in-nepal', '1772110137.jpg', 'Sunrise over 7000 meter peak in Nepal', '177037289517.png', 'Fish tail mountains in Nepal', NULL, '<p data-start=\"36\" data-end=\"460\">7000m Peak Expeditions in Nepal offer a perfect balance between extreme high-altitude challenge and advanced mountaineering experience. These peaks are ideal for climbers preparing for 8000m giants while still demanding strong technical skills, endurance, and proper acclimatization. With dramatic ridgelines, glacier crossings, and remote alpine environments, 7000m mountains deliver a true Himalayan expedition atmosphere.</p>\r\n<p data-start=\"462\" data-end=\"918\" data-is-last-node=\"\" data-is-only-node=\"\">Popular 7000-meter peaks like <span class=\"whitespace-normal\">Himlung Himal</span>, <span class=\"whitespace-normal\">Putha Hiunchuli</span>, <span class=\"whitespace-normal\">Baruntse</span>, and <span class=\"whitespace-normal\">Tilicho Peak</span> provide serious yet achievable summits for experienced climbers. Our fully guided expeditions include professional Sherpa support, high-altitude logistics, acclimatization planning, and base camp management to ensure a safe, successful, and rewarding Himalayan climb.</p>', NULL, NULL, '7000m Peak Expeditions in Nepal | Himalayan Climbing', 'Explore 7000m peak expeditions in Nepal with fully guided Himalayan climbing packages. Ideal for experienced mountaineers preparing for 8000m peaks.', 2, '1', NULL, '2023-07-13 07:34:42', '2026-02-26 23:33:57'),
(47, 'expedition', '6000m Peak Expeditions in Nepal', NULL, 'triplist', '6000m-peak-expeditions-in-nepal', '1772109514.jpg', 'Sunrise over 6000 meter peak in Nepal', '17703728609.jpg', 'Sunrise over 6000 meter mountain', NULL, '<p data-start=\"102\" data-end=\"450\">6000m Peak Expeditions in Nepal are the perfect introduction to Himalayan mountaineering. These climbs offer real high-altitude adventure without the extreme technical demands of 8000-meter expeditions. From stunning alpine ridges to glacier crossings, Nepal’s 6000-meter peaks provide breathtaking Himalayan views and valuable climbing experience.</p>\r\n<p data-start=\"452\" data-end=\"804\" data-is-last-node=\"\" data-is-only-node=\"\">Ideal for aspiring mountaineers and experienced trekkers ready to step higher, these expeditions combine adventure, skill development, and unforgettable summit moments. With professional guides, well-planned itineraries, and fully supported logistics, our 6000m peak climbing packages ensure a safe, rewarding, and truly memorable Himalayan expedition.</p>\r\n<p> </p>', NULL, NULL, '6000m Peak Expeditions in Nepal | Climbing Packages 2026', 'Explore 6000m peak expeditions in Nepal with fully guided climbing packages. Perfect for aspiring mountaineers seeking real Himalayan adventure.', 3, '1', NULL, '2023-07-28 16:37:25', '2026-02-26 23:23:34'),
(75, 'expedition', '14 Peaks Expeditions', NULL, 'triplist', '14-peaks-expeditions', '1774543825.jpg', NULL, '17745438256.jpg', NULL, NULL, '<p>Embark on the ultimate adventure with the 14 Peaks Expedition, exploring Nepal’s highest and most challenging mountains. This category covers detailed guides, trekking and climbing itineraries, altitude information, peak difficulty, best seasons, and essential preparation tips. From the towering Mount Everest to the majestic Kanchenjunga, discover expert insights, cost breakdowns, packing lists, and local culture along each route. Whether you are a professional climber aiming for summits or a trekking enthusiast seeking Himalayan thrills, the 14 Peaks Expedition guides provide everything you need to plan your dream journey in Nepal.</p>', NULL, NULL, '14 Peaks Expedition Nepal | Ultimate Himalayan Trek & Climb Guides', 'Explore Nepal’s 14 highest peaks with detailed itineraries, altitude info, costs, packing lists, and expert trekking & climbing tips for an unforgettable Himalayan adventure.', 4, '0', NULL, '2026-03-27 02:35:25', '2026-03-27 02:35:25');
