INSERT INTO `cl_trip_grade` (`id`, `grade_message`, `trip_grade`, `icon`) VALUES
(1, 'Light walking and generally level hiking that is good for most fitness levels. During these trips, hill-walking experience is desirable.', 'Easy', 'easy.svg'),
(2, 'Trek has various types of moderate to difficult terrain, including rough trails and normally 3 to 5 hours a day. Requires an average to above average fitness level.', 'Moderate', 'moderate.svg'),
(3, 'High altitude treks above 3000 meters or in fairly difficult terrain- normally 4 to 6 hours a day. Requires an above average fitness level and high level of stamina.', 'Challenging', 'hard.svg'),
(4, 'These high altitude treks or passes are known to be the most strenuous and has difficult terrain and conditions. These treks may require a degree of mountaineering skills and you capability of carrying on normally at an altitude of 4000-5600 meters. Daily walking is 5-8 hours approx.', 'Strenuous', 'extreme.svg');
INSERT INTO `cl_trip_groups` (`id`, `title`, `sub_title`, `uri`, `banner`, `content`, `meta_keyword`, `meta_description`, `ordering`, `status`, `created_at`, `updated_at`) VALUES
(3, 'Luxury Trips', '7Zg_aPM2pVc', 'luxury-trip', NULL, '<p>Tourism Industry has been highly commercialized in Nepal lately which instigated the birth of countless Travel enterprises, especially Trekking and Tours organizers. Nevertheless, it is a matter of the fact that one ought to cherry-pick their trip organizer very wisely in order to pursue their dream trip. The question is legitimate and logical that amongst numerous agencies, why to choose Nepal Mountain Trekkers and trust us to spend your valuable time and hard-earned money?</p>', 'Luxury Trips', 'Tourism Industry has been highly commercialized in Nepal lately which instigated the birth of countless Travel enterprises, especially Trekking and Tours organizers. Nevertheless, it is a matter of the fact that one ought to cherry-pick their trip organizer very wisely in order to pursue their dream trip. The question is legitimate and logical that amongst numerous agencies, why to choose Nepal Mountain Trekkers and trust us to spend your valuable time and hard-earned money?', '1', '1', '2022-11-29 08:32:14', '2023-02-01 18:23:36'),
(4, 'Is Popular', 'is popular', 'is-popular', NULL, '<p>For popular trips.</p>', NULL, NULL, '2', '1', '2022-12-09 08:38:26', '2022-12-29 03:02:42'),
(5, 'Experiences', NULL, 'experiences', 'koshi-tappu-national-park-oUnM1D4HSEBFsvGLKlvofwLYub7VZjLTO0FhumP1.jpg', NULL, 'Experiences', 'Experiences', '3', '1', '2023-02-01 18:24:01', '2023-02-01 19:40:24'),
(6, 'Holiday Types', NULL, 'holiday-types', '', NULL, NULL, NULL, '4', '1', '2023-04-27 10:31:05', '2023-04-27 10:31:05');
INSERT INTO `cl_trip_itinerary` (`id`, `trip_detail_id`, `days`, `meals`, `title`, `max_altitude`, `distance`, `duration`, `content`, `ordering`, `created_at`, `updated_at`) VALUES
(1300, 133, '1', NULL, 'Arrival in Islamabad', '500m', NULL, NULL, '<p>\r\n\r\nUpon arrival at Islamabad International Airport, you will be met by our representative and \r\ntransferred to your hotel. You will have the rest of the day to rest and explore the city.\r\n\r\n<br></p>', 1, '2023-07-30 17:33:20', '2023-07-30 17:33:57'),
(1301, 133, '2', NULL, 'Islamabad to Skardu', '2,228m', NULL, NULL, 'After breakfast, you will take a domestic flight to Skardu. Upon arrival, you will be transferred to your hotel. You will have the rest of the day to explore the town and acclimatize to the altitude.', 2, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1302, 133, '3', NULL, 'Skardu to Askole', '3,048m', NULL, '6-7 Hours', 'After breakfast, you will drive to Askole, the last village before the trek. The drive takes around 6-7 hours and passes through the beautiful Shigar Valley. You will camp overnight in Askole.', 3, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1303, 133, '4', NULL, 'Askole to Jhola', '3,100m', NULL, NULL, 'After breakfast, you will start your trek to Jhola. The trail follows the Braldu River and passes through the beautiful Biafo Glacier. You will camp overnight in Jhola', 4, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1304, 133, '5', NULL, 'Jhola to Paiyu', '3,450m', NULL, NULL, 'After breakfast, you will continue your trek to Paiyu. The trail passes through the beautiful Baltoro Glacier and offers stunning views of the surrounding peaks. You will camp overnight in Paiyu.', 5, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1305, 133, '6', NULL, 'Rest day in Paiyu', '3,450m', NULL, NULL, 'Today is a rest day to acclimatize to the altitude. You can explore the surrounding area and enjoy the beautiful views.', 6, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1306, 133, '7', NULL, 'Paiyu to Khoburtse', '3,800m', NULL, NULL, 'After breakfast, you will continue your trek to Khoburtse. The trail passes through the beautiful Paiyu Peak and offers stunning views of the surrounding peaks. You will camp overnight in Khoburtse.', 7, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1307, 133, '8', NULL, 'Khoburtse to Urdukas', '4,100m', NULL, NULL, 'After breakfast, you will continue your trek to Urdukas. The trail passes through the beautiful Goro II and offers stunning views of the surrounding peaks. You will camp overnight in Urdukas.', 8, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1308, 133, '9', NULL, 'Urdukas to Goro II', '4,500m', NULL, NULL, 'After breakfast, you will continue your trek to Goro II. The trail passes through the beautiful Baltoro Glacier and offers stunning views of the surrounding peaks. You will camp overnight in Goro II.', 9, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1309, 133, '10', NULL, 'Goro II to Concordia', '4,600m', NULL, NULL, 'After breakfast, you will continue your trek to Concordia. The trail passes through the beautiful K2 and offers stunning views of the surrounding peaks. You will camp overnight in Concordia.', 10, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1310, 133, '11', NULL, 'Rest day in Concordia', '4,600m', NULL, NULL, 'Today is a rest day to acclimatize to the altitude. You can explore the surrounding area and enjoy the beautiful views.', 11, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1311, 133, '12', NULL, 'Concordia to Masherbrum Base Camp', '4,800m', NULL, NULL, 'After breakfast, you will continue your trek to Masherbrum Base Camp. The trail passes through the beautiful Masherbrum Peak and offers stunning views of the surrounding peaks. You will camp overnight in Masherbrum Base Camp.', 12, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1312, 133, '13-14', NULL, 'Explore Masherbrum Base Camp', '4,800m', NULL, NULL, 'These two days are for exploring the Masherbrum Base Camp and surrounding areas. You can hike to nearby peaks and enjoy the beautiful views.', 13, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1313, 133, '15', NULL, 'Masherbrum Base Camp to Goro II', '4,500m', NULL, NULL, 'After breakfast, you will start your trek back to Goro II. You will camp overnight in Goro II.', 14, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1314, 133, '16', NULL, 'Goro II to Khoburtse', '3,800m', NULL, NULL, 'After breakfast, you will continue your trek to Khoburtse. You will camp overnight in Khoburtse.', 15, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1315, 133, '17', NULL, 'Khoburtse to Paiyu', '3,450m', NULL, NULL, 'After breakfast, you will continue your trek to Paiyu. You will camp overnight in Paiyu.', 16, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1316, 133, '18', NULL, 'Paiyu to Jhola', '3,100m', NULL, NULL, 'After breakfast, you will continue your trek to Jhola. You will camp overnight in Jhola.', 17, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1317, 133, '19', NULL, 'Jhola to Askole', '3,048m', NULL, NULL, 'After breakfast, you will continue your trek to Askole. You will camp overnight in Askole.', 18, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1318, 133, '20', NULL, 'Askole to Skardu', '2,228m', NULL, NULL, 'After breakfast, you will drive back to Skardu. You will have the rest of the day to explore the town and relax.', 19, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1319, 133, '21', NULL, 'Skardu to Islamabad', '500m', NULL, NULL, 'After breakfast, you will take a domestic flight back to Islamabad. Upon arrival, you will be transferred to your hotel. You will have the rest of the day to explore the city.', 20, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1320, 133, '22', NULL, 'Departure from Islamabad', NULL, NULL, NULL, 'After breakfast, you will be transferred to Islamabad International Airport for your departure flight.', 21, '2023-07-30 17:44:05', '2023-07-30 17:44:05'),
(1355, 135, '1', NULL, 'Arrival in Islamabad', NULL, NULL, NULL, 'Upon arrival in Islamabad, you will be greeted by our representative and transferred to your hotel. You will have a briefing about the trek and have time to explore the city.', 1, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1356, 135, '2', NULL, 'Islamabad to Skardu', NULL, NULL, '1 Hour', 'Today, you will take a flight from Islamabad to Skardu, which is the starting point of the trek. The flight takes around 1 hour and you will have stunning views of the Himalayas along the way.', 2, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1357, 135, '3', NULL, 'Skardu', NULL, NULL, NULL, 'Today, you will have a rest day in Skardu. You can explore the city and visit the famous Kharpocho Fort.', 3, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1358, 135, '4', NULL, 'Skardu to Askole', NULL, NULL, '6-7 Hours', 'Today, you will drive to Askole, which is the starting point of the trek. The drive takes around 6-7 hours and you will pass through beautiful landscapes and small villages.', 4, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1359, 135, '5', NULL, 'Askole to Jhola', '3,100m', NULL, NULL, 'Today, you will start your trek and walk through lush forests, rice paddies, and small villages. You will reach Jhola, which is a small village located at an altitude of 3,100 meters.', 5, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1360, 135, '6', NULL, 'Jhola to Paiju', '3,450m', NULL, NULL, 'Today, you will continue your trek and cross the Braldu River several times. You will pass through beautiful landscapes and reach Paiju, which is a small village located at an altitude of 3,450 meters.', 6, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1361, 135, '7', NULL, 'Paiju to Khoburtse', '3,600m', NULL, NULL, 'Today, you will trek through beautiful forests and reach Khoburtse, which is a small village located at an altitude of 3,600 meters. You will have stunning views of the Baltoro Glacier along the way.', 7, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1362, 135, '8', NULL, 'Khoburtse to Urdukas', '4,130m', NULL, NULL, 'Today, you will trek to Urdukas, which is a small village located at an altitude of 4,130 meters. You will pass through beautiful landscapes and have stunning views of the Himalayas.', 8, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1363, 135, '9', NULL, 'Urdukas to Goro II', '4,350m', NULL, NULL, 'Today, you will trek to Goro II, which is a small village located at an altitude of 4,350 meters. You will have stunning views of the Baltoro Glacier along the way.', 9, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1364, 135, '10', NULL, 'Goro II to Concordia', '4,600m', NULL, NULL, 'Today, you will trek to Concordia, which is a small village located at an altitude of 4,600 meters. You will have stunning views of the Himalayas, including K2, Broad Peak, and Gasherbrum.', 10, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1365, 135, '11', NULL, 'Rest day in Concordia', NULL, NULL, NULL, 'Today, you will have a rest day in Concordia. You can explore the village and interact with the locals.', 11, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1366, 135, '12', NULL, 'Trek to K2 Base Camp', '5,150m', NULL, NULL, 'Today, you will trek to K2 Base Camp, which is located at an altitude of 5,150 meters. You will have stunning views of K2 and the surrounding Himalayas.', 12, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1367, 135, '13-15', NULL, 'Explore K2 Base Camp', NULL, NULL, NULL, 'These days will be spent exploring K2 Base Camp and the surrounding areas. You can hike to nearby glaciers and have stunning views of the Himalayas.', 13, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1368, 135, '16', NULL, 'Trek back to Concordia', NULL, NULL, NULL, 'Today, you will trek back to Concordia and spend the night there.', 14, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1369, 135, '17', NULL, 'Trek to Ali Camp', '5,100m', NULL, NULL, 'Today, you will trek to Ali Camp, which is a small village located at an altitude of 5,100 meters. You will have stunning views of the Himalayas along the way.', 15, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1370, 135, '18', NULL, 'Trek to Goro I', '4,300m', NULL, NULL, 'Today, you will trek to Goro I, which is a small village located at an altitude of 4,300 meters. You will have stunning views of the Baltoro Glacier along the way.', 16, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1371, 135, '19', NULL, 'Trek to Khoburtse', NULL, NULL, NULL, 'Today, you will trek back to Khoburtse and spend the night there.', 17, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1372, 135, '20', NULL, 'Trek to Paiju', NULL, NULL, NULL, 'Today, you will trek back to Paiju and spend the night there.', 18, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1373, 135, '21', NULL, 'Trek to Jhola', NULL, NULL, NULL, 'Today, you will trek back to Jhola and spend the night there', 19, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1374, 135, '22', NULL, 'Trek to Askole', NULL, NULL, NULL, 'Today, you will trek back to Askole and spend the night there.', 20, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1375, 135, '23', NULL, 'Drive to Skardu', NULL, NULL, NULL, 'Today, you will drive back to Skardu and spend the night there.', 21, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1376, 135, '24', NULL, 'Skardu to Islamabad', NULL, NULL, NULL, 'Today, you will take a flight from Skardu to Islamabad and spend the night there.', 22, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(1377, 135, '25', NULL, 'Departure', NULL, NULL, NULL, 'Today, you will be transferred to the airport for your flight back home.', 23, '2023-07-30 18:34:25', '2023-07-30 18:34:25'),
(3169, 276, '1', NULL, 'Arrival in Kathmandu (1,300 m / 4,264 ft.)', NULL, NULL, NULL, 'Arrive at Tribhuvan International Airport in Kathmandu, where our team will receive you and transfer you to your hotel. After settling in, there will be a brief discussion about the expedition, including the route, schedule, safety protocols, and what to expect in the coming days. This session ensures all climbers are prepared and informed before the adventure begins.', 1, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3170, 276, '2', NULL, 'Sightseeing in Kathmandu', NULL, NULL, NULL, 'Spend the day exploring the rich cultural heritage of Kathmandu. Visit iconic sites such as Swayambhunath Stupa, Boudhanath Stupa, Pashupatinath Temple, and the historic Durbar Square. This is also a chance to purchase any last-minute gear and experience the local culture, cuisine, and traditions.', 2, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3171, 276, '3', NULL, 'Paperwork and Preparations', NULL, NULL, NULL, 'Dedicate this day to completing all necessary permits, paperwork, and final expedition arrangements. Guides will review the climbing plan, medical requirements, and logistics, ensuring that everything is in order for a smooth journey to Tibet. This day also allows for rest and final packing.', 3, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3172, 276, '4', NULL, 'Drive to Zangmu (2,350 m / 7,710 ft.)', NULL, NULL, NULL, 'Begin the overland journey to the Tibet border town of Zangmu. The drive offers stunning views of the Himalayan foothills, rivers, and Tibetan landscapes. This day is primarily for travel and acclimatization, helping the body adjust to increasing altitudes.', 4, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3173, 276, '5', NULL, 'Drive to Nyalam (3,750 m / 12,303 ft.)', NULL, NULL, NULL, 'Continue the journey deeper into Tibet, arriving at Nyalam. The town is known for its Tibetan culture and stunning mountain vistas. Overnight at a local hotel provides an opportunity to rest and further acclimatize.', 5, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3174, 276, '6', NULL, 'Drive to Tingri (4,349 m / 14,268 ft.)', NULL, NULL, NULL, 'Drive to Tingri, a small Tibetan settlement that serves as a gateway to Everest. The route offers panoramic views of the Himalayas, including glimpses of Everest and Cho Oyu. Tingri’s high-altitude environment prepares climbers for the upcoming ascent', 6, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3175, 276, '7', NULL, 'Acclimatization Day at Tingri', NULL, NULL, NULL, 'Spend the day acclimatizing with light walks and rest. This is crucial for preventing altitude sickness. Guides may organize short hikes to help climbers adapt to higher elevations while enjoying breathtaking views of the surrounding mountains.', 7, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3176, 276, '8', NULL, 'Drive to Everest Base Camp (5,200 m / 17,060 ft.)', NULL, NULL, NULL, 'Drive along the Tibetan plateau to the Everest North Base Camp. This is the official starting point of the climb. Settle into camp, familiarize yourself with the facilities, and begin preparing gear for the climbing phase.', 8, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3177, 276, '9-10', NULL, 'At Tibet Base Camp (5,200 m / 17,060 ft.)', NULL, NULL, NULL, 'Spend these days at Base Camp for acclimatization and orientation. Activities include light hikes, gear checks, and team briefings. This period allows climbers to adjust to the high altitude, essential for a safe and successful ascent.', 9, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3178, 276, '11-12', NULL, 'Rest and Preparation at Base Camp', NULL, NULL, NULL, 'Optional buffer days for rest, weather adjustment, and further acclimatization before moving to higher camps.', 11, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3179, 276, '13', NULL, 'Move to Intermediate Camp (6,200 m / 20,341 ft.)', NULL, NULL, NULL, 'Climb to the Intermediate Camp, where climbers experience steeper terrain and higher altitudes. Focus on maintaining proper acclimatization, hydration, and energy levels. This stage is critical for preparing the body for the challenges ahead.', 13, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3180, 276, '14', NULL, 'Move to Advanced Base Camp (6,500 m / 21,325 ft.)', NULL, NULL, NULL, 'Advance to the next camp, which serves as the staging point for the final summit push. Spend time resting, organizing equipment, and preparing mentally and physically for the long climbing period ahead.', 14, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3181, 276, '15-53', NULL, 'Climbing Period', NULL, NULL, NULL, 'This phase involves multiple rotations between higher camps, acclimatization climbs, and ultimately the summit attempt. The climbing period is flexible depending on weather, acclimatization, and individual progress. Guides closely monitor all climbers for safety during the technical ascent.', 15, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3182, 276, '54', NULL, 'Return to Advanced Base Camp (6,500 m / 21,325 ft.)', NULL, NULL, NULL, 'After completing the summit attempt, descend to the Advanced Base Camp for rest and recovery. This stage allows climbers to relax, celebrate achievements, and prepare for further descent.', 16, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3183, 276, '55', NULL, 'Return to Base Camp (5,200 m / 17,060 ft.)', NULL, NULL, NULL, 'Descend to Base Camp, where climbers can enjoy the final moments of the high-altitude environment and organize gear for the journey back to lower elevations.', 17, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3184, 276, '56', NULL, 'Cleaning Base Camp', NULL, NULL, NULL, 'Participate in environmental conservation by cleaning and packing up Base Camp. This ensures that the area remains pristine and contributes to responsible mountaineering practices.', 18, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3185, 276, '57', NULL, 'Drive to Nyalam and Stay at Hotel', NULL, NULL, NULL, 'Begin the return journey to Nyalam, enjoy a comfortable stay at a local hotel, and rest after the long climb. This also allows climbers to reflect on the expedition and enjoy Tibetan culture one last time.', 19, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3186, 276, '58', NULL, 'Drive to Kathmandu and Transfer to Hotel', NULL, NULL, NULL, 'Return to Kathmandu by road, completing the overland journey from Tibet. Transfer to your hotel for rest, relaxation, and a warm shower after the long expedition.', 20, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3187, 276, '59', NULL, 'Stay in Kathmandu', NULL, NULL, NULL, 'Enjoy a free day in Kathmandu to relax, shop for souvenirs, or explore any sites missed at the beginning sof the trip. This day serves as a decompression period after the high-altitude expedition.', 21, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3188, 276, '60', NULL, 'Final Departure', NULL, NULL, NULL, 'Transfer to Tribhuvan International Airport for your onward flight. Depart with memories of an unforgettable adventure, having experienced the challenges and triumphs of climbing Everest via the North Face in Tibet.', 22, '2026-02-03 23:07:03', '2026-02-03 23:07:03'),
(3218, 278, '1', NULL, 'Arrival in Kathmandu Valley', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Namaste and welcome to Kathmandu valley the gateway to your dream destinations. One of our team mates from our company will be waiting for you at the airport with your banner name. Upon meeting you will have meet and greet session and we will drive to Thamel. Rest and relax for the day.</p>', 1, '2026-02-19 22:40:07', '2026-03-16 16:47:17'),
(3219, 278, '2', NULL, 'Preparations for the Expeditions and Sightseeing', '1400', '4 Star Hotel', 'B, L, & D', '<p>Today will be the day when your guide will meet you and he will help you to do buy or renting the packing lists required for the Baruntse expeditions. You will get many gears and equipment shops and from them our guide will find the best shop for you. After getting your packing lists done you will get the permits as well on the same day. After completing all these things if you are left with some time we would suggest you to visit the nearby Swayambhu Nath Stupa for the city view and hiking experience.</p>', 2, '2026-02-19 22:40:07', '2026-04-05 11:56:39'),
(3220, 278, '3', NULL, 'Fly to Lukla (2,860m) and Trek to Chutanga', '3100', 'Tea House', 'B, L, & D', '<p>Early in the morning you will have a flight to Lukla. Yes, you heard it right the airport is not only gateway to the Everest region treks but it’s also the gateway to the Baruntse, Everest, Cho Oyu and surround peak climbing. You will have 35 minutes flights above the mountain and then reach Lukla. Upon reaching the place you will start your trek to the Chutanga village. It’s a peaceful campsite forests which is known for its majestic views of the surrounding peaks and then the beautiful Rhododendron forests.</p>', 3, '2026-02-19 22:40:07', '2026-04-05 11:56:39'),
(3221, 278, '4', NULL, 'Chutanga to Tuli Kharka via Zatrawa La Pass', '4600', 'Tea House', 'B, L, & D', '<p>Today will be the most demanding trek for you as you will be crossing the Zatrawa la pass at the altitude of the 4,610m (15,125ft) above sea level. The pass is known for its beautiful mountain passes and the gateway to the Hinku Valley which is in another Makalu region and it separate the Everest region with the Makalu.</p>', 4, '2026-02-19 22:40:07', '2026-04-05 11:56:39'),
(3222, 278, '5', NULL, 'Trek from Tuli Kharka to Kothe', '3580', 'Tea House', 'B, L, & D', '<p>Early morning trek to the Kothe a beautiful village entry to the Hinku valley. From the valley you will be crossing the dense rhododendron and bamboo forests, crossing streams and ridges. Upon reaching the Kothe you will see that it’s a small settle which is made seasonally for the climbers who wants to summit the Mera peak and the Baruntse peak.</p>', 5, '2026-02-19 22:40:07', '2026-04-05 11:56:39'),
(3223, 278, '6', NULL, 'Trekking from Kothe to Thangnak', '4350', 'Tea House', 'B, L, & D', '<p>You will stat your day from the walking to the Thangnak village which is a high-altitude village alongside the Hinku river. It is known for its alpine valley due to the high-altitude deserts and no sign of the forests. On the way you can experience the soothing sound of the Hinku river flowing in its potential along side the trail. Upon reaching your summit team will also do the health monitoring for your safety.</p>', 6, '2026-02-19 22:40:08', '2026-04-05 11:56:39'),
(3224, 278, '7', NULL, 'Walking from Thangnak to Khare', '5045', 'Tea House', 'B, L, & D', '<p>Start your day with the hearty breakfast in your accommodations. After the guide brief you will head towards the Khare village in the Makalu region. You will be ascending towards the Khare alongside the glacier moraines and specular mountain views. Witness the dramatic mountain views of the Mera peak, Kusum Kanguru, and the Charpate Himal.</p>', 7, '2026-02-19 22:40:08', '2026-04-05 11:56:39'),
(3225, 278, '8', NULL, 'Acclimatization Day at Khare', '5045', 'Tea House', 'B, L, & D', '<p>As the Khare village is located at an altitude of the 5,054m its necessary for you to acclimate properly to adapt the high-altitude thin air. For the adaption of the thin air we will have a hike to the nearby short rides from where you can witness the dramatic landscapes. As it’s the rest day you will have a practice for the ice axe technique, crampons walking, fixed rope ascending and descending.</p>', 8, '2026-02-19 22:40:08', '2026-04-05 11:56:39'),
(3226, 278, '9', NULL, 'Khare to Khamedingma', '5300', 'Tea House', 'B, L, & D', '<p>You will walk to the Khamedingma the beautiful alpine basin in the region which is known for its fully remote wilderness before the climbing starts. From this place you will have the proper experience of the ice falls and the glacier valleys. On the way you will cross the rocky moraines and the glacier sections. Our climbing crew will establish the tented accommodations in the Khamedingma.</p>', 9, '2026-02-19 22:40:08', '2026-04-05 12:00:49'),
(3227, 278, '10', NULL, 'Khamedingma to Seto Pokhari', '5035', 'Tea House', 'B, L, & D', '<p>You will have a climb to the Seto Pokhari which translate as the white pond in the upper mountain regions. The Seto Pokhari is a sacred high-altitude lake and it’s also known for its reflections of the Baruntse peak. The environment here is serene and the peaceful. If you love photography then it’s the perfect place for you.</p>', 10, '2026-02-19 22:40:08', '2026-04-05 12:00:49'),
(3228, 278, '11', NULL, 'Seto Pokhari to Baruntse Base Camp', '5300', 'Camp', 'B, L, & D', '<p>Today will be the day for the true adventure which will excite you for your climbing journey as you will be trekking to the base of the Baruntse. The distance between the Seto Pokhari to Base camp is around 8 kilo meters which can be reached in the 6 hours. Upon reaching the base camp you will see the tented accommodations ready for you along with the kitchen tent, dinning tent, sleeping tents, and the medical supplies and backups for your safety.</p>', 11, '2026-02-19 22:40:08', '2026-04-05 12:00:49'),
(3229, 278, '12', NULL, 'Acclimatization & Rotation Climbs (Camp I & Camp II)', '6400', 'Camp', 'B, L, & D', '<p>During this phase, we set up Camp I (5,700m) and Camp II (6,400m) while following a gentle climb high, sleep low rotation moving up from Base Camp, touching higher ground, and returning to rest. Along the way, you practice fixed-rope climbing, glacier travel, and crevasse rescue, with strong Sherpa support for load carrying and safety. Plenty of rest and careful weather watching keep the pace flexible, safe, and perfectly timed for the summit push.</p>', 11, '2026-02-19 22:40:08', '2026-04-05 12:00:49'),
(3230, 278, '13 to 25', NULL, 'Summit Push (Baruntse Summit 7,129m)', '7129', 'Camp', 'B, L, & D', '<p>The summit push is the most exciting and rewarding phase of the expedition, carefully spread over several days to maximize safety and success. You will move steadily upward from Base Camp to Camp I, then continue to Camp II, and, if conditions require, establish an optional Camp III higher on the mountain. On summit day, you begin well before midnight, ascending steep 45–55° snow slopes and following fixed ropes along exposed ridges under a sky full of stars. Reaching the 7,129m summit of Baruntse at sunrise is a truly magical moment, with jaw-dropping views of Everest, Lhotse, Makalu, Cho Oyu, and even distant Kanchenjunga. After celebrating this once-in-a-lifetime achievement, climbers descend carefully back through the camps and return safely to Base Camp the following day, carrying unforgettable memories from the top of the Himalayas</p>', 12, '2026-02-19 22:40:08', '2026-04-05 12:00:49'),
(3237, 282, '1', NULL, 'Arrival in Kathmandu', '1350', '4 Star Hotel', 'Welcome Dinner', '<p>Welcome to Kathmandu. Our team member from Summit 8000 will be waiting for you at the arrival gate with your name. After the meeting, you will have a small meet and greet ceremony where our team member will put a mala and tika on you and drive you to Thamel. In the evening you can explore the Thamel husting and bustling streets.</p>', 1, '2026-02-24 03:16:47', '2026-04-08 14:43:26'),
(3238, 282, '2 to 4', NULL, 'Expeditions, Preparations, and Sightseeing', '1350', '4 Star Hotel', 'Breakfast', '<p>From the 2nd to the 4th, you will meet your guide. Your guide will give you instructions on how to buy the gear and equipment for you. You can buy or rent the items. You will need to select high-quality materials for your safety. You will need to re-check the missing equipment and do proper inspections. You shall try everything and check if it\'s working or not. After everything is done, you will get your permits ready for the climbing. After that, if you still have time left, you may do some sightseeing in Kathmandu Valley. Also, your guide will brief you on everything about the expeditions.</p>', 2, '2026-02-24 03:16:47', '2026-04-08 14:43:26'),
(3239, 282, '5', NULL, 'Fly Kathmandu–Lukla and trek to Phakding', '2610', 'Tea House', 'B, L, & D', '<p>Early in the morning, you will have your breakfast, and then our company vehicle will come to pick you up from your hotel and drop you off at the airport. After that, you will f ly to Lukla. The flight is around 35 minutes above the valleys and mountains. Upon reaching Lukla, you will trek to Phakding via the lush green forests of pines and Rhododendron.</p>', 3, '2026-02-24 03:16:47', '2026-04-08 14:43:26'),
(3240, 282, '6', NULL, 'Trek from Phakding to Namche Bazar', '3440', '4 Star Hotel', 'B, L, & D', '<p>You will have an early morning hike to Namche Bazar, the market hub in the Khumbu region. You will walk via the beautiful suspension bridges like the Tenzing Hillary suspension bridge, which is named after the first mount Everest climber Tenzing Hillary. You will walk through the beautiful valleys and reach Namche.</p>', 4, '2026-02-24 03:16:47', '2026-04-08 14:43:26'),
(3241, 282, '7', NULL, 'Acclimatization at Namche Bazar', '3440', '4 Star Hotel', 'B, L, & D', '<p>Today will be the acclimatization day for you at Namche Bazar. You will hike to the Everest View hotel from where you can witness the breathtaking views of Mount Everest (8848 m, which will be summiting its peak. Along with that, you will see the surrounding peaks like the Lhotse (8,516), Nuptse (7,861), Ama Dablam (6,812), and many more. You may visit the Sherpa museum, where you can learn about their history, their cultures, their traditions, and their bravery.</p>', 7, '2026-02-24 03:18:58', '2026-04-08 14:43:26'),
(3242, 282, '8', NULL, 'Namche to Tengboche', '3870', 'Tea House', 'B, L, & D', '<p>You will trek to Tengboche on the 8th day. You will be trekking through the red and white Rhododendron forests along the Dudh Koshi River, following the streams. You will cross the suspension bridges and reach your destinations. Upon reaching, you can visit the Tengboche monastery, which is a famous monastery inside the Everest region, as it is the largest in the region</p>', 8, '2026-02-24 03:18:58', '2026-04-08 14:43:27'),
(3243, 282, '9', NULL, 'Walk from Tengboche to Dingboche', '4410', 'Tea House', 'B, L, & D', '<p>You will have an early morning walk from Tengboche to Dingboche. You will have your breakfast in the tea house. On the way, you will cross some wooden bridges and descend at first through the green forests. After that, you will ascend from the Debouche villages, from where you can witness the first glimpse of the alpine shrubs.</p>', 9, '2026-02-24 03:18:58', '2026-04-08 14:43:27'),
(3244, 282, '10', NULL, 'Acclimatization day at Dingboche', '4410', 'Tea House', 'B, L, & D', '<p>As you are closer to the EBC, it\'s important for you to acclimate yourself so that you don’t feel any difficulty breathing. Following this, you will have a short walk around the village via the small chortens and prayer flags. You will walk to the Nangkartshang Peak, which is located at an altitude of 4,700 m, and return to the village, which will help you to acclimate.</p>', 10, '2026-02-24 03:25:32', '2026-04-08 14:43:27'),
(3245, 282, '11', NULL, 'Trek Dingboche to Lobuche', '4940', 'Tea House', 'B, L, & D', '<p>We understand your curiosity to reach the EBC and start your climb, but before that, it\'s important for you fight the high altitude and AMS problems due to which you will need to follow this itinerary as well. You will go via the well-marked terrains, crossing small streams and agricultural areas. You will start to see the rocky surroundings, glacier moraines, and uneven trails.</p>', 11, '2026-02-24 03:25:32', '2026-04-08 14:43:27'),
(3246, 282, '12', NULL, 'Trek Lobuche to Gorak Shep', '5170', 'Tea House', 'B, L, & D', '<p>Today you will be starting your trip from Lobuche to Gorakshep, the last village before the Everest base camp. You will pass through the glacier moraines and small glacier streams. You will walk on the high-altitude deserts. Upon reaching, you can relax, and in the evening you will have a walk to the Gorakshep viewpoint to witness the sunset over the mountains.</p>', 12, '2026-02-24 03:25:32', '2026-04-08 14:43:27'),
(3247, 282, '13', NULL, 'Hike to Kala Patthar and trek to Everest Base  Camp', '5545', 'Camp', 'B, L, & D', '<p>In the morning, you will hike to the Kala Patthar at an altitude of 5545 m from where you can witness the beautiful views of the Everest and its surrounding peaks. You will walk via zigzag rocky trails, and after that, you will trek to the EBC. During the walk, you will cross the glacial moraine and sandy paths. After reaching the base camp, you will finally reach the foot of the world\'s highest mountain, and your goal will be to climb to its top within 3 months. While a normal trekker will return from there, you can stay there inside your tent with your expedition team.</p>', 13, '2026-02-24 03:25:32', '2026-04-08 14:43:27'),
(3248, 282, '14', NULL, 'Rest, Puja ceremony, and training at Everest Base  Camp.', '5364', 'Camp', 'B, L, & D', '<p>You will have a rest day. And it\'s important for you to perform a puja ceremony, which is the worship of mountains. As local people believe the mountain is a god, they need to worship and take blessings, so you do. After performing all the rituals, you will be ready to embark on your journey to the heights. You will have the training of technical skills, yes, it\'s not learning, but it’s a revision.</p>', 14, '2026-02-24 03:25:32', '2026-04-08 14:43:27'),
(3249, 282, '15 to 85', NULL, 'Rotation climbs, summit, and return to Base  Camp', '8848.86', 'Camp', 'B, L, & D', '<p>From day 15 to 85, your true adventure spirit will test you. You will acclimate yourself in the mountains along with the rotations climbs from Camp I (6,065m), Camp II (6,400m), and Camp III (7,200m). After completing your rotations and climbs, you will do the summit push on the South Col route. To the top of the world at an altitude of 8,848.86. Please be careful, listen to your guide, and follow all rules and regulations of climbing the peak.</p>', 15, '2026-02-24 03:25:32', '2026-04-08 14:43:27'),
(3250, 282, '86', NULL, 'Trek down from EBC to Gorakshep', '5170', 'Tea House', 'B, L, & D', '<p>After completing your Mount Everest expeditions, congratulate yourself on doing it. After that, you will trek down to Gorakshep from the EBC to rest and relax. You can enjoy your time with the locals and share your interesting stories with them. Upon reaching Gorakshep, you can again visit the Kala Patthar to witness the peak that you just summited.</p>', 16, '2026-02-24 03:25:32', '2026-04-08 14:43:27'),
(3251, 282, '87', NULL, 'Walk down from Gorak Shep to Pheriche', '4240', 'Tea House', 'B, L, & D', '<p>As you have already conquered the Everest peak and acclimated yourself, it would be easy for you to trek down from Gorakshep to Pheriche. Your trail will be descending via the alpine moraines and beautiful surroundings. You will pass through beautiful villages like the Lobuche, Thukla, and finally reach Pheriche</p>', 17, '2026-02-24 03:25:32', '2026-04-08 14:43:27'),
(3252, 282, '88', NULL, 'Trek down from Pheriche to Namche Bazar', '3440', '4 Star Hotel', 'B, L, & D', '<p>As you descend towards Namche Bazar, you will see the beautiful villages like Pangboche and Tengboche. You will go down via crossing the suspension bridges, and the scenic villages that lie on the way. Upon reaching Namche, you can relax and enjoy the beautiful views and the local foods. You can visit the different bakeries and cafes, you can take a hot shower, and enjoy your dinner.</p>', 18, '2026-02-24 03:25:32', '2026-04-08 14:43:27'),
(3253, 282, '89', NULL, 'Namche to Luka and fly to Kathmandu', '1350', '4 Star Hotel', 'Farewell Dinner', '<p>Early in the morning, you start your journey towards Lukla, which will be an easy descent via the beautiful, well-marked trails. You can interact with the locals and enjoy your last day of adventure in the mountains. Upon reaching Lukla, you will fly to Kathmandu, which will be a 35-minute flight. Upon reaching, you can relax and then enjoy your last day in Kathmandu.</p>', 89, '2026-02-24 03:27:14', '2026-04-08 14:43:27'),
(3254, 282, '90', NULL, 'Departure', '350', NULL, 'Breakfast', '<p>Early in the morning, you will head towards the gear and equipment shops and return the things that you rented. And the things that you bought, you can carry yourself. We will have a flight schedule for you, and according to that, we will drop you off at the airport at least 4 hours before completing your visa and immigration-related work. We hope we served you best and wish to welcome you again to climb some other mountains like the <span style=\"color: #236fa1;\"><a style=\"color: #236fa1;\" href=\"/trip/annapurna-expeditions-in-nepal\">Annapurna – 1</a></span>, Dhaulagiri, Makalu, or any other peaks.</p>', 90, '2026-02-24 03:27:14', '2026-04-08 14:43:27'),
(3255, 283, '1', NULL, 'Arrival in Kathmandu', 'Tourist Standard Hotel', NULL, 'Welcome Dinner', '<p>Greetings from Summit 8000. One of our team members will be waiting for you at the airport to welcome you. After the meeting, you will be assisted to your hotel in Thamel, as it is the tourist hub. Upon reaching, relax and enjoy your day. In the evening, you can have a stroll around the marketplace.</p>', 1, '2026-02-24 04:08:39', '2026-02-24 04:09:14'),
(3256, 283, '2', NULL, 'Expeditions briefing, Gears and Equipment buying, and obtaining permits', 'Tourist Standard Hotel', NULL, 'Breakfast', '<p>Today, early in the morning, you will have your breakfast with your guide, who will brief you about the expeditions. After that, you and our guide will go to the market to buy your gear and equipment which you will require during the trek and climb. You can rent or buy, depending on your preference. Please buy each and every items our guide suggests you can have a safe climb. After completing the shopping, you can take the items to your hotel and pack for the next day. Also, you will need to obtain the permits on the same day that our guide will be assisting you to obtain.</p>', 2, '2026-02-24 04:08:39', '2026-02-24 04:09:14'),
(3257, 283, '3', NULL, 'Fly from Kathmandu to Pokhara', 'Tourist Standard Hotel', NULL, 'Breakfast', '<p>Early in the morning, our guide, along with the driver, will come to pick you up at your hotel. You can have your breakfast and load your duffel bags, trekking, and everything in the vehicle. If you have a suitcase, you can shift the items from the suitcase to duffel bags and trekking bags and leave them in the hotel. Upon returning, you can take it again. After that, you will drive to the Tribhuvan International Airport and fly from Kathmandu to Pokhara. The flight time is around 25 minutes above the mountains and valleys. Upon reaching, you will be transferred to the hotel. After that, you can have the sightseeing in Pokhara and explore the Phewa Lake, Pumditkot, David falls, and many more.</p>', 3, '2026-02-24 04:08:39', '2026-02-24 04:09:14'),
(3258, 283, '4', NULL, 'Fly from Pokhara to Annapurna Base Camp', 'Tea House', NULL, 'B, L, & D', '<p>You will have a Heli flight from Pokhara to Annapurna base camp. The flight time will be of 30 minutes while approaching the Annapurna peaks along with the surrounding peaks like the Machapuchhare and Dhaulagiri. The flight from Pokhara to ABC seems so perfect in terms of scene and beauty. Upon reaching the ABC, you can click photographs and relax at your tent house. You will get the perfect sunset views of Annapurna I from the ABC. You will have a short hike to the nearby ridges so that you can acclimate yourself.</p>', 4, '2026-02-24 04:08:39', '2026-02-24 04:09:14'),
(3259, 283, '5 to 29', NULL, 'Rotation Periods', 'Tent', NULL, 'B, L, & D', '<p>From the day 5th you will have practice of climbing, using ropes, crampons, axes, ice arrest, and many more. Along with that, you will have the climbing and rotations periods, which means you will start your climb from the Annapurna base camp, conquer Camp I, conquer it, and return to ABC, and then again from ABC to Camp I, and then from Camp I to II, and again return to ABC. Along with that, you will have a gradual ascent to the terrains, and you will learn about the mountains.</p>', 5, '2026-02-24 04:08:39', '2026-02-24 04:09:14'),
(3260, 283, '29 to 37', NULL, 'Summit Climbing Period', 'Tent', NULL, 'B, L, & D', '<p>Your summit climbing period will start from the 29th day after you successfully climbed the different camps and conquered. Now you will climb from the base camp to Camp I, Camp II, Camp III, Camp Iv and from Camp Iv you will summit the peak at an altitude of 8,091 meters. After a successful summit, you can congratulate yourself for achieving what other dreams of.</p>', 6, '2026-02-24 04:08:39', '2026-02-24 04:09:14'),
(3261, 283, '38', NULL, 'Heli Flight from Annapurna I Base Camp to Pokhara', 'Tourist Standard Hotel', NULL, 'Dinner', '<p>After your successful summit of the Annapurna peak, I will descend to the base camp. Our helicopter will come to pick you up from the camp. You can fly from there to Pokhara and rest at your hotel. Also in the evening, we will invite you to the congratulations dinner were we will share our stories, difficulties, and everything we felt on the climb.</p>', 7, '2026-02-24 04:08:39', '2026-02-24 04:09:14'),
(3262, 283, '39', NULL, 'Flight from Pokhara to Kathmandu', 'Tourist Standard Hotel', NULL, 'Breakfast', '<p>You will have a flight from Pokhara to Kathmandu, which will be of again 25 minutes. Upon reaching, you can rest for a while. After that, you can return the climbing gear and equipment’s which you rented. You can take your suitcase from the hotel and pack your belongings for the next day. You can also visit the different places in Kathmandu valley, such as the Sawayambhunath stupa, Boudhanath stupa, and Kathmandu durbar square. And many more.</p>', 8, '2026-02-24 04:08:39', '2026-02-24 04:09:14'),
(3263, 283, '40', NULL, 'Departure', NULL, NULL, 'Breakfast', '<p>According to your time schedule, we will drive you to the airport. We hope you loved our itinerary and experience Nepal mountains. We wish to welcome you again for some other expeditions or treks, such as the<span style=\"color: #236fa1;\"> </span><a href=\"/trip/mount-everest-expeditions\"><span style=\"color: #236fa1;\">Everest Expeditions</span>,</a> Cho Oyu expeditions, or some trekking like the EBC.</p>', 9, '2026-02-24 04:08:39', '2026-02-24 04:14:47'),
(3264, 284, '1', NULL, 'Arrival in Kathmandu Valley', '1350', '4 Star Hotel', 'Welcome Dinner', '<p>Namaste and we welcome you to the land of the Sherpas Nepal. You will be arriving at the Tribhuvan International airport for your Cho Oyu mountain expeditions. One of our team mates will be waiting for you at the airport arrival sections and upon arriving you will drive to the hotel in Thamel and rest.</p>', 1, '2026-02-26 22:44:38', '2026-04-10 14:39:12'),
(3265, 284, '2', NULL, 'Preparations and Sightseeing', '1350', '4 Star Hotel', 'B, L, & D', '<p>You will have a leisure day for yourself so that you can prepare your packing lists obtain your permits and be prepared for your upcoming summit. Our guide will give you the check list for the gears and equipment. You can obtain those from any of the shops in Thamel and your Tibet Visa will be also processed on the same day so that you can enter the Tibet without any difficulties.</p>', 2, '2026-02-26 22:44:38', '2026-04-10 14:39:12'),
(3266, 284, '3', NULL, 'Drive from Kathmandu to Timure', '1800', 'Tea House', 'B, L, & D', '<p>Early morning drive to Timure which from Kathmandu to Timure which is a small village in located near the Nepal Tibet border. The distance between this place is around 130 kilo meters which can be reached in the 5 to 7 hours as there are many off roads leading to this village. You will via many beautiful villages along side the way while enjoying the lush green dense forests and beautiful peaks</p>', 3, '2026-02-26 22:44:38', '2026-04-10 14:39:12'),
(3267, 284, '4', NULL, 'Cross Border into Tibet & Drive to Kerung', '2800', 'Tea House', 'B, L, & D', '<p>You will cross the border of Nepal- Tibet and enter inside the Tibet region. You will need to show the passport and the visas to the security force. After that we will take another vehicle inside the Tibet and then drive to the Kerung. The distance between Tibet border to Kerung is around the 250 kilo meters via the beautiful alpine landscapes which will take you around 7 to 9 hours drive. Upon reaching the Kerung rest and enjoy the delicious Tibetan delicacy.</p>', 4, '2026-02-26 22:44:38', '2026-04-10 14:39:12'),
(3268, 284, '5', NULL, 'Drive from Kerung to Old Tingri', '4350', 'Tea House', 'B, L, & D', '<p>You will again have a morning drive to Tingri at an altitude of the 4300 meters. The distance between these places is around 270 kilo meters which can be reached in the 8 to 10 hours time. You will see the beautiful landscapes of the alpine valley which will take you to your destinations. On the way you will stop of the scenic photographs and enjoy your journey.</p>', 5, '2026-02-26 22:44:38', '2026-04-10 14:39:12'),
(3269, 284, '6', NULL, 'Acclimatization and Preparation in Old Tingri', '4350', 'Tea House', 'B, L, & D', '<p>Today is reserved for acclimatization to help your body adjust to the high altitude before heading deeper into the Tibetan plateau. You will spend the day resting, doing short walks around Old Tingri, and enjoying panoramic views of Everest, Cho Oyu, and other Himalayan giants. Our climbing guide will conduct a detailed briefing about the upcoming days, safety measures, and altitude awareness. Final equipment checks will be done to ensure everything is in order for the expedition ahead. Overnight stay at a lodge in Old Tingri.</p>', 6, '2026-02-26 22:44:38', '2026-04-10 14:39:12'),
(3270, 284, '7', NULL, 'Drive from Old Tingri to Thingri', '4400', 'Tea House', 'B, L, & D', '<p>After breakfast, you will drive towards Thingri, a small Tibetan town that serves as an important acclimatization stop for Cho Oyu expeditions. The drive takes you through vast open landscapes, traditional Tibetan villages, and dramatic high-altitude scenery. Upon arrival, you will check into a local lodge, rest, and prepare for the journey toward the Cho Oyu Basecamp region.</p>', 7, '2026-02-26 22:44:38', '2026-04-10 14:39:12'),
(3271, 284, '8', NULL, 'Acclimatization and Preparation Day in Thingri', '4400', 'Tea House', 'B, L, & D', '<p>This day is dedicated to further acclimatization and preparation. You will take short acclimatization walks around Thingri, helping your body adapt to the increasing altitude. Your climbing Sherpa and expedition leader will review climbing techniques, rope handling, use of oxygen systems, and emergency protocols. This is also a great day to mentally prepare while enjoying the peaceful Tibetan highlands. Overnight at a lodge.</p>', 8, '2026-02-26 22:44:38', '2026-04-10 14:39:12'),
(3272, 284, '9', NULL, 'Drive from Thingri to Cho Oyu Chinese Basecamp  via Rombuk Monastery', '5100', 'Camp', 'B, L, & D', '<p>After an early breakfast, you will drive toward the Cho Oyu Chinese Basecamp. En route, you will visit the historic Rombuk Monastery, one of the highest monasteries in the world, offering spiritual insight and stunning mountain views. Continuing the drive across rugged terrain, you will finally reach the Chinese Basecamp of Cho Oyu at 5,100 meters. Upon arrival, the expedition team will set up tents, and you will rest and acclimatize. Overnight stay in tents.</p>', 9, '2026-02-26 22:44:38', '2026-04-10 14:39:12'),
(3273, 284, '10', NULL, 'Rest and Acclimatization Day at Cho Oyu Chinese Basecamp', '5100', 'Camp', 'B, L, & D', '<p>Today is another important acclimatization day at the Chinese Basecamp. You will spend the day resting, hydrating, and taking short walks around the camp. The team will organize climbing gear, loads, and food supplies for higher camps. Your guide will closely monitor your health and oxygen levels. Overnight stay in tents at Basecamp.</p>', 10, '2026-02-26 22:44:38', '2026-04-10 14:39:12'),
(3274, 284, '11', NULL, 'Trek from Cho Oyu Chinese Basecamp to Intermediate Camp', '5500', 'Camp', 'B, L, & D', '<p>After breakfast, you will begin trekking toward the Intermediate Camp. The trail gradually ascends over rocky moraines and glacial terrain, offering spectacular views of Cho Oyu’s north face. This short but significant ascent helps your body continue acclimatizing. Upon reaching Intermediate Camp, tents will be set up, and you will rest for the remainder of the day. Overnight in tents.</p>', 11, '2026-02-26 22:54:13', '2026-04-10 14:39:12'),
(3275, 284, '12', NULL, 'Ascent from Intermediate Camp to Advanced Basecamp', '5700', 'Camp', 'B, L, & D', '<p>Today you will trek further up to the Advanced Basecamp. The route follows the glacier, with steady elevation gain and breathtaking views of surrounding peaks. Advanced Basecamp is strategically located closer to the climbing route and will be your main staging point for rotations and summit attempts. After arrival, you will rest, rehydrate, and prepare for the upcoming acclimatization rotations. Overnight stay in tents.</p>', 12, '2026-02-26 22:54:13', '2026-04-10 14:39:12'),
(3276, 284, '13 to 20', NULL, 'Acclimatization Rotations on Cho Oyu', '7000', 'Camp', 'B, L, & D', '<p>These days are dedicated to crucial acclimatization rotations, which significantly increase your chances of a successful and safe summit. First Rotation You will climb from Advanced Basecamp to Camp I, then continue to touch Camp II before descending and sleeping at Camp I. The following day, you will descend back to Advanced Basecamp. Second Rotation You will again climb from Advanced Basecamp to Camp I, then continue to Camp II, where you will spend a night. After proper acclimatization, you will descend back to Advanced Basecamp for rest and recovery. These rotations help your body adapt to extreme altitude while familiarizing you with the route, terrain, and conditions. Full board accommodation will be provided at high camps.</p>', 13, '2026-02-26 22:54:13', '2026-04-10 14:39:12');
INSERT INTO `cl_trip_itinerary` (`id`, `trip_detail_id`, `days`, `meals`, `title`, `max_altitude`, `distance`, `duration`, `content`, `ordering`, `created_at`, `updated_at`) VALUES
(3277, 284, '21 to 26', NULL, 'Summit Push and Climbing Period', '8188', 'Camp', 'B, L, & D', '<p>This is the main climbing phase of the expedition. Weather conditions will be carefully monitored to choose the safest summit window. You will climb from Advanced Basecamp to Camp I, then to Camp II. From Camp II, you will make your summit attempt of Cho Oyu (8,188 m), one of the world’s highest and most achievable 8,000-meter peaks. After reaching the summit and celebrating your achievement, you will descend safely back to Camp II or directly to Advanced Basecamp depending on conditions and strength. These days require patience, determination, and teamwork. Full board will be provided at all high camps.</p>', 14, '2026-02-26 22:54:13', '2026-04-10 14:39:12'),
(3278, 284, '27', NULL, 'Trek from Advanced Basecamp to Chinese Basecamp', '5100', 'Camp', 'B, L, & D', '<p>After completing the summit phase, you will trek down from Advanced Basecamp to the Chinese Basecamp. The descent is easier and allows you to reflect on your incredible achievement. Upon arrival, you will enjoy a well-earned rest and a comfortable lodge stay.</p>', 15, '2026-02-26 22:54:13', '2026-04-10 14:39:12'),
(3279, 284, '28', NULL, 'Drive from Chinese Basecamp to Thingri', '4350', 'Tea House', 'B, L, & D', '<p>Today you will drive back to Thingri, retracing the scenic route across the Tibetan plateau. The lower altitude will feel refreshing, and you can relax after the intense climbing days. Overnight stay at a lodge.</p>', 16, '2026-02-26 22:54:13', '2026-04-10 14:39:12'),
(3280, 284, '29', NULL, 'Drive from Thingri to Kerung Border', '2700', 'Tea House', 'B, L, & D', '<p>After breakfast, you will drive toward the Kerung border. The journey offers sweeping views of mountains, wide valleys, and traditional Tibetan settlements. Upon arrival near the border, you will rest overnight at a lodge.</p>', 17, '2026-02-26 22:54:13', '2026-04-10 14:39:12'),
(3281, 284, '30', NULL, 'Cross the Border and Drive to Kathmandu', '1350', '4 Star Hotel', 'B, L, & D', '<p>You will cross the Tibet–Nepal border after completing immigration formalities. Once back in Nepal, you will continue the drive to Kathmandu. Upon arrival, you will check into your hotel and enjoy a well-deserved rest after your expedition adventure.</p>', 18, '2026-02-26 22:54:13', '2026-04-10 14:39:12'),
(3282, 284, '31', NULL, 'Leisure Day in Kathmandu', '1350', '4 Star Hotel', 'B, L, & D', '<p>This is a free day in Kathmandu to relax, explore the city, do souvenir shopping, or enjoy a farewell dinner with your expedition team. You can also visit cultural sites or simply unwind after the long journey. Overnight stay at a hotel.</p>', 19, '2026-02-26 22:54:14', '2026-04-10 14:39:12'),
(3283, 284, '32', NULL, 'Transfer to the International Airport for Final Departure', '1350', NULL, 'Breakfast', '<p>According to your flight schedule, our representative will transfer you to Tribhuvan International Airport for your final departure. With unforgettable memories of climbing Cho Oyu, we bid you farewell and wish you a safe journey home.</p>', 20, '2026-02-26 22:54:14', '2026-04-10 14:39:12'),
(3284, 285, '1', NULL, 'Arrival in Kathmandu and transfer to the hotel', 'Tourist Standard Hotel', NULL, 'Welcome Dinner', '<p>Namaste and we welcome you to the land of the brave Gurkha Army Nepal. Upon your arrival we will meet you at the airport arrival section and with the meet and greet drive to Thamel. In the evening you can relax and explore the vibrant streets with the different cuisines’ restaurant and handicraft shops.</p>', 1, '2026-02-27 01:37:57', '2026-02-27 01:46:22'),
(3285, 285, '2', NULL, 'Drive from Kathmandu to Pokhara', 'Tourist Standard Hotel', NULL, 'B, L, & D', '<p>Early in the morning, summit 8000 driver will come to pick you up at the hotel parking. Pack your bags and we will drive to Pokhara the gateway to the Annapurna mountains. The distance between Kathmandu to Pokhara is around 160 miles which can be reached upon the 6 to 8 hours travel time. On the way you will have drive via the lush green scenic forests and explore the local village life. In the evening you can do the boating in the Phewa lake or have stroll around the city.</p>', 2, '2026-02-27 01:37:57', '2026-02-27 01:46:22'),
(3286, 285, '3', NULL, 'Drive from Pokhara to Beni & trek to Tatopani', 'Tourist Standard Hotel', NULL, 'B, L, & D', '<p>You will have a drive from Pokhara to Beni after the breakfast. The distance between the two destinations is 59 miles which can be reached in the 4/5 hours via the Kali Gandaki River. Upon reaching Beni you can have lunch there and from there we will have a trek to the Tatopani via the lush green forested trails.</p>', 3, '2026-02-27 01:37:57', '2026-02-27 01:46:22'),
(3287, 285, '4', NULL, 'Trek from Tatopani to Ghasa', 'Tea House', NULL, 'B, L, & D', '<p>You will hike to the Ghasa a beautiful traditional Magar village located over at an altitude of the 2010 meters. You will walk via lush forests of rhododendron, pine, and bamboo. Also, you will be hiking alongside the world’s deepest gorge formed by the Kali Gandaki. Also, we will Pass via waterfalls, and cliffs with some gentle ascends and descend through the day.</p>', 4, '2026-02-27 01:37:57', '2026-02-27 01:46:22'),
(3288, 285, '5', NULL, 'Trek from Ghasa to Larjung', 'Tea House', NULL, 'B, L, & D', '<p>Upon having the hearty breakfast, you will start your journey to the Larjung. It is a beautiful village in the Mustang region of Nepal known for its awesome views of the Nilgiri and Dhaulagiri ranges. We will walk via the apple orchards and stone-built villages and experience the Tibetan-influenced culture and lifestyle of the local people.</p>', 5, '2026-02-27 01:37:57', '2026-02-27 01:46:22'),
(3289, 285, '6', NULL, 'Trek from Larjung to Marpha', 'Tea House', NULL, 'B, L, & D', '<p>You will walk to the Marpha from the Larjung village which is situated at an altitude of the 2670 meters above sea level. We will have a scenic walk alongside the kali Gandaki valley. You will pass via the monasteries, prayer wheels, and mani walls. Upon reaching Marpha check in into your tea house and in the evening, you can explore the apple orchards and enjoy apple pie or brandy in the evening.</p>', 6, '2026-02-27 01:37:57', '2026-02-27 01:46:22'),
(3290, 285, '7', NULL, 'Trek from Marpha to Yak Kharka', 'Tea House', NULL, 'B, L, & D', '<p>After enjoying the warm Gurung hospitality in the Marpha we will ascend towards the Yak Kharka. Please note this is not the classic Annapurna circuit trek yak Kharka in the Manang region but it’s a small village inside the Mustang which is also named as the Yak Kharka by the locals. You will have a gradual ascend towards the alpine terrain and open pastures. Where you will notice the Changing landscape from greenery to barren high-altitude terrains. You might see occasionally blue sheep and Himalayan birds.</p>', 7, '2026-02-27 01:37:57', '2026-02-27 01:46:22'),
(3291, 285, '8', NULL, 'Trek from Yak Kharka to Dhampus Pass (Thapa Pass', 'Tea House', NULL, 'B, L , & D', '<p>You will have a hike from the Yak Kharka to Dhampus pass which is also known as the Thapa pass which is situated at an altitude of the 5244 meters above sea level. You will start early today because the pass is located at a high altitude and the weather might be unpredictable at such terrains. You walk on the Steep ascent over rocky trails and snow patches and upon reaching the witness the beautiful Spectacular panoramic views of Annapurna, Dhaulagiri, and Nilgiri ranges. In the evening you will have rest on the pass itself. You will need to sleep early today as your summit will start in the middle of the night to avoid any kinds of difficulties.</p>', 8, '2026-02-27 01:37:57', '2026-02-27 01:46:22'),
(3292, 285, '9', NULL, 'Climb from Thapa Pass up to Thapa Peak (Dhampus Peak) & return to Kalopani', 'Tea House', NULL, 'B, L ,& D', '<p>Early in the morning around 2 Am you will have summit to the Thapa peak often known as the Dhampus peak by the most of the travellers. You will start early and cross the Snow and ice climbing with rope support which will be guide-assisted. When climber reach the summit top they see the beautiful 360° panoramic Himalayan views of the mountains. After reaching the top you can spend some time and click photographs and celebrate the moment of victory and descend to Kalo Pani also be careful while descending as the difficult part of the summit is not ascending but its descend safely.</p>', 9, '2026-02-27 01:37:57', '2026-02-27 01:46:22'),
(3293, 285, '10', NULL, 'Trek from Kalopani to Tatopani', 'Tea House', NULL, 'B, L ,& D', '<p>You will trek down from the Kalo Pani to Tatopani. You will have a long descent through forests and river valleys. As you come to lower altitude you will experience that you are able to breathe in the heavy oxygen and your body is performing better. Upon reaching the Tatopani you can check into the hotel and relax in the natural hot spring of the Tatopani. Hot spring have many medicinal values due to which your body will recover at the fullest.</p>', 10, '2026-02-27 01:37:57', '2026-02-27 01:46:22'),
(3294, 285, '11', NULL, 'Drive from Tatopani to Beni to Pokhara', 'Tea House', NULL, 'B, L, & D', '<p>As the acclimatization is not much more important today you will directly drive from Tatopani to Pokhara. The distance between these places is 60 miles via the Kali Gandaki River passing. You will pass via the Beni, Baglung, and Pokhara. On the way if you want, we can take you to the Kusma bungee jumping which is the world’s 2nd highest Bungee in Nepal. Upon reaching Pokhara you can relax and explore the Pokhara city and visit the places such as the World peace pagoda, Pumdikot, Davis fall, Mahendra Gufa, Chamero gufa and many more.</p>', 11, '2026-02-27 01:37:57', '2026-02-27 01:46:22'),
(3295, 285, '12', NULL, 'Drive from Pokhara to Kathmandu', 'Tea House', NULL, 'B, L, & D', '<p>Early in the morning, you will have a drive to Sarangkot from where you can witness the beautiful sunrise over the Annapurna and Dhaulagiri ranges. After that drive back to the hotel and have breakfast and be prepared for your next journey which is the Drive from Pokhara to Kathmandu. Upon reaching the Kathmandu we will have a farewell dinner where you can share your thoughts and opinions on the expeditions.</p>', 12, '2026-02-27 01:37:57', '2026-02-27 01:46:22'),
(3296, 285, '13', NULL, 'International departure from Kathmandu Airport.', 'Tea House', NULL, 'B, L, & D', '<p>Our journey comes to an end today. According to your flight schedule, we will provide a transfer to Tribhuvan International Airport. We hope you had a memorable time in Nepal and look forward to welcoming you again. Your feedback on Google Reviews or Tripadvisor would be greatly appreciated.</p>', 13, '2026-02-27 01:37:57', '2026-02-27 01:46:22'),
(3297, 286, '1', NULL, 'Arrival in Kathmandu', '1350', '4 Star Hotel', 'Welcome Dinner', '<p>Namaste and we welcome you to the city of the temples, history, culture and traditions Kathmandu. You will be arriving at the Tribhuvan International Airport which is the gateway to Nepal. Upon your arrival you can complete the visa and immigration works. One of the Summit 8000 team member will be waiting for you at the arrival gate and after meeting he will drive you to the hotel in Thamel. In the evening you can have the stroll in the vibrant streets of Thamel and enjoy the delicious local foods that are available.</p>', 1, '2026-02-28 19:35:48', '2026-04-07 14:13:33'),
(3298, 286, '2', NULL, 'Trip Preparation', '1350', '4 Star Hotel', 'B, L, & D', '<p>Today you will be your trip preparation day. You will meet your guide who will brief you about the packing lists that will be required during the summit, climbing and trekking time. You will need to rent and buy the items required with your guide help. Your guide will also help you to get the permits from the Tourism Board Office. And if you have time you might visit to the Swayambhunath Stupa for the short hiking in the evening.</p>', 2, '2026-02-28 19:35:48', '2026-04-07 14:13:33'),
(3299, 286, '3', NULL, 'Fly to Lukla, then trek to Phakding', '2800', 'Tea House', 'B, L, & D', '<p>Early in the morning, after the breakfast your driver with the expedition guide will come to pick you up at your hotel. After that you will drive to the airport and from there you will fly to Lukla. The flight time will be of 30 to 35 minutes. Upon arrival you will trek to Phakding. The gateway to the Everest region in Nepal.</p>', 3, '2026-02-28 19:35:48', '2026-04-07 14:13:33'),
(3300, 286, '4', NULL, 'Phakding to Namche Bazaar', '3440', 'Tea House', 'B, L, & D', '<p>You will trek to the Namche Bazar from the Phakding. The trek will be of 6 to 8 hours depending upon your pace and the hiking experience. The trail will be steep passing via the beautiful pine and Rhododendron forests. You will be crossing the several suspension bridges over the Dudh Koshi river. As you pass you will see the small village located on the backdrop of the big giant mountains which is also the main trading hub inside the Khumbu region.</p>', 4, '2026-02-28 19:35:48', '2026-04-07 14:13:33'),
(3301, 286, '5', NULL, 'Namche Bazaar – Acclimatization', '3440', 'Tea House', 'B, L, & D', '<p>Acclimatization is very important part for the trekking and climbing peak so that your body can adopt the thin air of the high altitudes. In order to make it happen today will be acclimatization for you. You will hike to the Everest view hotel from where you can enjoy the beautiful mountain ranges of the world’s highest mountain Mount Everest and its surrounding ranges. After that you can explore the local market in the Namche. Spend your time in the mountains were if you want you can do the meditations and yoga in the monastery or in your tea house as well.</p>', 5, '2026-02-28 19:35:48', '2026-04-07 14:13:34'),
(3302, 286, '6', NULL, 'Namche Bazaar to Debuche', '3700', 'Tea House', 'B, L, & D', '<p>After acclimating yourself in the Namche you will head towards the Debuche which is a small village in the Khumbu region known for its peace surroundings and the beautiful views of the rhododendron forests. As you walk you will feel the cold air of the mountains and you will see the first glimpse of the Ama Dablam peak which you will be summiting.</p>', 6, '2026-02-28 19:35:48', '2026-04-07 14:13:34'),
(3303, 286, '7', NULL, 'Debuche to Pheriche', '4288', 'Tea House', 'B, L, & D', '<p>After the local breakfast in the Debuche you will head towards the Pheriche. On the way you will visit the Pangboche village which is the oldest sherpa settlement inside the Everest region. As you walk above you will feel that the serene is changing from the lush green to alpine meadows and the peaks are dominating the skyline.</p>', 7, '2026-02-28 19:35:48', '2026-04-07 14:13:34'),
(3304, 286, '8', NULL, 'Acclimatization at Pheriche', '4288', 'Tea House', 'B, L, & D', '<p>Today will be the acclimatization day for you after the Namche. As you will be approaching the Ama Dablam base camp its very important for you to acclimate yourself. You will be visiting the HRA medical post where you can learn about the high-altitude sickness, Acute mountain sickness and its symptoms along with its preventions. After that will hike to the nearby ridges to see the mountains views and in the mountains there is saying that if a person walks high and sleeps low his/ her body acclimates to the environment rapidly.</p>', 8, '2026-02-28 19:35:48', '2026-04-07 14:13:34'),
(3305, 286, '9', NULL, 'Pheriche to Ama Dablam Base Camp', '4570', 'Tent', 'B, L, & D', '<p>Finally, on the day 9th your dream will come true to walk to the Ama Dablam peak base camp. As you walk you will get the close-up views of the Ama Dablam Southwest face which is stunning and eye catching. You will walk via the glacier river which is known as the Imja khola. Upon reaching the base camp your true adventure will start. Your personality and mindset will be changed from the trekker to the climber.</p>', 9, '2026-02-28 19:35:48', '2026-04-07 14:13:34'),
(3306, 286, '10', NULL, 'Acclimatization and Pre-climb Training at Ama Dablam Base Camp', '4570', 'Tent', 'B, L, & D', '<p>You will be having the training as well the acclimatization so that you can make your dream come true. You will learn about the how to fix the rope, ice and rock-climbing techniques, use of crampons, ice exes and many more. Don’t worry they will not teach everything in a single day. You will have some safety drills and team work so that you can co ordinate and our team can take you back to Kathmandu safely.</p>', 10, '2026-02-28 19:35:48', '2026-04-07 14:13:34'),
(3307, 286, '11 to 25', NULL, 'Ascending and Descending Ama Dablam', '6812', 'Tent', 'B, L, & D', '<p>From the day 11 to 25th your true spirit of the climber will start. You will learn about every safety drill, use of the gears and equipment. You will ascend and descend so that your body can adopt to the such high altitude. You will ascend via the camp I, Camp II, III and various routes and again descend and again climb till the day you do the Ama Dablam summit. After summiting the peak you will have the sense of achievement and discipline which will shape the personality out of you.</p>', 11, '2026-02-28 19:35:48', '2026-04-07 14:13:34'),
(3308, 286, '26 to 27', NULL, 'Trek to Namche Bazar', '3440', 'Tea House', 'B, L, & D', '<p>After climbing the Ama Dablam peak you will trek to the Pheriche and from Pheriche you will trek down to the Namche Bazar. As you descend you will have emotional connections with the mountains and its surroundings. You will gradually descend and feel the oxygen level is rising and you are able to breathe in the heavy air. You can celebrate your success with your expeditions teams in the Namche and share your stories and experience with them.</p>', 12, '2026-02-28 19:35:48', '2026-04-07 14:13:34'),
(3309, 286, '28', NULL, 'Trek down to Lukla and Fly back to Kathmandu', '1350', '4 Star Hotel', 'B, L, & D', '<p>Early in the morning, you will start your walk to Lukla. As you will need to fly from Lukla to Kathmandu. The descend from Namche to Lukla is easy and the trails will be known to you it would be easy for you to walk. You can click photographs and talk to the local and fellow travellers. Upon reaching Lukla you will fly from Lukla to Kathmandu in 30 minutes. After the long day walk, you can finally stay inside a good star hotel and relax yourself. You can do the Sauna and Spa to relax your muscles and take rest from the long day trek, and climb.</p>', 14, '2026-02-28 19:35:48', '2026-04-07 14:13:34'),
(3310, 286, '29', NULL, 'Leisure Day in Kathmandu', '1400', '4 Star Hotel', 'B, L, & D', '<p>As you have visited Nepal and you have completed your dream of climbing the 6000 meter above peak. It would be your leisure day in Kathmandu city. As Nepal is not only known for its peaks but it’s also known for its history, cultures, traditions, foods and festivals. You can visit to the different places of Kathmandu like the Holy Pashupatinath temple, Boudhanath Stupa, Swayambhunath Stupa, Kathmandu Durbar Square, Bhaktapur durbar square and many more places according to your preference.</p>', 15, '2026-02-28 19:35:48', '2026-04-07 14:13:34'),
(3311, 286, '30', NULL, 'Final Departure', '1400', NULL, 'Breakfast', '<p>After spending such a long time with you we don’t want you to send you back. But we understand you will need to in order to continue your regular life. We hope we served you best out of us. We hope to see you again for the some other treks or tours. As per your schedule our team member will drop you to the airport where you can complete your immigration process and head towards your next destinations.</p>', 16, '2026-02-28 19:35:48', '2026-04-07 14:13:34'),
(3312, 287, '1', NULL, 'Arrival in Kathmandu (1,400 m)', '4 Star Hotel', NULL, 'Welcome Dinner', '<p>Your expedition begins with arrival in Kathmandu, the vibrant capital of Nepal. Upon landing at Tribhuvan International Airport, you will be transferred to your hotel where you can rest and recover from your journey. The day is also used for an expedition briefing, where your guide will review the itinerary, check your climbing gear, and answer any questions. If time permits, a short walk through Thamel allows you to explore the bustling streets and pick up last-minute supplies for the trek ahead.</p>', 1, '2026-03-06 02:05:42', '2026-03-06 02:06:07'),
(3313, 287, '2', NULL, 'Kathmandu to Pokhara (827 m)', '4 Star Hotel', NULL, 'B, L, & D', '<p>On the second day, you will drive from Kathmandu to Pokhara, a scenic journey along the Prithvi Highway. The drive passes through terraced hills, rivers, and small towns, offering glimpses of rural Nepal along the way. Pokhara serves as the gateway to the Annapurna region, and the evening is reserved for preparation, rest, and briefing on the trekking route. You can enjoy the serene lakeside atmosphere and prepare for the days of trekking ahead</p>', 2, '2026-03-06 02:05:42', '2026-03-06 02:06:07'),
(3314, 287, '3', NULL, 'Pokhara to Chame (2,670 m)', '4 Star Hotel', NULL, 'B, L, & D', '<p>From Pokhara, the expedition heads towards Chame, the administrative center of the Manang district and the starting point of the trekking trail. The drive offers spectacular views of the Marshyangdi River and surrounding hills. Upon arrival in Chame, you will settle into a local guesthouse and take a short walk to stretch your legs after the long journey. This is an opportunity to adjust to the increasing altitude and get acquainted with the trail ahead.</p>', 3, '2026-03-06 02:05:42', '2026-03-06 02:06:07'),
(3315, 287, '4', NULL, 'Chame to Upper Pisang (3,300 m)', '4 Star Hotel', NULL, 'B, L, & D', '<p>The trek from Chame to Upper Pisang winds through pine forests, terraced fields, and small villages. The trail offers magnificent views of Annapurna II, Pisang Peak, and Gangapurna. Along the way, you can interact with local Gurung communities and experience traditional mountain culture. Upper Pisang is a quiet village that provides the perfect setting for rest and acclimatization before continuing higher into the mountains.</p>', 4, '2026-03-06 02:05:42', '2026-03-06 02:06:08'),
(3316, 287, '5', NULL, 'Upper Pisang to Manang (3,500 m)', '4 Star Hotel', NULL, 'B, L, & D', '<p>From Upper Pisang, the trail continues to Manang, a key acclimatization stop in the Annapurna region. Manang is a picturesque village with traditional stone houses and monasteries, set against a backdrop of snow-capped peaks. Spending extra time here helps your body adapt to the higher altitudes, reducing the risk of altitude sickness during the climb. Short hikes in the afternoon allow for gentle acclimatization while offering stunning views of the surrounding mountains.</p>', 5, '2026-03-06 02:05:42', '2026-03-06 02:06:08'),
(3317, 287, '6', NULL, 'Acclimatization Day in Manang', '4 Star Hotel', NULL, 'B, L, & D', '<p>This day is reserved entirely for acclimatization in Manang. Optional short hikes to nearby areas, such as Gangapurna Lake, help your body adjust to the altitude. The day is also ideal for rest, hydration, and nutrition planning, as well as reviewing climbing techniques with your guide. Proper acclimatization ensures that you are physically prepared for the technical sections of the Chulu West climb.</p>', 6, '2026-03-06 02:05:42', '2026-03-06 02:06:08'),
(3318, 287, '7', NULL, 'Manang to Chulu West Base Camp (4,700 m)', '4 Star Hotel', NULL, 'B, L, & D', '<p>The trek to Chulu West Base Camp begins in earnest on day seven. The trail passes rocky terrain, small streams, and moraines, gradually introducing climbers to high-altitude conditions. Base Camp provides the final staging point before technical climbing begins. Here, you can enjoy panoramic views of Chulu West and East and observe the route ahead, while tents and other facilities are set up for the night.</p>', 7, '2026-03-06 02:05:42', '2026-03-06 02:06:08'),
(3319, 287, '8', NULL, 'Base Camp Preparation and Gear Check', '4 Star Hotel', NULL, 'B, L, & D', '<p>At Base Camp, the focus is on preparation. Guides and support staff assist climbers in checking all gear, reviewing safety procedures, and practicing rope and crevasse techniques if needed. The day is essential for rest, hydration, and mentally preparing for the challenging ascent. Understanding the route and confirming logistics ensures a smooth start to the climb.</p>', 8, '2026-03-06 02:05:42', '2026-03-06 02:06:08'),
(3320, 287, '9', NULL, 'Base Camp to Advanced Base Camp (5,100 m)', '4 Star Hotel', NULL, 'B, L, & D', '<p>The trek from Base Camp to Advanced Base Camp (ABC) involves more technical terrain, including snow slopes and mixed ice sections. Climbers ascend gradually to ABC to continue acclimatizing while navigating the steeper sections of the route. The environment becomes more alpine, and spectacular views of glaciers and surrounding peaks make this stretch both challenging and rewarding. Overnight at ABC is in tents, with team briefings to plan the next day’s climb.</p>', 9, '2026-03-06 02:05:42', '2026-03-06 02:06:08'),
(3321, 287, '10', NULL, 'Advanced Base Camp to High Camp (5,700 m)', '4 Star Hotel', NULL, 'B, L, & D', '<p>Climbers move from ABC to High Camp on day ten, where the ascent becomes steeper and more demanding. This section involves careful navigation over snow and ice, and the use of fixed ropes on some slopes. High Camp is the launching point for the summit push, and the afternoon is spent resting, preparing gear, and finalizing plans for the early morning summit attempt.</p>', 10, '2026-03-06 02:05:42', '2026-03-06 02:06:08'),
(3322, 287, '11', NULL, 'Summit Day – Chulu West Peak (6,419 m)', '4 Star Hotel', NULL, 'B, L, & D', '<p>The summit attempt begins in the early hours, typically around 2:00–3:00 AM, to take advantage of stable morning weather. Climbers face steep snow slopes, mixed rock sections, and glacier crossings before reaching the summit. From the top, the panoramic views of Annapurna, Dhaulagiri, and surrounding Himalayan peaks are breathtaking. After celebrating the achievement, climbers descend carefully back to High Camp, ensuring energy is conserved for the return journey.</p>', 11, '2026-03-06 02:05:42', '2026-03-06 02:06:08'),
(3323, 287, '12', NULL, 'High Camp to Base Camp (4,700 m)', '4 Star Hotel', NULL, 'B, L, & D', '<p>After the summit, climbers descend from High Camp to Base Camp. The journey back involves retracing the technical sections safely while gradually reducing altitude. Rest at Base Camp allows climbers to recover from the physical and mental challenges of the summit, preparing for the trek back to Manang.</p>', 12, '2026-03-06 02:05:42', '2026-03-06 02:06:08'),
(3324, 287, '13', NULL, 'Base Camp to Manang (3,500 m)', '4 Star Hotel', NULL, 'B, L, & D', '<p>The trek continues from Base Camp to Manang, moving from high-altitude technical terrain back to trekking trails. This segment provides time to relax, celebrate the successful climb, and enjoy the alpine landscapes one last time. Overnight in Manang offers comfort before the descent toward lower altitudes.</p>', 13, '2026-03-06 02:05:42', '2026-03-06 02:06:08'),
(3325, 287, '14', NULL, 'Manang to Kathmandu (via Pokhara) / Departure', '4 Star Hotel', NULL, 'B, L, & D', '<p>On the final day, the expedition returns to Pokhara and then drives back to Kathmandu. The journey provides an opportunity to reflect on the climb and enjoy the scenic landscapes one final time. Depending on your flight schedule, you can rest in Kathmandu or explore the city before departing from Tribhuvan International Airport.</p>', 14, '2026-03-06 02:05:42', '2026-03-06 02:06:08'),
(3326, 288, '1', NULL, 'Arrival in Kathmandu & Transfer to Hotel (1,400m)', '4 Star Hotel', NULL, 'Welcome Dinner', '<p>Upon arrival at Tribhuvan International Airport in Kathmandu, our expedition team will welcome you and transfer you to your hotel. Take rest after your long flight and recover from jet lag. In the evening, attend a welcome dinner where you\'ll meet your climbing team and expedition leader. This is a good time to discuss the Dhaulagiri climbing expedition ahead.</p>', 1, '2026-03-06 03:34:13', '2026-03-06 20:31:59'),
(3327, 288, '2', NULL, 'Rest in Kathmandu - Briefing and Preparation', '4 Star Hotel', NULL, 'B, L, & D', '<p>This day is dedicated to expedition preparation and official briefings. Visit the Department of Tourism for your climbing permit briefing. Check all your mountaineering equipment and climbing gear. Purchase any missing items from Thamel\'s climbing shops. Attend a detailed briefing about the Dhaulagiri expedition route, weather conditions, and safety protocols. Meet with your Sherpa climbing guide and discuss the summit plan.</p>', 2, '2026-03-06 03:34:13', '2026-03-06 20:31:59'),
(3328, 288, '3', NULL, 'Fly from Kathmandu to Pokhara (960m)', '4 Star Hotel', NULL, 'B, L, & D', '<p>Take a scenic 25-minute flight from Kathmandu to Pokhara. Enjoy beautiful views of the Himalayan mountains including Manaslu, Annapurna, and Dhaulagiri. Upon arrival in Pokhara, transfer to your hotel. Spend the rest of the day exploring Pokhara lakeside or resting before the trek begins. Final gear check and pack your equipment for the helicopter flight to base camp.</p>', 3, '2026-03-06 03:34:13', '2026-03-06 20:31:59'),
(3329, 288, '4', NULL, 'Drive from Pokhara to Takam (2,900m)', 'Tea House', NULL, 'B, L, & D', '<p>Start early morning drive from Pokhara to Takam village. The journey takes approximately 8-10 hours through rough mountain roads. Pass through beautiful villages and terraced farmlands. Arrive at Takam, a small village that serves as the starting point for Dhaulagiri expeditions. Stay overnight in a basic lodge. This is your first night at altitude, so drink plenty of water.</p>', 4, '2026-03-06 03:34:13', '2026-03-06 20:31:59'),
(3330, 288, '5', NULL, 'Acclimatization in Takam (Rest Day)', 'Tea House', NULL, 'B, L, & D', '<p>Spend the day acclimatizing at Takam. Take short walks around the village to help your body adjust to the altitude. Check your climbing equipment one final time. Attend briefing about helicopter safety and Italian Base Camp. Rest well as tomorrow you\'ll fly to higher altitude. Monitor your health and inform the expedition leader of any altitude sickness symptoms.</p>', 5, '2026-03-06 03:34:13', '2026-03-06 20:31:59'),
(3331, 288, '6', NULL, 'Helicopter Flight from Takam to Italian Base Camp (3,660m', 'Tea House', NULL, 'B, L, & D', '<p>Take an exciting helicopter flight from Takam to Italian Base Camp. The flight offers spectacular aerial views of Dhaulagiri Mountain and surrounding peaks. Land at Italian Base Camp and set up your tents. The camp is located on the Chhonbardan Glacier. Spend the afternoon organizing camp and resting. Drink lots of fluids to prevent altitude sickness.</p>', 6, '2026-03-06 03:34:13', '2026-03-06 20:31:59'),
(3332, 288, '7', NULL, 'Acclimatization at Italian Base Camp (Rest Day)', 'Tea House', NULL, 'B, L, & D', '<p>First acclimatization day at Italian Base Camp. Take short walks around the camp area. Practice using your climbing equipment and get familiar with the glacier terrain. Attend training sessions on rope techniques and glacier travel. The climbing Sherpa team will demonstrate proper use of fixed ropes, jumars, and crampons. Rest and hydrate well.</p>', 7, '2026-03-06 03:34:13', '2026-03-06 20:31:59'),
(3333, 288, '8', NULL, 'Acclimatization at Italian Base Camp (Rest Day)', 'Tea House', NULL, 'B, L, & D', '<p>Continue acclimatization at Italian Base Camp. Take slightly longer walks and practice climbing skills. Some team members may make a short climb up to scout the route ahead. Review the route map to Dhaulagiri Base Camp. Check weather forecasts and discuss the climbing plan. Maintain good nutrition and rest for the trek tomorrow.</p>', 8, '2026-03-06 03:34:13', '2026-03-06 20:31:59'),
(3334, 288, '9', NULL, 'Trek from Italian Base Camp to Dhaulagiri Base Camp (4,750m)', 'Tea House', NULL, 'B, L, & D', '<p>Trek from Italian Base Camp to Dhaulagiri Base Camp. The route crosses the Chhonbardan Glacier and involves glacier walking. Trek time is approximately 5-7 hours. The path includes crevassed sections requiring careful navigation. Arrive at Dhaulagiri Base Camp and set up camp. This will be your home for the next several weeks during the climbing expedition. Organize your personal tent and equipment.</p>', 9, '2026-03-06 03:34:13', '2026-03-06 20:31:59'),
(3335, 288, '10 to 30', NULL, 'Rotation Period - Base Camp to Camp I, Camp II, Camp III', 'Tea House', NULL, 'B, L, & D', '<p>These three weeks are dedicated to acclimatization rotations and establishing higher camps. The rotation schedule includes: First Rotation: Climb from Base Camp to Camp I (5,800m) and return to Base Camp. This helps your body adapt to higher altitude. Second Rotation: Climb to Camp I, continue to Camp II (6,400m), and return to Base Camp. Spend night at Camp I during this rotation. Third Rotation: Climb to Camp I, Camp II, touch Camp III (7,400m), and return to Base Camp. This prepares your body for summit push. Between rotations, rest at Base Camp to recover strength. The climbing Sherpa team will fix ropes and establish camps. Weather conditions will determine the exact rotation schedule. Each rotation makes your body stronger for high altitude climbing.</p>', 10, '2026-03-06 03:34:13', '2026-03-06 20:31:59'),
(3336, 288, '31 to 40', NULL, 'Summit Push Period', 'Tea House', NULL, 'B, L, & D', '<p>This is the summit push period for Dhaulagiri (8,167m). The exact timing depends on weather window and your acclimatization. Summit Route: Base Camp → Camp I → Camp II → Camp III → Summit Camp → Dhaulagiri Summit → Return to Base Camp Summit Day: Wake up around midnight. Start climbing at 1-2 AM from Summit Camp. Climb through the night using headlamps. Reach Dhaulagiri summit (8,167m) in morning. Enjoy summit views but don\'t stay long due to oxygen and weather. Descend carefully back to Camp III, then Camp II, and finally return to Base Camp. Total summit push takes 7-10 days depending on conditions and your climbing speed. This period includes buffer days for bad weather. Not all days will be climbing days. Weather and your physical condition determine the final summit attempt.</p>', 11, '2026-03-06 03:34:13', '2026-03-06 20:31:59'),
(3337, 288, '41', NULL, 'Trek from Dhaulagiri Base Camp to Italian Base Camp (3,660m)', 'Tea House', NULL, 'B, L, & D', '<p>After successful summit, trek back from Dhaulagiri Base Camp to Italian Base Camp. Retrace your route across the Chhonbardan Glacier. Celebrate your achievement with the team. Pack all personal equipment and clean up the camp. Rest well at Italian Base Camp before helicopter flight.</p>', 12, '2026-03-06 03:34:13', '2026-03-06 20:31:59'),
(3338, 288, '42', NULL, 'Helicopter Flight from Italian Base Camp to Takam', 'Tea House', NULL, 'B, L, & D', '<p>Take helicopter flight from Italian Base Camp back to Takam village. Enjoy the scenic flight and relief of successful expedition. Arrive at Takam and transfer to lodge. Take a hot shower and enjoy cooked meals. This is your first comfortable accommodation after weeks in tents.</p>', 13, '2026-03-06 03:34:14', '2026-03-06 20:31:59'),
(3339, 288, '43', NULL, 'Drive from Takam to Pokhara', '4 Star Hotel', NULL, 'B, L, & D', '<p>Drive back from Takam to Pokhara. The journey takes 8-10 hours. Arrive in Pokhara and check into hotel. Enjoy the comfort of a proper bed and hot shower. Celebrate your Dhaulagiri summit success with team dinner at Pokhara lakeside. Share expedition photos and memories with teammates.</p>', 14, '2026-03-06 03:34:14', '2026-03-06 20:31:59'),
(3340, 288, '44', NULL, 'Fly from Pokhara to Kathmandu & Transfer to Hotel', '4 Star Hotel', NULL, 'B, L, & D', '<p>Take morning flight from Pokhara to Kathmandu. Transfer to hotel upon arrival. Rest of the day is free for personal activities. Visit Thamel for souvenir shopping. Get summit certificate processed from expedition company. Attend farewell dinner with expedition team in the evening.</p>', 15, '2026-03-06 03:34:14', '2026-03-06 20:31:59'),
(3341, 288, '45', NULL, 'Leisure Day in Kathmandu City', '4 Star Hotel', NULL, 'B, L, & D', '<p>Free day to explore Kathmandu city. Visit UNESCO World Heritage Sites like Pashupatinath Temple, Boudhanath Stupa, or Swayambhunath. Shop for gifts and souvenirs. Rest and recover from the expedition. Organize your luggage for departure. Optional: Receive your official Dhaulagiri summit certificate.</p>', 16, '2026-03-06 03:34:14', '2026-03-06 20:31:59'),
(3342, 288, '46', NULL, 'Final Departure from Kathmandu', NULL, NULL, NULL, '<p>Transfer to Tribhuvan International Airport for your final departure. Our team will assist you with airport procedures. Depart Nepal with memories of your successful Dhaulagiri expedition and Himalayan mountaineering experience.</p>', 17, '2026-03-06 03:34:14', '2026-03-06 20:31:59'),
(3343, 289, '1', NULL, 'Arrival in Kathmandu', '4 Star Hotel', NULL, 'Welcome Dinner', '<p>Arrive at Tribhuvan International Airport in Kathmandu, where our team will transfer you to your hotel. Take some time to rest and recover from your flight. In the evening, attend a briefing about the upcoming Gangapurna expedition. Get familiar with your trekking and climbing equipment and meet your guides. This is the perfect opportunity to acclimatize to the local environment.</p>', 1, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3344, 289, '2', NULL, 'Kathmandu Valley Sightseeing & Preparation', '4 Star Hotel', NULL, 'Breakfast', '<p>Explore Kathmandu’s rich cultural heritage with visits to Pashupatinath Temple, Boudhanath Stupa, and Patan Durbar Square. Learn about local traditions and architecture while enjoying the vibrant city atmosphere. Use this day to finalize your trekking permits and check your climbing gear. Meet with your guides to discuss the expedition plan. This day sets the foundation for your high-altitude adventure.</p>', 2, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3345, 289, '3', NULL, 'Drive to Besisahar (823m)', 'Tea House', NULL, 'Breakfast and Dinner', '<p>Begin your journey to the Annapurna region with a scenic drive to Besisahar. Pass terraced fields, rivers, and traditional villages along the way. The drive allows you to gradually immerse yourself in the Himalayan landscape. Overnight at a local lodge in Besisahar. Prepare for the trekking phase of the expedition starting tomorrow.</p>', 3, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3346, 289, '4', NULL, 'Drive to Dharapani (1,860m)', 'Tea House', NULL, 'B, L, & D', '<p>Continue deeper into the mountains with a drive to Dharapani, following the Marsyangdi River. The road winds through forests, hills, and small villages, offering glimpses of Annapurna peaks. This day helps your body adjust to increasing altitudes. Arrive at Dharapani and settle in at a cozy lodge. Enjoy the serene mountain environment before trekking begins.</p>', 4, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3347, 289, '5', NULL, 'Trek to Chame (2,670m)', 'Tea House', NULL, 'B, L, & D', '<p>Start the official travel from Dharapani to Chame, passing through rhododendron forests and picturesque villages. Stop along the way for short breaks and to enjoy the views of Lamjung Himal and Annapurna II. Chame offers comfortable lodges and warm hospitality. The trail gradually ascends, allowing for proper acclimatization. Evening at leisure in Chame to relax and enjoy the scenery.</p>', 5, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3348, 289, '6', NULL, 'Trek to Pisang (3,300m)', 'Tea House', NULL, 'B, L, & D', '<p>Trek from Chame to Pisang, where the terrain becomes more alpine. The trail offers stunning views of Gangapurna Peak and Annapurna II. Pisang village is known for its traditional architecture and panoramic surroundings. Overnight at a lodge and enjoy a hearty local meal. This is an important day for altitude adjustment as you ascend further.</p>', 6, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3349, 289, '7', NULL, 'Trek to Manang (3,440m)', 'Tea House', NULL, 'B, L, & D', '<p>Continue the walk to Manang, one of the most beautiful villages in the Annapurna region. Pass by Buddhist monasteries and local markets along the way. The higher altitude requires a steady pace, allowing your body to acclimatize. Overnight in Manang at a lodge with comfortable facilities. Enjoy the spectacular mountain views surrounding the village.</p>', 7, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3350, 289, '8', NULL, 'Rest Day in Manang (Acclimatization)', 'Tea House', NULL, 'B, L, & D', '<p>Spend a full day in Manang to acclimatize to the high altitude. Optional short hikes to nearby viewpoints or Gangapurna Lake help your body adjust. Rest, hydrate, and prepare for the climb ahead. This day also provides a chance to interact with local communities and learn about their culture. Evening at leisure to relax and enjoy the Himalayan scenery.</p>', 8, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3351, 289, '9', NULL, 'Trek to Gangapurna Base Camp (4,650m)', 'Tent', NULL, 'B, L, & D', '<p>Trek from Manang to Gangapurna Base Camp, passing glaciers and alpine terrain. The base camp is the starting point for the summit climb, offering incredible close-up views of Gangapurna Peak. Overnight at the base camp in tents or lodges. Use the day to settle in, organize your gear, and acclimatize further. Enjoy the serenity and breathtaking Himalayan panorama.</p>', 9, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3352, 289, '10 to 27', NULL, 'Climbing Period – Gangapurna Summit (7,455m)', 'Tent', NULL, 'B, L, & D', '<p>Over the next 18 days, climbers follow a careful schedule of establishing higher camps, acclimatizing, and technical climbing. Under expert guidance, you navigate snow and ice routes, practicing rope techniques along the way. The ultimate goal is the summit of Gangapurna Peak, rewarding climbers with unparalleled Himalayan views. Safety is the top priority, and the pace is adapted to weather and conditions. Descend gradually after the summit to recover at lower camps.</p>', 10, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3353, 289, '28', NULL, 'Pack Up and Preparation for Return', 'Tent', NULL, 'B, L, & D', '<p>After the climb, pack all climbing equipment and personal belongings. Prepare for the descent back through the trekking route. Reflect on the accomplishment and enjoy the last moments at high altitude. Overnight at a lodge near the base camp. Take in the surrounding mountains one last time before heading down.</p>', 11, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3354, 289, '29', NULL, 'Trek to Yak Kharka', 'Tea House', NULL, 'B, L, & D', '<p>Descend from Tilicho Base Camp to Yak Kharka, walking through alpine meadows and glacial terrain. Overnight at a cozy lodge and enjoy the high-altitude village’s hospitality. The descent is easier but still requires caution. Hydrate well and rest to prevent fatigue. This is a scenic day filled with beautiful Himalayan views.</p>', 12, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3355, 289, '30', NULL, 'Trek to Thorong Phedi/High Camp (4,600m)', 'Tea House', NULL, 'B, L, & D', '<p>Continue descending to Thorong Phedi, preparing for the lower-altitude trek ahead. Overnight at a lodge, allowing your body to adjust gradually. The trail passes through rugged terrain and traditional villages. Enjoy the serene mountain environment and spectacular views. Rest well for the next day’s journey to Muktinath.</p>', 13, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3356, 289, '31', NULL, 'Trek to Muktinath (3,710m)', 'Tea House', NULL, 'B, L, & D', '<p>Trek through alpine landscapes to Muktinath, a sacred pilgrimage site for Hindus and Buddhists. Explore the temple, holy springs, and surrounding trails. Overnight at a lodge in Muktinath. This descent is easier on the body and offers a chance to appreciate cultural experiences. Enjoy the peaceful Himalayan surroundings.</p>', 14, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3357, 289, '32', NULL, 'Trek to Jomsom via Kagbeni (2,700m)', 'Tea House', NULL, 'B, L, & D', '<p>Descend further through the Thak Khola valley, passing Kagbeni and other traditional villages. Arrive in Jomsom, a charming town with mountain views and cozy lodges. Overnight in Jomsom, preparing for the short flight to Pokhara the next day. Reflect on the trekking journey and the stunning landscapes you’ve passed.</p>', 15, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3358, 289, '33', NULL, 'Fly to Pokhara & Explore the City', '4 Star Hotel', NULL, 'Breakfast', '<p>Take a scenic flight to Pokhara, the adventure capital of Nepal. Explore Phewa Lake, Davis Falls, and the Lakeside area. Overnight at a hotel, enjoying the city’s vibrant atmosphere and relaxing after the trek. Pokhara offers a refreshing change from the high-altitude environment. Enjoy leisure activities or simply unwind by the lake.</p>', 16, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3359, 289, '34', NULL, 'Drive Back to Kathmandu', '4 Star Hotel', NULL, 'Breakfast', '<p>Drive from Pokhara to Kathmandu, passing rivers, hills, and charming villages. Overnight in Kathmandu hotel. Rest and relax after the long drive. Prepare for your final day in the city. Reflect on your incredible journey through the Annapurna and Gangapurna region.</p>', 17, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3360, 289, '35', NULL, 'Leisure Day in Kathmandu', 'Tea House', NULL, 'Breakfast', '<p>Enjoy a full day at leisure in Kathmandu. Shop for souvenirs, explore the city, or simply rest at your hotel. Optional visits to local markets or cultural sites. This is the perfect day to unwind before departure. Celebrate the success of your Gangapurna expedition.</p>', 18, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3361, 289, '36', NULL, 'Departure', NULL, NULL, NULL, '<p>Transfer to Tribhuvan International Airport for your onward flight. Carry with you unforgettable memories of the Himalayas, cultural experiences, and the triumph of climbing Gangapurna Peak. Bid farewell to Nepal and your expedition team.</p>', 19, '2026-03-06 21:04:22', '2026-03-06 21:06:46'),
(3362, 290, '1', NULL, 'Arrival in Kathmandu Valley (1,350 m / 4,429 ft)', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Your Himalayan adventure begins upon arrival at Tribhuvan International Airport in Kathmandu, the vibrant capital city of Nepal. After landing, our representative will warmly welcome you and transfer you to your hotel in the bustling tourist district of Thamel. Kathmandu is a historic city filled with ancient temples, colorful markets, and rich cultural heritage. After checking into the hotel, you can rest after your long international flight or explore the lively streets nearby.</p>\r\n<p>In the evening, there will be a welcome briefing with your expedition leader and team members, where you will receive detailed information about the Himlung Himal Expedition, climbing permits, safety procedures, and the upcoming trekking route. This day also provides time to check your climbing gear and make any last-minute purchases if necessary.</p>', 1, '2026-03-06 22:48:19', '2026-03-16 17:02:47');
INSERT INTO `cl_trip_itinerary` (`id`, `trip_detail_id`, `days`, `meals`, `title`, `max_altitude`, `distance`, `duration`, `content`, `ordering`, `created_at`, `updated_at`) VALUES
(3363, 290, '2', NULL, 'Trek Preparation in Kathmandu', '1400', '4 Star Hotel', 'Breakfast', '<div class=\"flex flex-col text-sm pb-25\">\r\n<article class=\"text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]\" dir=\"auto\" data-turn-id=\"request-WEB:6efa45dc-ea9d-4685-9b11-9d092e9f2adc-4\" data-testid=\"conversation-turn-10\" data-scroll-anchor=\"true\" data-turn=\"assistant\" tabindex=\"-1\">\r\n<div class=\"text-base my-auto mx-auto pb-10 [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)\">\r\n<div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn\" tabindex=\"-1\">\r\n<div class=\"flex max-w-full flex-col gap-4 grow\">\r\n<div data-message-author-role=\"assistant\" data-message-id=\"2491be3a-5f7b-4871-a6e9-59107d90e449\" dir=\"auto\" data-message-model-slug=\"gpt-5-3\" class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\">\r\n<div class=\"flex w-full flex-col gap-1 empty:hidden\">\r\n<div class=\"markdown prose dark:prose-invert w-full wrap-break-word dark markdown-new-styling\">\r\n<p data-start=\"46\" data-end=\"807\" data-is-last-node=\"\" data-is-only-node=\"\" style=\"text-align: left;\">Today you will spend the day preparing for the Baruntse expedition in Kathmandu. After breakfast, you will meet your expedition leader and climbing team for a detailed briefing about the trekking route, climbing strategy, safety procedures, and acclimatization plan for the journey ahead. You will also carefully check your trekking and climbing equipment, including crampons, ice axes, harnesses, climbing boots, and high-altitude gear to make sure everything is ready for the expedition. If any items are missing, you will have time to visit the trekking shops in Thamel to rent or purchase the necessary gear before departure. In the evening, you will return to your hotel, relax, and mentally prepare for the incredible Himalayan adventure that begins soon.</p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"z-0 flex min-h-[46px] justify-start\"></div>\r\n<div class=\"mt-3 w-full empty:hidden\">\r\n<div class=\"text-center\"></div>\r\n</div>\r\n</div>\r\n</div>\r\n</article>\r\n</div>', 2, '2026-03-06 22:48:19', '2026-03-16 17:02:47'),
(3379, 291, '1', NULL, 'Day 1: Arrival in Kathmandu (1,354 m)', '4 Star Hotel', NULL, 'Welcome Dinner', '<p>Your adventure begins as you arrive at Tribhuvan International Airport in Kathmandu. You will be warmly welcomed by your guide and transferred to your hotel. The remainder of the day is reserved for rest and preparation, including organizing gear and attending a detailed expedition briefing. Your guide will cover the itinerary, safety protocols, and essentials for trekking and climbing in the Everest region. You may also use this time to explore Thamel, the bustling heart of Kathmandu, full of shops, cafés, and trekking outfitters.</p>', 1, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3380, 291, '2', NULL, 'Kathmandu Sightseeing and Final Preparations', '4 Star Hotel', NULL, 'Breakfast', '<p>Today is devoted to cultural immersion and final preparations. Visit UNESCO World Heritage Sites such as Pashupatinath Temple, Boudhanath Stupa, and Swayambhunath (Monkey Temple). These iconic landmarks offer a glimpse of Nepal\'s rich heritage and spiritual traditions. Your guide will ensure all climbing and trekking permits are ready, including the Sagarmatha National Park entry permit, TIMS card, and Island Peak climbing permit. Gear checks and packing advice will be provided to ensure you are ready for the challenging expedition ahead</p>', 2, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3381, 291, '3', NULL, 'Flight to Lukla (2,860 m) and Trek to Phakding (2,610 m)', 'Tea House', NULL, 'B, L, & D', '<p>Take an early morning scenic flight to Lukla one of the most exhilarating experiences in the Himalayas as the runway perches atop a steep hillside with panoramic views of snowy peaks. From Lukla, begin your trek along the Dudh Koshi River, crossing suspension bridges and passing through small villages. Today\'s trek is gentle and serves as a first acclimatization walk, ending in Phakding, where you will stay overnight in a teahouse.</p>', 3, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3382, 291, '4', NULL, 'Trek from Phakding to Namche Bazaar (3,440 m)', 'Tea House', NULL, 'B, L, & D', '<p>The trail gradually ascends through lush forests of rhododendron and pine, crossing several rivers via suspension bridges. The trek passes through Monjo and Jorsale before eventually reaching the vibrant market town of Namche Bazaar, the gateway to the Everest region. Namche is a lively Sherpa town offering views of Thamserku and Kongde Ri. Take time to explore the local market and rest, as Namche serves as your first major acclimatization stop.</p>', 4, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3383, 291, '5', NULL, 'Acclimatization Day in Namche Bazaar', 'Tea House', NULL, 'B, L, & D', '<p>Spend the day adjusting to the altitude and exploring the surroundings. Hike to the Everest View Hotel for spectacular vistas of Everest (8,848 m), Lhotse (8,516 m), Nuptse (7,861 m), and Ama Dablam (6,812 m). This day is crucial for reducing the risk of altitude sickness. You can also visit Khumjung Village, home to the famous Hillary School and a monastery housing a reputed sacred Yeti scalp.</p>', 5, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3384, 291, '6', NULL, 'Trek from Namche Bazaar to Tengboche (3,860 m)', 'Tea House', NULL, 'B, L, & D', '<p>The trail continues through Sherpa settlements with magnificent views of the Everest massif. Visit Tengboche Monastery, the largest in the region, which offers a spiritual atmosphere set against the backdrop of towering peaks. This stretch is moderate but includes some steep sections. The evening is spent resting and enjoying a traditional Sherpa meal.</p>', 6, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3385, 291, '7', NULL, 'Trek from Tengboche to Dingboche (4,410 m)', 'Tea House', NULL, 'B, L, & D', '<p>Trek through a stunning high-altitude landscape, passing yak pastures, icy streams, and rocky terrain. Views of Ama Dablam dominate the skyline as you approach Dingboche, a village nestled in a picturesque valley surrounded by mountains. Overnight at a teahouse in preparation for further altitude gain.</p>', 7, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3386, 291, '8', NULL, 'Acclimatization Day in Dingboche', 'Tea House', NULL, 'B, L, & D', '<p>Spend the day acclimatizing with a hike to Nangkar Tshang Peak or nearby ridges. The higher-altitude trek conditions your body for the challenges ahead and provides awe-inspiring views of Lhotse and Island Peak. Learn basic mountaineering skills and practice with crampons and ropes, guided by your expert Sherpa team.</p>', 8, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3387, 291, '9', NULL, 'Trek from Dingboche to Lobuche (4,940 m)', 'Tea House', NULL, 'B, L, & D', '<p>The trail climbs gently alongside the Imja Khola, passing memorials dedicated to climbers who lost their lives on Everest. Lobuche is a small settlement beneath towering ridges, providing the perfect base for your approach to Island Peak Base Camp. Overnight in a teahouse in preparation for higher-elevation trekking.</p>', 9, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3388, 291, '10', NULL, 'Trek from Lobuche to Everest Base Camp (5,364 m) and Return to Gorak Shep (5,164 m)', 'Tea House', NULL, 'B, L, & D', '<p>Today is the highlight of the trek Everest Base Camp (EBC). The path passes the Khumbu Glacier and iconic landmarks such as the Memorial Wall. Standing at EBC, you are surrounded by the footprints of climbers aiming for 8,000 m summits like Everest, Lhotse, and Nuptse. After soaking in the dramatic vistas, descend to Gorak Shep for the night.</p>', 10, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3389, 291, '11', NULL, 'Kala Patthar (5,545 m) and Trek to Pheriche (4,240 m)', 'Tea House', NULL, 'B, L, & D', '<p>Rise early for a pre-dawn hike to Kala Patthar, a viewpoint offering the most stunning sunrise views over Everest and the surrounding Himalayan giants. After enjoying the panoramic vistas, descend to Pheriche, passing glacial moraines and high-altitude landscapes. Overnight in Pheriche, a village known for its acclimatization clinics and medical posts.</p>', 11, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3390, 291, '12', NULL, 'Trek from Pheriche to Island Peak Base Camp (5,100 m)', 'Tea House', NULL, 'B, L, & D', '<p>The trail now shifts focus from trekking to climbing. Hike through the Imja Valley, crossing glacial streams and moraines, until you reach Island Peak Base Camp. Spend the afternoon with your climbing team learning technical skills and practicing rope handling, crampon walking, and ice axe techniques. This is the final preparation before your summit push.</p>', 12, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3391, 291, '13', NULL, 'Island Peak High Camp (5,600 m', 'Tea House', NULL, 'B, L, & D', '<p>Climb to High Camp, located on the upper slopes of Island Peak. The ascent includes moraine trails, rock scrambles, and glacier walking. Your Sherpa team will help set up tents and provide mountaineering guidance. Use the evening to rest and hydrate, as summit day will begin in the early hours.</p>', 13, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3392, 291, '14', NULL, 'Island Peak Summit (6,189 m) and Return to Base Camp', 'Tea House', NULL, 'B, L, & D', '<p>Wake at midnight for the summit attempt, moving under starlit skies to avoid strong winds. The climb includes vertical ice walls (100 m), glacier crossings, and a narrow summit ridge requiring rope assistance. Upon reaching the top, experience 360-degree views of Lhotse, Makalu, Baruntse, Ama Dablam, and the surrounding Himalayas, with glacial valleys unfolding below. Descend carefully to Base Camp for a well-deserved rest.</p>', 14, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3393, 291, '15', NULL, 'Trek from Island Peak Base Camp to Namche Bazaar (3,440 m', 'Tea House', NULL, 'B, L, & D', '<p>Begin the descent through the Khumbu Valley, retracing your steps past Dingboche, Tengboche, and other villages. Enjoy the changing landscapes, from high alpine terrain to lush forests and cultural settlements. Overnight in Namche Bazaar, celebrating your successful climb and trek.</p>', 15, '2026-03-07 00:16:24', '2026-03-07 18:29:13'),
(3394, 291, '16', NULL, 'Trek to Lukla and Flight to Kathmandu', '4 Star Hotel', NULL, 'B, L, & D', '<p>Complete the trek back to Lukla, where you will board a flight to Kathmandu. Upon arrival, transfer to your hotel for relaxation or last-minute shopping. The evening is an opportunity to celebrate the expedition, share experiences, and prepare for departure the following day.</p>', 16, '2026-03-07 00:16:24', '2026-03-07 18:29:14'),
(3395, 291, '17', NULL, 'Departure from Kathmandu', NULL, NULL, NULL, '<p>After a hearty breakfast and some final shopping or sightseeing in Thamel, you will be transferred to Tribhuvan International Airport for your onward flight. Reflect on your incredible 17-day adventure the trek to Everest Base Camp, the technical climb of Island Peak, and the unforgettable views of 8,000 m Himalayan giants. Safe travels as you depart Nepal, carrying memories of both its natural beauty and Sherpa culture.</p>', 17, '2026-03-07 00:16:24', '2026-03-07 18:29:14'),
(3396, 292, '1', NULL, 'Arrival in Kathmandu (1,400m)', '4 Star Hotel', NULL, 'Welcome Dinner', '<p>Upon arrival at Tribhuvan International Airport in Kathmandu, you\'ll be met by our representative and transferred to your hotel in the Thamel area. The rest of the day is free for you to recover from your journey and explore the vibrant streets of Nepal\'s capital.</p>\r\n<p> </p>\r\n<p>In the evening, there will be a welcome dinner where you\'ll meet your expedition leader and fellow climbers for an initial briefing about the journey ahead. This is an opportunity to ask questions, discuss equipment, and finalize any last-minute preparations.</p>', 1, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3397, 292, '2', NULL, 'Kathmandu - Expedition Preparations and Briefing', '4 Star Hotel', NULL, 'Breakfast', '<p>This day is dedicated to final expedition preparations in Kathmandu. You\'ll attend a comprehensive briefing at the expedition office, where the climbing leader will discuss the detailed itinerary, safety protocols, and mountain conditions. The morning includes a permit briefing at the Department of Tourism, followed by an equipment check to ensure all technical gear meets expedition standards.</p>\r\n<p> </p>\r\n<p>You\'ll have time to purchase any last-minute items in Thamel\'s well-stocked outdoor shops. In the afternoon, there\'s an opportunity to visit Kathmandu\'s UNESCO World Heritage Sites such as Swayambhunath (Monkey Temple) or Pashupatinath Temple, offering cultural immersion before departing for the mountains.</p>', 2, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3398, 292, '3', NULL, 'Fly to Bhadrapur and Drive to Ilam (1,200m)', 'Tourist Standard Hotel', NULL, 'Breakfast', '<p>An early morning flight takes you to Bhadrapur in eastern Nepal, offering stunning aerial views of the Himalayan range. The 45-minute flight descends into the subtropical lowlands near the Indian border. From Bhadrapur, a scenic drive of approximately 3-4 hours brings you to Ilam, a picturesque hill town famous for its tea plantations. The winding road climbs through lush green hillsides covered in terraced tea gardens.</p>\r\n<p>You\'ll spend the night in Ilam, enjoying the mild climate and perhaps sampling the region\'s renowned orthodox tea. This is your last experience of comfortable accommodation before beginning the trek.</p>', 3, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3399, 292, '4', NULL, 'Drive to Taplejung and Trek to Mitlung (921m)', 'Tea House', NULL, 'B, L, & D', '<p>After breakfast, you\'ll embark on a 6-7 hour drive to Taplejung, the district headquarters and gateway to the Kanchanjunga region. The journey follows rough mountain roads with spectacular views of rural eastern Nepal. Upon reaching Taplejung, you\'ll meet your trekking crew and porters who will accompany you throughout the expedition.</p>\r\n<p>The trek begins with a descent to Mitlung village, taking approximately 2-3 hours along a well-worn trail through traditional Limbu settlements. This gentle start allows your body to adjust to walking with a pack while experiencing the warmth and hospitality of Nepal\'s eastern hill communities.</p>', 4, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3400, 292, '5', NULL, 'Trek to Chirwa (1,270m)', 'Tea House', NULL, 'B, L, & D', '<p>The trail continues following the Tamor River valley, gradually ascending through subtropical forests filled with rhododendron, bamboo, and orchids. You\'ll cross several suspension bridges over cascading tributaries, each offering thrilling crossings high above the churning rivers below. The path passes through small villages where you can observe traditional farming practices and terraced rice paddies carved into the hillsides.</p>\r\n<p>The 6-7 hour trek brings you to Chirwa, a small settlement where you\'ll camp for the night. The increasing remoteness becomes apparent as modern conveniences fade and you immerse yourself deeper into mountain life.</p>', 5, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3401, 292, '6', NULL, 'Trek to Sukathum (1,580m)', 'Tea House', NULL, 'B, L, & D', '<p>Today\'s trek of 5-6 hours continues along the Tamor River, with the trail alternating between riverside paths and climbs over ridges that separate side valleys. You\'ll pass through several small settlements, including Taplethok and Hellok, where teahouses offer refreshment and glimpses into local culture. The vegetation begins to transition as you gain altitude, with temperate forest species becoming more prominent.</p>\r\n<p>The trail can be challenging during the monsoon season when leeches are common in the lower forests. Sukathum sits at the confluence of the Tamor and Ghunsa rivers, marking a significant junction in the valley system. The evening offers time to rest and prepare for the steeper climbing ahead.</p>', 6, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3402, 292, '7', NULL, 'Trek to Amjilosa (2,510m)', 'Tea House', NULL, 'B, L, & D', '<p>The character of the trek changes significantly today as you leave the Tamor valley and begin ascending the Ghunsa Khola valley toward Kanchanjunga. The trail climbs steeply through dense rhododendron and bamboo forests, gaining nearly 1,000 meters over 5-6 hours of trekking. You\'ll cross several tributary streams on log bridges and climb through areas that can be muddy and slippery, especially during or after rain.</p>\r\n<p>The forest is alive with birdlife, and if fortunate, you might spot Himalayan monkeys in the canopy. Amjilosa is a small clearing with basic teahouse facilities, offering your first real mountain camping experience. The temperature drops noticeably as you gain elevation.</p>', 7, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3403, 292, '8', NULL, 'Trek to Gyabla (2,730m)', 'Tea House', NULL, 'B, L, & D', '<p>Continuing up the Ghunsa valley, today\'s 5-6 hour trek passes through magnificent old-growth forests of pine, oak, and rhododendron. The trail undulates along the valley side, occasionally descending to cross side streams before climbing again. You\'ll notice the architecture and culture beginning to shift as you approach areas traditionally inhabited by people of Tibetan origin. Prayer flags and stone chortens (Buddhist shrines) become more common along the trail.</p>\r\n<p>The village of Gyabla offers spectacular views up the valley toward the approaching peaks. The thinning air at this altitude may begin to affect some team members, making it important to maintain a steady, sustainable pace and stay well-hydrated.</p>', 8, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3404, 292, '9', NULL, 'Trek to Ghunsa (3,595m)', 'Tea House', NULL, 'B, L, & D', '<p>Today\'s trek of 4-5 hours brings you to Ghunsa, the largest village in the upper valley and an important cultural center for the Tibetan Buddhist community. The trail continues through alpine forests with increasing views of snow-capped peaks. Ghunsa village features traditional stone houses with colorful prayer flags strung between buildings, a monastery, and several teahouses serving both trekkers and local residents.</p>\r\n<p>This is a significant settlement where yak herders and traders have lived for generations, maintaining traditional Tibetan Buddhist culture. You\'ll spend the night here, allowing time to explore the village, visit the monastery, and continue the crucial acclimatization process before climbing higher.</p>', 9, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3405, 292, '10', NULL, 'Acclimatization Day in Ghunsa', 'Tea House', NULL, 'B, L, & D', '<p>This rest day is essential for proper acclimatization to the increasing altitude. Rather than remaining completely inactive, you\'ll take a short acclimatization hike to higher elevation, climbing 300-400 meters above the village before descending to sleep at Ghunsa. This \"climb high, sleep low\" strategy helps your body produce more red blood cells and adapt to lower oxygen levels. You might hike to the viewpoint above the village or explore the lateral moraine on the valley side.</p>\r\n<p> </p>\r\n<p>The afternoon allows time to visit Ghunsa\'s Buddhist monastery, interact with local residents, organize gear, and rest. Expedition doctors will monitor team members for any signs of altitude sickness.</p>', 10, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3406, 292, '11', NULL, 'Trek to Khambachen (4,050m)', 'Tea House', NULL, 'B, L, & D', '<p>The trail climbs gradually out of Ghunsa through thinning forest, eventually emerging into the alpine zone above the tree line. The 4-5 hour trek offers increasingly dramatic mountain views as you approach the heart of the Kanchanjunga sanctuary. The landscape transforms into rocky moraines, glacial streams, and alpine meadows where yaks graze during the summer months.</p>\r\n<p> </p>\r\n<p>You\'ll pass several stone shelters used by yak herders and cross glacial outwash plains where braided streams from the Kanchanjunga Glacier flow through wide gravel beds. Khambachen is a seasonal settlement with basic lodges, sitting in a spectacular amphitheater surrounded by towering peaks. The thin air and cold temperatures are a reminder that you\'re now in the high Himalayas.</p>', 11, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3407, 292, '12', NULL, 'Acclimatization Day in Khambachen', 'Tea House', NULL, 'B, L, & D', '<p>Another crucial acclimatization day allows your body to continue adapting to the altitude. You\'ll take an acclimatization hike toward Kanchanjunga North Base Camp or climb the ridge behind Khambachen for spectacular panoramic views of the surrounding peaks, including Jannu (7,710m) and the north face of Kanchanjunga. The hike typically lasts 3-4 hours, climbing 300-400 meters higher before returning to Khambachen to sleep.</p>\r\n<p>This is an excellent opportunity for photography as the clear mountain air and proximity to the giants of the Himalayas offer breathtaking vistas. The afternoon is spent resting, hydrating, and allowing your body to process the altitude gains.</p>', 12, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3408, 292, '13', NULL, 'Trek to Lhonak (4,780m)', 'Tea House', NULL, 'B, L, & D', '<p>Today\'s trek of 4-5 hours continues up the valley toward the base of Kanchanjunga. The trail crosses the snout of the Kanchanjunga Glacier and navigates through a moonscape of glacial debris, rocky moraines, and ice-scoured bedrock. The vegetation has completely disappeared, leaving only a stark world of rock, ice, and snow. You\'ll cross several glacial streams on makeshift bridges and climb over lateral moraines that tower above the glacier surface.</p>\r\n<p>Lhonak is a basic camping area in a desolate but spectacular location, with massive ice faces and hanging glaciers visible on all sides. The temperature can drop significantly at night, and strong winds often funnel down from the glaciers above.</p>', 13, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3409, 292, '14', NULL, 'Trek to Kanchanjunga Base Camp (5,140m)', 'Tea House', NULL, 'B, L, & D', '<p>The final approach to base camp takes 3-4 hours across the lateral moraine alongside the Kanchanjunga Glacier. The trail is rough and requires careful footing over unstable rocks and across glacial streams.</p>\r\n<p>As you round the final ridge, the full south face of Kanchanjunga comes into view, a massive wall of ice, rock, and snow rising over 3,000 meters above you. Base camp is established on the rocky moraine at the edge of the glacier, with spectacular views of Kanchanjunga\'s southwest face and neighboring peaks including Wedge Peak and the Twins. This will be your home for the next several weeks as you prepare for the summit push.</p>', 14, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3410, 292, '15 to 16', NULL, 'Base Camp - Rest and Preparation', 'Tea House', NULL, 'B, L, & D', '<p>These days are spent organizing base camp, setting up communication systems, and preparing equipment for the climbing phase. The expedition Sherpas will begin establishing the route through the icefall, fixing ropes on the most technical sections, and scouting locations for higher camps. Climbers rest, sort gear, and conduct training sessions on the use of fixed ropes, ascending and descending with jumars, and reviewing crevasse rescue techniques. The expedition doctor monitors everyone\'s health and oxygen saturation levels. These final preparation days are crucial for ensuring all systems are ready before committing to the mountain.</p>', 15, '2026-03-07 19:10:44', '2026-03-07 19:11:32'),
(3411, 292, '17 to 45', NULL, 'Climbing Period', 'Tent', NULL, 'B, L, & D', '<p>This extended period encompasses the summit push, including establishing Camps 1 (5,900m), 2 (6,800m), 3 (7,400m), and 4 (7,850m). The climbing strategy follows a rotational approach where team members make multiple ascents to progressively higher camps before descending to base camp to rest and recover. This process, typically requiring three or four rotations, continues the acclimatization process while allowing climbers to cache equipment and supplies at higher camps. The route from base camp climbs through a dangerous icefall threatened by seracs and avalanches from the hanging glaciers above. Fixed ropes are established on the steepest sections, and the Sherpa team maintains the route as the glacier shifts and crevasses open.</p>\r\n<p>Camp 1 sits on a relatively flat section of the glacier, offering a temporary respite from the technical climbing. From Camp 1, the route continues up the glacier before tackling steep snow and ice slopes leading to Camp 2. This section requires front-pointing with crampons and climbing sustained pitches of 50-60 degree ice. Camp 2 to Camp 3 involves mixed climbing over rock, ice, and snow, with exposure to high winds and extreme cold. The terrain becomes increasingly technical, with knife-edge ridges, exposed traverses, and steep headwalls requiring full concentration and technical skill.</p>\r\n<p>Camp 3 is positioned on a precarious platform carved from the ice, and climbers must be prepared for extremely cold conditions and strong winds that can make tent life miserable. The final push from Camp 3 to Camp 4 and then to the summit follows the southeast ridge, with sections of exposed climbing along narrow snow ridges with massive drops on either side.</p>\r\n<p>Summit day typically begins around midnight, with climbers using headlamps to navigate the initial steep sections. The route crosses the upper snowfields and climbs the final summit pyramid, requiring 10-14 hours of continuous climbing from Camp 4. Following tradition, climbers stop just short of the absolute summit to honor the sacred nature of the peak.</p>\r\n<p>Weather windows are critical, and the team must be prepared to wait at base camp or descend from higher camps if conditions deteriorate. The expedition leader monitors weather forecasts closely and makes strategic decisions about when to push higher or retreat to safety. Several days are built into the schedule for weather delays and to allow multiple summit attempts if necessary.</p>', 16, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3412, 292, '46 to 48', NULL, 'Return to Base Camp and Clean-Up', 'Tent', NULL, 'B, L, & D', '<p>After successful summits or when the climbing window closes, all team members descend to base camp. These days are spent dismantling the high camps, recovering cached equipment, and cleaning base camp. Following Leave No Trace principles, all waste is packed out, and the campsite is returned to its natural state.</p>\r\n<p>There\'s a mixture of emotions during this phase relief at returning safely, satisfaction with achievements, and perhaps disappointment if summit goals weren\'t met. The team celebrates their accomplishments together, sharing stories and photographs from the mountain.</p>', 17, '2026-03-07 19:10:44', '2026-03-07 19:14:15'),
(3413, 292, '49', NULL, 'Trek to Khambachen (4,050m)', 'Tent', NULL, 'B, L, & D', '<p>The return journey begins with a long day descending from base camp to Khambachen. The 6-7 hour trek retraces your route down the valley, and the increasing oxygen levels at lower altitude are immediately noticeable. Energy levels rise, breathing becomes easier, and the landscape that seemed harsh on the way up now appears welcoming. The teahouses at Khambachen offer the first real comfort in weeks, with opportunities for hot showers and fresh food beyond expedition rations. Team members often feel a profound sense of relief at leaving the extreme altitude behind.</p>', 18, '2026-03-07 19:10:44', '2026-03-07 19:11:33'),
(3414, 292, '50', NULL, 'Trek to Ghunsa (3,595m)', 'Tent', NULL, 'B, L, & D', '<p>Continuing the descent, today\'s 4-5 hour trek drops another 500 meters to Ghunsa. The trail passes through familiar landscapes that were challenging on the approach but now seem easy as your acclimatized bodies operate efficiently at this moderate altitude. Ghunsa village offers a chance to visit the monastery again, purchase local handicrafts, and enjoy the hospitality of the teahouse owners who are always eager to hear summit stories. The relative warmth and thicker air make sleep much more restful than at higher elevations.</p>', 19, '2026-03-07 19:10:44', '2026-03-07 19:11:33'),
(3415, 292, '51', NULL, 'Trek to Amjilosa (2,510m)', 'Tent', NULL, 'B, L, & D', '<p>The long descent continues through the forested sections of the Ghunsa valley. The 5-6 hour trek drops over 1,000 meters, bringing you back into the lush vegetation zones with rhododendrons, birdsong, and the sound of rushing water. The temperature rises noticeably, and you may even feel warm during the day a stark contrast to the freezing conditions at base camp. Amjilosa\'s simple camping area provides basic facilities, and the surrounding forest offers a peaceful environment for reflection on the expedition experience.</p>', 20, '2026-03-07 19:10:44', '2026-03-07 19:11:33'),
(3416, 292, '52', NULL, 'Trek to Sukathum (1,580m)', 'Tent', NULL, 'B, L, & D', '<p>Descending further into the valley system, today\'s trek of 5-6 hours brings you to the confluence of the Ghunsa and Tamor rivers at Sukathum. The trail is predominantly downhill, though there are still some short uphill sections as the path crosses side ridges. The vegetation becomes increasingly subtropical, with broadleaf trees replacing the conifers of higher elevations. The warmer, humid air feels thick and rich with oxygen after weeks at altitude. Sukathum\'s small settlement marks your return to the lower regions where cultivation and normal village life resumes.</p>', 21, '2026-03-07 19:10:44', '2026-03-07 19:11:33'),
(3417, 292, '53', NULL, 'Trek to Taplejung (1,820m)', 'Tent', NULL, 'B, L, & D', '<p>Rather than retracing the entire route to Mitlung and Chirwa, the trek takes an alternative route directly to Taplejung. This 6-7 hour trek involves significant climbing as you gain altitude to reach the district headquarters perched on its hillside. The trail passes through terraced farmland, small villages, and patches of forest. Taplejung feels almost urban after weeks in the wilderness, with shops, restaurants, and a bustling market. You\'ll stay in a lodge, enjoying the luxury of a real bed, hot shower, and diverse food options for the first time since leaving Kathmandu.</p>', 22, '2026-03-07 19:10:44', '2026-03-07 19:11:33'),
(3418, 292, '54', NULL, 'Drive to Bhadrapur and Fly to Kathmandu', 'Tent', NULL, 'B, L, & D', '<p>An early morning departure begins the long journey back to Kathmandu. The 6-7 hour drive to Bhadrapur retraces the rough mountain roads, descending through progressively lower elevations to the subtropical plains. The afternoon flight from Bhadrapur back to Kathmandu reverses your original route, offering final views of the Himalayan range from the air. Upon arrival in Kathmandu, you\'ll be transferred to your hotel in Thamel. The evening is free to rest, enjoy a hot shower, and venture out to the restaurants and shops of the capital. The contrast between the expedition environment and urban life is striking.</p>', 23, '2026-03-07 19:10:44', '2026-03-07 19:11:33'),
(3419, 292, '55', NULL, 'Kathmandu - Rest and Celebration', 'Tent', NULL, 'B, L, & D', '<p>This buffer day in Kathmandu allows for flight delays, provides a chance to recover from the journey, and offers time to explore the city properly. Many team members visit additional cultural sites, shop for souvenirs and trekking gear, or simply relax in cafes recounting expedition stories. In the evening, there\'s a farewell celebration dinner, typically held at a traditional Nepali restaurant with cultural performances. Certificates of achievement are presented, photographs are shared, and team members exchange contact information, having formed bonds through the shared challenges of the expedition.</p>', 24, '2026-03-07 19:10:44', '2026-03-07 19:11:33'),
(3420, 292, '56', NULL, 'Departure from Kathmandu', 'Tent', NULL, 'B, L, & D', '<p>On the final day, you\'ll be transferred to Tribhuvan International Airport according to your flight schedule. Depending on departure times, there may be opportunity for last-minute shopping or sightseeing. The expedition concludes as team members depart for their home countries, carrying memories of Kanchenjunga’s sacred summit, the challenges overcome, and the friendships forged in one of the world\'s most spectacular mountain environments. For many, this marks the end of one adventure and the beginning of planning the next.</p>', 25, '2026-03-07 19:10:44', '2026-03-07 19:11:33'),
(3421, 293, '1', NULL, 'Arrival in Kathmandu (1,400 m)', '4 Star Hotel', NULL, 'Welcome Dinner', '<p>Arrive at Tribhuvan International Airport in Kathmandu, the gateway to the Himalayas. Our team will welcome you and transfer you to your hotel. Take this day to rest after your international flight, recover from travel fatigue, and prepare for the expedition. In the evening, enjoy a briefing covering expedition details, route plans, permits, and essential equipment checks. Overnight stay in Kathmandu.</p>', 1, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3422, 293, '2', NULL, 'Rest and Expedition Briefing in Kathmandu', '4 Star Hotel', NULL, 'Breakfast', '<p>Spend the day in Kathmandu resting and preparing for the expedition. Participate in a detailed briefing with your expedition leader covering acclimatization schedules, high-altitude safety, equipment usage, and emergency protocols. This is also the day to make final adjustments to your gear and review the climbing plan. Overnight in Kathmandu.</p>', 2, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3423, 293, '3', NULL, 'Fly to Lukla and Trek to Phakding (2,800 m)', 'Tea House', NULL, 'Breakfast and Dinner', '<p>Take an early morning scenic flight from Kathmandu to Lukla, considered one of the most thrilling airports in the world. Begin trekking along the Dudh Koshi River, passing traditional Sherpa villages, prayer flags, and suspension bridges. The trail is gentle, helping your body adjust to altitude while enjoying views of pine forests and the surrounding hills. Overnight stay in a lodge at Phakding.</p>', 3, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3424, 293, '4', NULL, 'Trek from Phakding to Namche Bazaar (3,440 m)', 'Tea House', NULL, 'B, L, & D', '<p>The trail steadily ascends through pine and rhododendron forests, with several river crossings and suspension bridges. Arrive at Namche Bazaar, the cultural and commercial hub of the Khumbu region. Take time to explore the local market, visit small monasteries, and enjoy panoramic views of mountains including Kongde Ri and Thamserku. Overnight in Namche Bazaar.</p>', 4, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3425, 293, '5', NULL, 'Acclimatization Day at Namche Bazaar', 'Tea House', NULL, 'B, L, & D', '<p>A full day at Namche Bazaar to acclimatize to higher altitudes. Optional hikes include a trek to Everest View Hotel or nearby ridges to enjoy spectacular views of Everest, Lhotse, and Ama Dablam. This day reduces the risk of altitude sickness and prepares climbers for the challenging trek ahead. Overnight in Namche Bazaar.</p>', 5, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3426, 293, '6', NULL, 'Trek from Namche Bazaar to Dibuche (3,870 m)', 'Tea House', NULL, 'B, L, & D', '<p>The trail passes through dense forests and highland meadows, gradually gaining altitude. Cross the Dudh Koshi River and trek past traditional Sherpa villages. Dibuche offers serene mountain views and a chance to rest and acclimatize before heading into higher terrain. Overnight at Dibuche lodge.</p>', 6, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3427, 293, '7', NULL, 'Trek from Dibuche to Dingboche (4,243 m)', 'Tea House', NULL, 'B, L, & D', '<p>The trek moves through alpine terrain with moraines and scattered villages. Dingboche, a key acclimatization stop, provides sweeping views of Lhotse, Island Peak, and Ama Dablam. Trekkers are encouraged to hike nearby ridges for additional acclimatization. Overnight in Dingboche.</p>', 7, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3428, 293, '8', NULL, 'Trek from Dingboche to Lobuche (4,930 m)', 'Tea House', NULL, 'B, L, & D', '<p>The trail becomes more rugged, passing through high-altitude moraine fields and glacial streams. Lobuche, a small settlement near the Khumbu Glacier, serves as the final stop before the approach to Everest and Lhotse Base Camps. Overnight in a lodge at Lobuche.</p>', 8, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3429, 293, '9', NULL, 'Trek from Lobuche to Everest Base Camp (5,364 m)', 'Tea House', NULL, 'B, L, & D', '<p>Reach the legendary Everest Base Camp, the launching point for Everest and Lhotse expeditions. Witness the Khumbu Icefall, glaciers, and towering peaks of Lhotse, Nuptse, and Everest. Set up camp in tents and begin final preparations for the high-altitude rotations. Overnight at Base Camp.</p>', 9, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3430, 293, '10 to 39', NULL, 'Rotation Between Base Camp and High Camps (Camp I, II, III)', 'Tent', NULL, 'B, L, & D', '<p>Climbers follow a rotation schedule between Base Camp and higher camps (Camp I, II, and III) for acclimatization and technical preparation. These rotations involve carrying loads, setting up camps, and familiarizing with climbing routes while gradually increasing altitude. This period is critical for ensuring a safe summit attempt. Full board meals and tents are provided during these rotations.</p>', 10, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3431, 293, '40 to 53', NULL, 'Summit Period – Base Camp to Lhotse Summit (8,516 m) and Return', 'Tent', NULL, 'B, L, & D', '<p>The summit push begins from Base Camp, progressing through the high camps to reach Lhotse’s summit at 8,516 meters. Climbers follow carefully planned schedules with expert guidance and Sherpa support. After summiting, climbers descend safely back to Base Camp. This period focuses on summit success while managing high-altitude risks. Full board meals and tents are provided.</p>', 11, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3432, 293, '54', NULL, 'Cleaning Up Base Camp', 'Tent', NULL, 'B, L, & D', '<p>Spend the day cleaning up Base Camp and organizing equipment for the descent. This ensures minimal environmental impact and proper preparation for the trek down. Overnight at Base Camp tents.</p>', 12, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3433, 293, '55', NULL, 'Trek from Base Camp to Pheriche (4,371 m)', 'Tent', NULL, 'B, L, & D', '<p>Begin the descent through Lobuche and Thukla, retracing the trail with stunning Himalayan views. Overnight stay in Pheriche, a peaceful village perfect for resting after the high-altitude climb.</p>', 12, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3434, 293, '56', NULL, 'Trek from Pheriche to Namche Bazaar (3,440 m)', 'Tent', NULL, 'B, L, & D', '<p>Continue descending through alpine landscapes and traditional villages. This day allows climbers to reflect on their expedition achievements. Overnight in Namche Bazaar.</p>', 13, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3435, 293, '57', NULL, 'Trek from Namche Bazaar to Lukla (2,860 m)', 'Tent', NULL, 'B, L, & D', '<p>Complete the trek back to Lukla, passing forests, rivers, and local settlements. Celebrate the successful completion of the expedition before preparing for the flight to Kathmandu. Overnight in a lodge at Lukla.</p>', 14, '2026-03-07 21:07:13', '2026-03-07 21:11:29'),
(3436, 293, '58', NULL, 'Fly from Lukla to Kathmandu & Transfer to Hotel', '4 Star Hotel', NULL, 'Breakfast', '<p>Take a scenic flight back to Kathmandu. Transfer to your hotel and spend the evening at leisure, resting and enjoying Kathmandu’s vibrant atmosphere. Overnight in Kathmandu.</p>', 15, '2026-03-07 21:07:14', '2026-03-07 21:11:29'),
(3437, 293, '59', NULL, 'Leisure Day in Kathmandu', '4 Star Hotel', NULL, 'Breakfast', '<p>Enjoy a free day in Kathmandu for sightseeing, shopping, or cultural exploration. This is the perfect opportunity to visit temples, markets, or relax before your departure. Overnight in Kathmandu.</p>', 16, '2026-03-07 21:07:14', '2026-03-07 21:11:29'),
(3438, 293, '60', NULL, 'Departure from Kathmandu', '4 Star Hotel', NULL, 'Breakfast', '<p>After breakfast, transfer to Tribhuvan International Airport for your onward flight. Depart with memories of an extraordinary expedition, having conquered Lhotse and experienced the remote beauty of the Himalayas.</p>', 17, '2026-03-07 21:07:14', '2026-03-07 21:11:29'),
(3439, 294, '1', NULL, 'Arrival in Kathmandu (1,350m) & Transfer to Hotel', '4 Star Hotel', NULL, 'Welcome Dinner', '<p>Welcome to Nepal! Upon arrival at Tribhuvan International Airport, you will be warmly greeted by our representative and transferred to your hotel in Kathmandu. This day allows you to rest and recover from your international flight. In the evening, we’ll conduct a briefing about the upcoming expedition, including an itinerary overview, equipment check, and travel tips for the trek and climb.</p>', 1, '2026-03-07 21:54:15', '2026-03-07 21:56:51'),
(3440, 294, '2', NULL, 'Flight to Lukla and Trek to Phakding (2,651m)', 'Tea House', NULL, 'Breakfast and Dinner', '<p>After an early breakfast, take a scenic flight from Kathmandu to Lukla, offering stunning views of the Himalayas. Upon arrival in Lukla, begin your trek toward Phakding, a charming village along the Dudh Koshi River. The trail passes through rhododendron forests, suspension bridges, and small villages, giving you your first taste of Sherpa culture. Overnight stay in Phakding.</p>', 2, '2026-03-07 21:54:15', '2026-03-07 21:56:51'),
(3441, 294, '3', NULL, 'Trek to Namche Bazaar (3,440m)', 'Tea House', NULL, 'B, L, & D', '<p>Today’s trek takes you along the Dudh Koshi River, gradually ascending through picturesque villages like Monjo and Jorsale. Cross famous suspension bridges and enjoy panoramic mountain views along the way. Arrive at Namche Bazaar, the bustling Sherpa hub of the Everest region. Evening at leisure to explore the market or relax.</p>', 3, '2026-03-07 21:54:15', '2026-03-07 21:56:51'),
(3442, 294, '4', NULL, 'Acclimatization Day in Namche Bazaar (3,440m)', 'Tea House', NULL, 'B, L, & D', '<p>A crucial day for altitude acclimatization. You can take short hikes to nearby viewpoints, such as Hotel Everest View or the Everest Viewpoint, to enjoy breathtaking panoramas of Everest, Lhotse, and Ama Dablam. This day helps your body adjust to higher altitudes, reducing the risk of altitude sickness. Optional visits include the Sherpa Cultural Museum.</p>', 4, '2026-03-07 21:54:15', '2026-03-07 21:56:51'),
(3443, 294, '5', NULL, 'Trek to Tengboche (3,860m)', 'Tea House', NULL, 'B, L, & D', '<p>Trek through beautiful forests and cross several suspension bridges as you ascend toward Tengboche, famous for its Tengboche Monastery, one of the largest monasteries in the Khumbu region. Enjoy spectacular views of Ama Dablam, Nuptse, Lhotse, and Everest from the monastery. Overnight stay in Tengboche with time to soak in the serene surroundings.</p>', 5, '2026-03-07 21:54:15', '2026-03-07 21:56:51'),
(3444, 294, '6', NULL, 'Trek to Dingboche (4,410m)', 'Tea House', NULL, 'B, L, & D', '<p>Continue trekking through the Imja Khola valley, passing by small villages and prayer wheels along the way. Arrive at Dingboche, a beautiful alpine village surrounded by towering peaks. The afternoon is perfect for light walks or visiting nearby chortens while preparing for the higher altitudes ahead.</p>', 6, '2026-03-07 21:54:16', '2026-03-07 21:56:51'),
(3445, 294, '7', NULL, 'Acclimatization Day in Dingboche (4,410m)', 'Tea House', NULL, 'B, L, & D', '<p>Another acclimatization day to help your body adjust before higher climbing. You can hike to Nangkar Tshang Hill for stunning views of Island Peak, Lhotse, and Ama Dablam. This hike strengthens your endurance and improves oxygen adaptation, essential for the Lobuche Peak summit attempt.</p>', 7, '2026-03-07 21:54:16', '2026-03-07 21:56:51'),
(3446, 294, '8', NULL, 'Trek to Lobuche (4,910m)', 'Tea House', NULL, 'B, L, & D', '<p>Trek past Chhukung and the Imja Glacier, gradually ascending to Lobuche village. The trail features dramatic mountain scenery, glacial moraines, and breathtaking vistas of the surrounding peaks. Overnight stay in Lobuche provides an opportunity to rest and prepare for the climb to high camp.</p>', 8, '2026-03-07 21:54:16', '2026-03-07 21:56:51'),
(3447, 294, '9', NULL, 'Trek to Lobuche High Camp (5,600m / 18,368 ft)', 'Tea House', NULL, 'B, L, & D', '<p>A short but steep trek today takes you to Lobuche High Camp, the base for your summit attempt. Along the way, you’ll traverse rocky paths and moraine fields. This is an ideal time to review climbing techniques, check your gear, and acclimatize further. Enjoy the spectacular sunrise or sunset views from high camp.</p>', 9, '2026-03-07 21:54:16', '2026-03-07 21:56:51'),
(3448, 294, '10', NULL, 'Summit Lobuche Peak (6,119m) and Return to Thukla', 'Tea House', NULL, 'B, L, & D', '<p>The most challenging and rewarding day! Begin the summit climb in the early hours, guided by experienced Sherpas. The climb involves rock and snow sections, requiring careful navigation. Upon reaching the summit of Lobuche Peak, take in the breathtaking 360-degree Himalayan panorama, including views of Everest, Nuptse, Lhotse, and Ama Dablam. Descend carefully to Thukla for overnight rest.</p>', 10, '2026-03-07 21:54:16', '2026-03-07 21:56:51'),
(3449, 294, '11', NULL, 'Trek to Namche Bazaar (3,440m)', 'Tea House', NULL, 'B, L, & D', '<p>Retrace your steps through Dingboche and Tengboche back to Namche Bazaar. Enjoy the changing scenery and reflect on the summit achievement while interacting with local Sherpa communities. Evening at leisure in Namche.</p>', 11, '2026-03-07 21:54:16', '2026-03-07 21:56:52'),
(3450, 294, '12', NULL, 'Trek from Namche Bazaar to Lukla (2,800m / 9,186 ft)', 'Tea House', NULL, 'B, L, & D', '<p>The final day of trekking takes you back to Lukla. Cross the Dudh Koshi River and pass through familiar villages, enjoying the last views of the towering Himalayan peaks. Overnight stay in Lukla.</p>', 12, '2026-03-07 21:54:16', '2026-03-07 21:56:52'),
(3451, 294, '13', NULL, 'Flight to Kathmandu (1,350m) & Transfer to Hotel', '4 Star Hotel', NULL, 'Breakfast', '<p>Take an early morning flight back to Kathmandu. Transfer to your hotel and spend the afternoon relaxing, shopping for souvenirs, or exploring Kathmandu’s vibrant streets. Evening free for leisure or cultural experiences.</p>', 13, '2026-03-07 21:54:16', '2026-03-07 21:56:52'),
(3452, 294, '14', NULL, 'Transfer to Tribhuvan International Airport', NULL, NULL, NULL, '<p>After breakfast, you will be transferred to Tribhuvan International Airport for your onward journey. Depart with unforgettable memories of the Everest region and the proud achievement of summiting Lobuche Peak.</p>', 14, '2026-03-07 21:54:16', '2026-03-07 21:56:52'),
(3453, 295, '1', NULL, 'Arrival in Kathmandu (1,400m) & Transfer to Hotel', '4 Star Hotel', NULL, 'Welcome Dinner', '<p>Upon arrival at Tribhuvan International Airport in Kathmandu, you will be warmly welcomed by your expedition team. Transfer to your hotel in the heart of Kathmandu and settle in after your journey. Take the evening to rest, recover from travel, and enjoy the vibrant city surroundings. The day concludes with a welcome meeting where you are introduced to your guides and Sherpa team, receive your first briefing, and review the itinerary ahead. This is your first opportunity to immerse yourself in Nepal’s rich culture while preparing for the adventure to come.</p>', 1, '2026-03-08 20:41:27', '2026-03-08 20:45:24'),
(3454, 295, '2', NULL, 'Rest in Kathmandu – Expedition Briefing and Preparation', '4 Star Hotel', NULL, 'Breakfast', '<p>Spend a full day in Kathmandu acclimatizing to the local environment. Attend a comprehensive expedition briefing where your guides explain the Makalu route, climbing schedule, high-altitude safety measures, and technical requirements. Equipment checks, personal gear adjustments, and tips on high-altitude trekking will be conducted. You can also explore Kathmandu’s cultural landmarks or enjoy local cuisine while mentally preparing for the challenging expedition ahead.</p>', 2, '2026-03-08 20:41:27', '2026-03-08 20:45:24');
INSERT INTO `cl_trip_itinerary` (`id`, `trip_detail_id`, `days`, `meals`, `title`, `max_altitude`, `distance`, `duration`, `content`, `ordering`, `created_at`, `updated_at`) VALUES
(3455, 295, '3', NULL, 'Fly from Kathmandu to Tumlingtar and Drive to Num (1,560m)', 'Tea House', NULL, 'B, L, & D', '<p>Take an early morning scenic flight from Kathmandu to Tumlingtar, a small airport in eastern Nepal serving as the gateway to the Makalu region. From Tumlingtar, embark on a drive through rolling hills and rural villages, arriving at Num, your first stop in the mountains. Num offers a glimpse of traditional Nepalese village life, surrounded by terraced fields and forested slopes. This day is ideal for light walking and stretching after the flight.</p>', 3, '2026-03-08 20:41:27', '2026-03-08 20:45:24'),
(3456, 295, '4', NULL, 'Trek from Num to Seduwa (1,510m)', 'Tea House', NULL, 'B, L, & D', '<p>Begin your trek along the well-marked trails that follow rivers and pass through dense forests and small villages. The trail gradually ascends, giving your body time to adjust to the higher altitude. Along the way, enjoy views of distant Himalayan peaks and interact with locals going about their daily routines. Seduwa, a picturesque village nestled in the hills, provides a comfortable lodge for the night.</p>', 4, '2026-03-08 20:41:27', '2026-03-08 20:45:24'),
(3457, 295, '5', NULL, 'Trek from Seduwa to Tashi Gaun (2,070m)', 'Tea House', NULL, 'B, L, & D', '<p>Today’s trek introduces slightly steeper climbs through rhododendron forests and terraced farmland. The trail passes small, traditional villages where you may witness local customs and lifestyles. Tashi Gaun, your destination for the night, is an excellent place for acclimatization before higher altitudes.</p>', 5, '2026-03-08 20:41:27', '2026-03-08 20:45:24'),
(3458, 295, '6', NULL, 'Acclimatization at Tashi Gaun (Rest Day)', 'Tea House', NULL, 'B, L, & D', '<p>Take a rest day at Tashi Gaun to acclimatize. Gentle hikes around the village allow your body to adapt to the increasing altitude, while the surrounding forests and ridges provide breathtaking views of distant snow-capped peaks. Guides provide instruction on high-altitude trekking techniques and safety measures for the days ahead.</p>', 6, '2026-03-08 20:41:27', '2026-03-08 20:45:24'),
(3459, 295, '7', NULL, 'Trek from Tashi Gaun to Khongma (3,760m)', 'Tea House', NULL, 'B, L, & D', '<p>A longer and more challenging trekking day through alpine terrain, forests, and river valleys. The landscape becomes more rugged as you ascend, with panoramic views of Makalu and nearby peaks emerging. Khongma is a high-altitude village where you spend the night in a lodge, preparing for the move toward the Base Camp.</p>', 7, '2026-03-08 20:41:28', '2026-03-08 20:45:24'),
(3460, 295, '8', NULL, 'Trek from Khongma to Dobato (4,010m) – Begin Camping', 'Camp', NULL, 'B, L, & D', '<p>Trek through high-altitude valleys and glacial streams to reach Dobato. This marks the start of camping accommodations, bringing you closer to the wilderness and the mountains. The environment becomes stark and dramatic, with sparse vegetation and a sense of isolation. Your guides help set up camp, ensuring tents are secure and supplies are organized.</p>', 8, '2026-03-08 20:41:28', '2026-03-08 20:45:24'),
(3461, 295, '9', NULL, 'Trek from Dobato to Yangle Kharka (3,640m)', 'Camp', NULL, 'B, L, & D', '<p>Continue trekking along the rugged terrain of the Makalu region. Yangle Kharka is a picturesque campsite surrounded by alpine meadows and glacial streams. The trek involves navigating steep sections, small ridges, and open valleys, offering spectacular views of Makalu’s massive ridges.</p>', 9, '2026-03-08 20:41:28', '2026-03-08 20:45:24'),
(3462, 295, '10', NULL, 'Trek from Yangle Kharka to Langmale Kharka (4,450m)', 'Camp', NULL, 'B, L, & D', '<p>Ascend into higher alpine landscapes with breathtaking panoramas of surrounding peaks. Langmale Kharka is an expansive campsite, perfect for resting before reaching Lower Base Camp. This day helps your body adapt to higher altitudes and prepares you for the serious climbing ahead.</p>', 10, '2026-03-08 20:41:28', '2026-03-08 20:45:24'),
(3463, 295, '11', NULL, '1Trek to Makalu Lower Base Camp (4,850m) – Acclimatization', 'Camp', NULL, 'B, L, & D', '<p>Arrive at Lower Base Camp, the staging point for all summit attempts. Spend the day acclimatizing, organizing gear, and scouting the surrounding glaciers. The sheer size and scale of Makalu become apparent here, and climbers can enjoy close-up views of its impressive ridges and technical faces.</p>', 11, '2026-03-08 20:41:28', '2026-03-08 20:45:24'),
(3464, 295, '12 to 13', NULL, 'Acclimatization at Lower Base Camp (Rest Days)', 'Camp', NULL, 'B, L, & D', '<p>Rest and acclimatize with optional short hikes to nearby ridges or glaciers. These days are crucial for preparing your body for higher camps and the summit attempt. Guides review climbing techniques, rope work, and high-altitude safety drills.</p>', 12, '2026-03-08 20:41:28', '2026-03-08 20:45:25'),
(3465, 295, '14', NULL, 'Hike from Lower Base Camp to Higher (Main) Base Camp (5,600m)', 'Camp', NULL, 'B, L, & D', '<p>Move to Main Base Camp at 5,600m. The climb involves navigating moraines and small glaciers, giving climbers their first exposure to high-altitude technical terrain. The camp offers stunning views of Makalu’s upper ridges and the surrounding high Himalayan peaks.</p>', 13, '2026-03-08 20:41:28', '2026-03-08 20:45:25'),
(3466, 295, '15 to 30', NULL, 'High Camp Rotations', 'Camp', NULL, 'B, L, & D', '<p>Over the next two weeks, climbers rotate between Base Camp and higher camps (Camp I, II, III) to gradually acclimatize. Each rotation includes carrying loads, practicing rope and ice techniques, and sleeping at progressively higher altitudes. These rotations are essential for building strength, endurance, and confidence before the summit push.</p>', 14, '2026-03-08 20:41:28', '2026-03-08 20:45:25'),
(3467, 295, '31 to 42', NULL, 'Summit Climbing Period', 'Camp', NULL, 'B, L, & D', '<p>The final summit attempt involves moving from Base Camp to Makalu’s summit (8,485m) and returning safely. Climbers navigate glaciers, ice walls, and steep ridges, facing extreme conditions that demand technical skill, careful planning, and mental resilience. Success at the summit offers unparalleled views and a life-changing achievement.</p>', 15, '2026-03-08 20:41:28', '2026-03-08 20:45:25'),
(3468, 295, '43', NULL, 'Cleaning Up Base Camp', 'Camp', NULL, 'B, L, & D', '<p>After the summit push, the team organizes and cleans Base Camp, packing gear and ensuring the environment is left pristine. Rest and recover after the intense climbing period.</p>', 16, '2026-03-08 20:41:28', '2026-03-08 20:45:25'),
(3469, 295, '44 to 47', NULL, 'Trek Back to Seduwa and Num', 'Tea House', NULL, 'B, L, & D', '<p>Begin your descent retracing the route through Langmale Kharka, Yangle Kharka, Dobato, Khongma, and Tashi Gaun. Overnight stays are in lodges along the trail, giving climbers time to reflect on their achievement and enjoy the mountains one last time.</p>', 17, '2026-03-08 20:41:28', '2026-03-08 20:45:25'),
(3470, 295, '48', NULL, 'Drive from Khandbari to Tumlingtar – Fly to Kathmandu', '4 Star Hotel', NULL, 'Breakfast', '<p>Drive to Tumlingtar and take a flight back to Kathmandu. Upon arrival, transfer to your hotel for a relaxing evening, celebrating the completion of the expedition.</p>', 18, '2026-03-08 20:41:28', '2026-03-08 20:45:25'),
(3471, 295, '49', NULL, 'Leisure Day in Kathmandu', '4 Star Hotel', NULL, 'Breakfast', '<p>Spend the day exploring Kathmandu, visiting temples, markets, or relaxing at the hotel. This day is ideal for recovery, shopping, and experiencing the vibrant culture of Nepal’s capital.</p>', 19, '2026-03-08 20:41:28', '2026-03-08 20:45:25'),
(3472, 295, '50', NULL, 'Departure', 'Hotel', NULL, 'Breakfast', '<p>Transfer to Tribhuvan International Airport for your onward flight. Depart with memories of a challenging and unforgettable Himalayan expedition, having experienced the grandeur of Makalu and the remote beauty of eastern Nepal.</p>', 20, '2026-03-08 20:41:28', '2026-03-08 20:45:25'),
(3474, 296, '2', NULL, 'Flight from Kathmandu to Lukla and Trek to Paiya', 'Tea House', NULL, 'Breakfast', '<p>Early in the morning you will have the flight to the Lukla which is the gateway to the Everest expeditions and the EBC trek itself along with the other trekking regions. Upon reaching Lukla you will Get your local permits and hike to the Paiya. A beautiful village in the Khumbu region which is known for its terraced fields and Rhododendron forest.</p>', 2, '2026-03-08 21:22:12', '2026-03-08 21:25:20'),
(3475, 296, '3', NULL, 'Walk from Paiya to Panggom', 'Tea House', NULL, 'B, L, & D', '<p>Upon having your heart breakfast in your tea house our guide will give you brief of the day. After the brief you will travel to the Panggom which is another village that takes you to your destination. You will walk via lush forests of pine and rhododendron. Cross several suspension bridges and small streams along the way. When you reach the village, you will see that the settlements reflect with the beautiful majestic mountains at the background.</p>', 3, '2026-03-08 21:22:12', '2026-03-08 21:25:20'),
(3476, 296, '4', NULL, 'Panggom to Ningsow', 'Tea House', NULL, 'B, L, & D', '<p>Ningsow is another beautiful Sherpa village located inside the Solu Khumbu region known for its terraced farm lands along with the scenic forest paths and the beautiful mountain views. On the way you will interact with the locals and learn about their day to life in the mountains and their culture and traditions.</p>', 4, '2026-03-08 21:22:12', '2026-03-08 21:25:20'),
(3477, 296, '5', NULL, 'Ningsow to Chhatra Khola', 'Tea House', NULL, 'B, L, & D', '<p>Early in the morning you will head towards the next destination which is the Chhatra Khola a village located on the river bank of the Chhatra. It is a glacier river coming from the melting glacier of the mountains. As you walk you will feel the surrounding is covered by the rugged mountains and terraced fields. You will also cross the small river which is used for the agriculture in the mountains.</p>', 5, '2026-03-08 21:22:12', '2026-03-08 21:25:21'),
(3478, 296, '6', NULL, 'Chhatra Khola to Kothe', 'Tea House', NULL, 'B, L, & D', '<p>You will walk to the Kothe village which is a gateway to the Mera peak. The walk from the village to your destination will be challenging due to the higher altitudes. As you climb the altitude you will see that the lush green village is vanished and the surrounding is replaced by the shrubs and the rocky landscapes. Also, you will witness the dramatic landscapes at the background.</p>', 6, '2026-03-08 21:22:12', '2026-03-08 21:25:21'),
(3482, 296, '10', NULL, 'Khare to Mera High Camp', 'Camp', NULL, 'B, L, & D', '<p>After acclimating yourself in the Khare you will hike to the Mera High Camp at an altitude of the 5,780m / 18,958ft above sea level. The air here is very thin and its important for you to acclimate before climbing the high camp. You will see the terrain is rocky and snow patches all over the camp. You will have the closet views of the Mera Peak, Mount Everest and the surrounding ranges. You will sleep early today as tomorrow morning you will be having summit to the top of the peak and the weather is unstable at such altitude we start our climbing from the morning 2 Am due to which its important for you to sleep early and have enough rest</p>', 10, '2026-03-08 21:22:12', '2026-03-08 21:25:21'),
(3483, 296, '11', NULL, 'Mera High Camp to Summit and Back to Khare', 'Camp', NULL, 'B, L, & D', '<p>As we discussed above we will be having the summit from the morning 1 to 2 Am. You need to be ready before this time so that we can summit as soon as possible. You will need to trek slowly cross the glaciers and use the crampons and axes properly. Upon reaching the top of the Mera peak at an altitude of the (6,476m / 21,247ft) you will see the unmatched views of the Everest, Kanchenjunga, and Makalu. Enjoy your moment of victory and descend slowly as the fatality happens more when you descend then climbing the peak.</p>', 11, '2026-03-08 21:22:12', '2026-03-08 21:25:21'),
(3490, 296, '15', NULL, 'Trek from Thuli Kharka to Lukla via Zatrwa La Pass', 'Tea House', NULL, 'B, L, & D', '<p>Today is one of the most scenic and adventurous days of the trek. After an early breakfast, you will ascend steadily toward Zatrwa La Pass. The climb is steep but rewarding, offering breathtaking panoramic views of Everest, Lhotse, Makalu, Cho Oyu, and other Himalayan giants. After spending some time at the pass for photos and rest, the trail descends steeply toward the Lukla valley. The descent passes through rocky paths, alpine meadows, and gradually re-enters forested terrain. As you approach Lukla, the trail becomes more lively, marking the end of your trekking journey. Celebrate the successful completion of your adventure with your trekking team in Lukla.</p>', 15, '2026-03-08 21:22:13', '2026-03-08 21:25:21'),
(3492, 296, '16', NULL, 'Flight from Lukla to Kathmandu', '4 Star Hotel', NULL, 'B, L, & D', '<p>Early in the morning, you will take a scenic flight back to Kathmandu. The short but spectacular flight offers stunning aerial views of the Himalayas and the hill landscapes of Nepal. Upon arrival in Kathmandu, you will be transferred to your hotel. The rest of the day is free for relaxation, souvenir shopping, or exploring the vibrant streets of Thamel.</p>', 16, '2026-03-08 21:22:13', '2026-03-08 21:25:21'),
(3497, 296, '9', NULL, 'Khare – Acclimatization and Pre-Climb Training', 'Camp', NULL, 'B, L, & D', '<p>You will have an acclimatization day before the summit as its important as well due to the high altitude of the peak and thin air of the region. You will have a short hike to the Mera La or nearby ridges, where you will practice the use of crampons, ice axes, and other mountaineering gears.</p>', 9, '2026-03-08 21:22:13', '2026-03-08 21:25:21'),
(3499, 296, '1', NULL, 'Arrival in Kathmandu Valley', '4 Star Hotel', NULL, 'Welcome Dinner', '<p>We welcome you to Kathmandu the capital city of Nepal and it is also known as the gateway to Nepal. Upon arrival one of our team mates will be waiting for you to welcome you at the airport arrival sections. Upon meeting drive to Thamel and rest for the day.</p>', 1, '2026-03-08 21:22:13', '2026-03-08 21:25:20'),
(3502, 296, '12', NULL, 'Reserve Day for Contingency', 'Camp', NULL, 'B, L, & D', '<p>Today will be the reserve day for any kinds of Contingency which means the bad weather, flight delays or the recovery from the summit climb. If in your case everything worked our fine you can still enjoy the day in the mountains and explore the nearby places with your climbing guide.</p>', 12, '2026-03-08 21:22:14', '2026-03-08 21:25:21'),
(3511, 296, '7', NULL, 'Kothe to Thaknak', 'Tea House', NULL, 'B, L, & D', '<p>You will walk from the Kothe to Thaknak a beautiful village in the higher altitude which is known for its beautiful views of the Cho Oyu and other surrounding peaks. It’s a small village located over the mountains which is used an ideal acclimatization place before heading to the Mera Peak.</p>', 7, '2026-03-08 21:22:14', '2026-03-08 21:25:21'),
(3512, 296, '8', NULL, 'Thaknak to Khare', 'Tea House', NULL, 'B, L, & D', '<p>Tea HouseFinally, after the 7th day of continuous walk, you will officially enter inside the Mera peak region. Khare is the main base camp for the Mera Peak climbing due to which the area is covered with the beautiful decorated tents and awesome views of the Mount Mera Baruntse and the other Himalayan ranges.</p>', 8, '2026-03-08 21:22:14', '2026-03-08 21:25:21'),
(3517, 296, '13', NULL, 'Khare to Kothe', 'Camp', NULL, 'B, L, & D', '<p>After summiting the peak, you will again need to descend down to the Kothe. As the trail will be known you may not face any kinds of difficulties and descend easily. You will via the same alpine meadows route and have the scenic photographs and local people interactions.</p>', 13, '2026-03-08 21:22:14', '2026-03-08 21:25:21'),
(3518, 296, '14', NULL, 'Trek from Kothe to Thuli Kharka', 'Camp', NULL, 'B, L, & D', '<p>After breakfast at Kothe, the trail begins with a gradual ascent following the Hinku Valley. You will walk through beautiful rhododendron and pine forests, crossing small streams and alpine pastures. As you gain altitude, the vegetation becomes thinner and the landscape opens into wide high-altitude terrain. The trail continues uphill toward the ridge area of Thuli Kharka, also known as Chatra La base. From here, you can enjoy spectacular views of Mera Peak, Kusum Kanguru, and surrounding Himalayan ranges. Thuli Kharka is a peaceful high camp and serves as the preparation point for the next day’s crossing of the Zatrwa La Pass.</p>', 14, '2026-03-08 21:22:14', '2026-03-08 21:25:21'),
(3521, 296, '17', NULL, 'Final Departure', NULL, NULL, NULL, '<p>Your adventure in Nepal comes to an end today. Depending on your flight schedule, you will be transferred to Tribhuvan International Airport for your final departure. We hope you leave Nepal with unforgettable memories of the Himalayas and wonderful trekking experiences. We look forward to welcoming you again for another adventure.</p>', 17, '2026-03-08 21:26:04', '2026-03-08 21:38:53'),
(3522, 297, '1', NULL, 'Arrival in Kathmandu (1,300 m / 4,264 ft.)', NULL, NULL, 'Welcome Dinner', '<p>Arrive at Tribhuvan International Airport in Kathmandu, where our team will receive you and transfer you to your hotel. After settling in, there will be a brief discussion about the expedition, including the route, schedule, safety protocols, and what to expect in the coming days. This session ensures all climbers are prepared and informed before the adventure begins.</p>', 1, '2026-03-09 03:10:14', '2026-03-09 21:24:02'),
(3523, 297, '2', NULL, 'Sightseeing in Kathmandu', NULL, NULL, 'Breakfast', '<p>Spend the day exploring the rich cultural heritage of Kathmandu. Visit iconic sites such as Swayambhunath Stupa, Boudhanath Stupa, Pashupatinath Temple, and the historic Durbar Square. This is also a chance to purchase any last-minute gear and experience the local culture, cuisine, and traditions.</p>', 2, '2026-03-09 03:10:14', '2026-03-09 21:24:02'),
(3524, 297, '3', NULL, 'Paperwork and Preparations', NULL, NULL, 'Breakfast', '<p>Dedicate this day to completing all necessary permits, paperwork, and final expedition arrangements. Guides will review the climbing plan, medical requirements, and logistics, ensuring that everything is in order for a smooth journey to Tibet. This day also allows for rest and final packing.</p>', 3, '2026-03-09 03:10:14', '2026-03-09 21:24:02'),
(3525, 297, '4', NULL, 'Drive to Zangmu (2,350 m / 7,710 ft.)', NULL, NULL, 'B, L, & D', '<p>Begin the overland journey to the Tibet border town of Zangmu. The drive offers stunning views of the Himalayan foothills, rivers, and Tibetan landscapes. This day is primarily for travel and acclimatization, helping the body adjust to increasing altitudes.</p>', 4, '2026-03-09 03:10:14', '2026-03-09 21:24:02'),
(3526, 297, '5', NULL, 'Drive to Nyalam (3,750 m / 12,303 ft.)', NULL, NULL, 'B, L, & D', '<p>Continue the journey deeper into Tibet, arriving at Nyalam. The town is known for its Tibetan culture and stunning mountain vistas. Overnight at a local hotel provides an opportunity to rest and further acclimatize.</p>', 5, '2026-03-09 03:10:14', '2026-03-09 21:24:02'),
(3527, 297, '6', NULL, 'Drive to Tingri (4,349 m / 14,268 ft.)', NULL, NULL, 'B, L, & D', '<p>Drive to Tingri, a small Tibetan settlement that serves as a gateway to Everest. The route offers panoramic views of the Himalayas, including glimpses of Everest and Cho Oyu. Tingri’s high-altitude environment prepares climbers for the upcoming ascent.</p>', 6, '2026-03-09 03:19:04', '2026-03-09 21:24:02'),
(3528, 297, '7', NULL, 'Acclimatization Day at Tingri', NULL, NULL, 'B, L, & D', '<p>Spend the day acclimatizing with light walks and rest. This is crucial for preventing altitude sickness. Guides may organize short hikes to help climbers adapt to higher elevations while enjoying breathtaking views of the surrounding mountains.</p>', 7, '2026-03-09 03:19:04', '2026-03-09 21:24:02'),
(3529, 297, '8', NULL, 'Drive to Everest Base Camp (5,200 m / 17,060 ft.)', NULL, NULL, 'B, L, & D', '<p>Drive along the Tibetan plateau to the Everest North Base Camp. This is the official starting point of the climb. Settle into camp, familiarize yourself with the facilities, and begin preparing gear for the climbing phase.</p>', 8, '2026-03-09 03:19:04', '2026-03-09 21:24:02'),
(3530, 297, '9 to 10', NULL, 'At Tibet Base Camp (5,200 m / 17,060 ft.)', NULL, NULL, 'B, L, & D', '<p>Spend these days at Base Camp for acclimatization and orientation. Activities include light hikes, gear checks, and team briefings. This period allows climbers to adjust to the high altitude, essential for a safe and successful ascent.</p>', 9, '2026-03-09 03:19:04', '2026-03-09 21:24:02'),
(3531, 297, '11 to 12', NULL, 'Rest and Preparation at Base Camp', NULL, NULL, 'B, L, & D', '<p>Optional buffer days for rest, weather adjustment, and further acclimatization before moving to higher camps.</p>', 10, '2026-03-09 03:19:04', '2026-03-09 21:24:02'),
(3532, 297, '13', NULL, 'Move to Intermediate Camp (6,200 m / 20,341 ft.)', NULL, NULL, 'B, L, & D', '<p>Climb to the Intermediate Camp, where climbers experience steeper terrain and higher altitudes. Focus on maintaining proper acclimatization, hydration, and energy levels. This stage is critical for preparing the body for the challenges ahead.</p>', 11, '2026-03-09 03:19:04', '2026-03-09 21:24:02'),
(3533, 297, '14', NULL, 'Move to Advanced Base Camp (6,500 m / 21,325 ft.)', NULL, NULL, 'B, L, & D', '<p>Advance to the next camp, which serves as the staging point for the final summit push. Spend time resting, organizing equipment, and preparing mentally and physically for the long climbing period ahead.</p>', 12, '2026-03-09 03:19:04', '2026-03-09 21:24:02'),
(3534, 297, '15 to 53', NULL, 'Climbing Period', NULL, NULL, 'B, L, & D', '<p>This phase involves multiple rotations between higher camps, acclimatization climbs, and ultimately the summit attempt. The climbing period is flexible depending on weather, acclimatization, and individual progress. Guides closely monitor all climbers for safety during the technical ascent.</p>', 13, '2026-03-09 03:19:04', '2026-03-09 21:24:03'),
(3535, 297, '54', NULL, 'Return to Advanced Base Camp (6,500 m / 21,325 ft.)', NULL, NULL, 'B, L, & D', '<p>After completing the summit attempt, descend to the Advanced Base Camp for rest and recovery. This stage allows climbers to relax, celebrate achievements, and prepare for further descent.</p>', 14, '2026-03-09 03:19:04', '2026-03-09 21:24:03'),
(3536, 297, '55', NULL, 'Return to Base Camp (5,200 m / 17,060 ft.)', NULL, NULL, 'B, L, & D', '<p>Descend to Base Camp, where climbers can enjoy the final moments of the high-altitude environment and organize gear for the journey back to lower elevations.</p>', 15, '2026-03-09 03:19:04', '2026-03-09 21:24:03'),
(3537, 297, '56', NULL, 'Cleaning Base Camp', NULL, NULL, 'B, L, & D', '<p>Participate in environmental conservation by cleaning and packing up Base Camp. This ensures that the area remains pristine and contributes to responsible mountaineering practices.</p>', 16, '2026-03-09 03:19:04', '2026-03-09 21:24:03'),
(3538, 297, '57', NULL, 'Drive to Nyalam and Stay at Hotel', NULL, NULL, 'B, L, & D', '<p>Begin the return journey to Nyalam, enjoy a comfortable stay at a local hotel, and rest after the long climb. This also allows climbers to reflect on the expedition and enjoy Tibetan culture one last time.</p>', 17, '2026-03-09 03:19:04', '2026-03-09 21:24:03'),
(3539, 297, '58', NULL, 'Drive to Kathmandu and Transfer to Hotel', NULL, NULL, 'Breakfast', '<p>Return to Kathmandu by road, completing the overland journey from Tibet. Transfer to your hotel for rest, relaxation, and a warm shower after the long expedition.</p>', 18, '2026-03-09 03:19:04', '2026-03-09 21:24:03'),
(3540, 297, '59', NULL, 'Stay in Kathmandu', NULL, NULL, 'Breakfast', '<p>Enjoy a free day in Kathmandu to relax, shop for souvenirs, or explore any sites missed at the beginning of the trip. This day serves as a decompression period after the high-altitude expedition.</p>', 19, '2026-03-09 03:19:04', '2026-03-09 21:24:03'),
(3541, 297, '60', NULL, 'Final Departure', NULL, NULL, NULL, '<p>Transfer to Tribhuvan International Airport for your onward flight. Depart with memories of an unforgettable adventure, having experienced the challenges and triumphs of climbing Everest via the North Face in Tibet.</p>', 20, '2026-03-09 03:19:04', '2026-03-09 03:21:19'),
(3545, 299, '1', NULL, 'Arrival in Kathmandu Valley (1,354 m)', '1400', '4 Star Hotel', 'Welcome Dinner', '<div><span>Namaste and welcome to Kathmandu, the land of the mountains. One of our teammates from the summit 8000 will be waiting for you to receive you at the airport. After the meeting, you will drive to Thamel at the 4-star hotel, where you can relax or explore the vibrant streets on the same day. In the evening, we will meet for the welcome dinner, where we will get to know each other and talk about the upcoming climbing days.</span></div>', 1, '2026-03-09 22:02:20', '2026-04-03 15:16:43'),
(3546, 299, '2', NULL, 'Drive from Kathmandu to Jagat (1,300 m)', '1400', '4 Star Hotel', 'B, L, & D', '<div><span>After the early morning breakfast, you will drive to Jagat, which will be the starting point for our journey. The distance between these two destinations is around 205 kilo meters, which is roughly around 155 miles. </span><span>You will drive through Nepal’s countryside along the Budhi Gandaki River. The route passes terraced hills, small villages, and beautiful mountain landscapes. By late afternoon, you will reach Jagat, the gateway village of the Manaslu region.</span></div>\r\n<div></div>', 2, '2026-03-09 22:02:20', '2026-04-03 15:20:16'),
(3547, 299, '3', NULL, 'Trek from Jagat to Nyak', '2300', 'Tea House', 'B, L, & D', '<p>Begin trekking along the Budhi Gandaki valley through narrow gorges and traditional settlements. The trail includes suspension bridges, terraced fields, and peaceful forests. Gradually gaining altitude, you will arrive at the quiet village of Nyak.</p>', 3, '2026-03-10 02:14:39', '2026-03-10 02:16:51'),
(3548, 299, '4', NULL, 'Trek from Nyak to Namrung', '2,659', 'Tea House', 'B, L, & D', '<p>Today’s trek continues through forests, rocky trails, and Buddhist mani walls. You will pass charming villages that reflect Gurung and Tibetan culture. The views of surrounding peaks become more impressive as you approach Namrung. Overnight stay in a lodge.</p>', 4, '2026-03-10 02:14:39', '2026-03-10 02:16:51'),
(3549, 299, '5', NULL, 'Trek from Namrung to Syalla', '3520', 'Tea House', 'B, L, & D', '<p>The trail climbs steadily through rhododendron and pine forests. Along the way, enjoy stunning panoramic views of Mt. Manaslu and nearby Himalayan peaks. Syalla is a beautiful high village surrounded by dramatic mountain scenery. Overnight stay in a lodge.</p>', 5, '2026-03-10 02:14:39', '2026-03-10 02:16:51'),
(3550, 299, '6', NULL, 'Trek from Syalla to Sama Gaun', '3530', 'Tea House', 'B, L, & D', '<p>A shorter and easier trek brings you to Sama Gaun, the main village of the Manaslu region. This Tibetan-influenced settlement is an important acclimatization point before heading higher. You can explore the village, monasteries, and local lifestyle.</p>', 6, '2026-03-10 02:14:39', '2026-03-10 02:16:51'),
(3551, 299, '7', NULL, 'Trek from Sama Gaun to Manaslu Base Camp', '4700', 'Tea House', 'B, L, & D', '<p>Today you climb towards Manaslu Base Camp through rocky terrain and glacial landscapes. The trail is steep but rewarding with close-up mountain views. Upon arrival, the expedition camp will be set up for rest and preparation.</p>', 7, '2026-03-10 02:14:39', '2026-03-10 02:16:51'),
(3552, 299, '8 to 22', NULL, 'Acclimatization & Rotation Phase', '4700', 'Tea House', 'B, L, & D', '<p>These days are dedicated to proper acclimatization and training for the summit. Climbers make rotation climbs to Camp I, Camp II, and touch Camp III before returning to Base Camp. Technical skills, rope work, and glacier practice are completed during this period. Rest and recovery are equally important for summit success.</p>', 8, '2026-03-10 02:14:39', '2026-03-10 02:16:51'),
(3553, 299, '23 to 29', NULL, 'Summit Push – Mt. Manaslu', '8163', 'Tea House', 'B, L, & D', '<p>The summit phase begins depending on weather and mountain conditions. The team climbs gradually through higher camps before attempting the final ascent to the summit of Manaslu. Summit day is challenging but offers unforgettable Himalayan views. After the attempt, climbers safely descend back to Base Camp. If you want you can also cross the Larke La Pass at an altitutde of 5106 meters which is the main route for the<span style=\"color: #236fa1;\"> <a href=\"/trip/manaslu-circuit-trek\" target=\"_blank\" rel=\"noopener\" style=\"color: #236fa1;\">Manaslu circuit trekking in Nepal.</a></span></p>', 9, '2026-03-10 02:14:39', '2026-03-27 01:29:44'),
(3554, 299, '30', NULL, 'Descent from Base Camp to Sama Gaun (3,541 m)', '3540', 'Tea House', 'B, L, & D', '<p>After completing the expedition, you descend back to Sama Gaun. The return trek feels easier as you move to lower altitude. Overnight stay in a lodge with time to relax and celebrate. Meals included.</p>', 10, '2026-03-10 02:14:39', '2026-03-10 02:16:51'),
(3555, 299, '31 to 33', NULL, 'Larkya La Pass Trek to Bhimtang', '5160', 'Tea House', 'B, L, & D', '<p>This section takes you across the famous Larkya La Pass, one of the highest and most scenic passes in Nepal. The climb is demanding but rewards you with breathtaking views of glaciers and snow-covered peaks. After crossing the pass, you descend to the beautiful valley of Bhimtang. Overnight stays will be in lodges.</p>', 11, '2026-03-10 02:14:39', '2026-03-10 02:16:51'),
(3556, 299, '34', NULL, 'Bhimtang to Dharapani – Drive Back to Kathmandu', '1400', 'Tea House', 'Breakfast', '<p>Trek down through forests and river valleys to reach Dharapani. From here, you drive back to Kathmandu by private vehicle. In the evening, enjoy a farewell dinner with your team. Overnight stay in a hotel.</p>', 12, '2026-03-10 02:14:39', '2026-03-10 02:16:51'),
(3557, 299, '35', NULL, 'Departure from Kathmandu', NULL, NULL, NULL, '<p>Today is your final day in Nepal. Our team will transfer you to the airport for your onward flight. You leave with unforgettable memories of the Manaslu expedition and Himalayan adventure. Meals as per your schedule.</p>', 13, '2026-03-10 02:14:39', '2026-03-10 02:16:51'),
(3558, 300, '1', NULL, 'Arrival in Kathmandu Valley', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Upon arrival at Tribhuvan International Airport, you will be warmly welcomed by our team and transferred to your hotel in Kathmandu. After check-in, you can rest from your journey or explore the nearby streets. Kathmandu is the cultural gateway to the Himalayas and offers a first glimpse into Nepal’s rich heritage. In the evening, our representative will brief you about the upcoming days.</p>', 1, '2026-03-10 02:56:26', '2026-03-10 03:00:51'),
(3559, 300, '2', NULL, 'Rest Day in Kathmandu – Expedition Briefing & Preparation', '1400', '4 Star Hotel', 'Breakfast', '<p>This day is dedicated to expedition preparation. You will attend a detailed Nuptse Peak expedition briefing covering route plans, safety procedures, acclimatization strategy, and summit logistics. Gear checks are conducted to ensure all technical equipment meets expedition standards. Necessary permits are finalized, and climbers may use free time for last-minute shopping or rest before heading to the mountains.</p>', 2, '2026-03-10 02:56:26', '2026-03-10 03:00:51'),
(3560, 300, '3', NULL, 'Fly from Kathmandu to Lukla & Trek to Phakding', '2800', 'Tea House', 'B, L, & D', '<p>An early morning scenic flight takes you to Lukla, the gateway to the Everest region. After landing, the trek begins through traditional Sherpa villages, prayer wheels, and mani stones. The trail gently descends along the Dudh Koshi River to Phakding, allowing your body to begin adapting to altitude.</p>', 3, '2026-03-10 02:56:26', '2026-03-10 03:00:51'),
(3561, 300, '4', NULL, 'Trek from Phakding to Namche Bazaar', '3440', 'Tea House', 'B, L, & D', '<p>Today’s trek includes several suspension bridges and a gradual ascent through pine forests. After entering Sagarmatha National Park, the trail climbs steeply to Namche Bazaar, the commercial hub of the Khumbu region. Weather permitting, you’ll catch your first views of Everest and surrounding peaks.</p>', 4, '2026-03-10 02:56:26', '2026-03-10 03:00:51'),
(3562, 300, '5', NULL, 'Acclimatization Day at Namche Bazaar', '3440', 'Tea House', 'B, L, & D', '<p>Proper acclimatization is crucial for the Nuptse climb. A short hike to Everest View Hotel or nearby ridges helps your body adjust to altitude. The rest of the day is spent relaxing, hydrating, and exploring Namche’s bakeries, shops, and museums.</p>', 5, '2026-03-10 02:56:26', '2026-03-10 03:00:51'),
(3563, 300, '6', NULL, 'Trek from Namche Bazaar to Debuche', '3820', 'Tea House', 'B, L, & D', '<p>The trail contours along the valley with stunning views of Ama Dablam, Everest, and Lhotse. Passing through Tengboche Monastery, the spiritual heart of the Khumbu, the trek descends slightly to Debuche, offering a peaceful overnight stay surrounded by alpine forests.</p>', 6, '2026-03-10 02:56:27', '2026-03-10 03:00:51'),
(3564, 300, '7', NULL, 'Trek from Debuche to Dingboche', '4243', 'Tea House', 'B, L, & D', '<p>As you move higher, the landscape becomes more rugged and alpine. The trail crosses rivers and ascends steadily to Dingboche, a traditional Sherpa settlement with stone-walled fields. This village serves as an important acclimatization stop before heading toward Everest Base Camp.</p>', 7, '2026-03-10 02:56:27', '2026-03-10 03:00:51'),
(3565, 300, '8', NULL, 'Trek from Dingboche to Lobuche', '4930', 'Tea House', 'B, L, & D', '<p>The trek continues along glacial moraines with panoramic views of Nuptse Mountain dominating the skyline. Passing the memorials at Thukla dedicated to climbers who lost their lives in the Himalayas, you reach Lobuche, a small settlement close to the Khumbu Glacier.</p>', 8, '2026-03-10 02:56:27', '2026-03-10 03:00:51'),
(3566, 300, '9', NULL, 'Trek from Lobuche to Everest Base Camp', '5364', 'Tea House', 'B, L, & D', '<p>Today you reach Everest Base Camp, your home for the climbing phase. The trail follows the Khumbu Glacier, offering dramatic views of Nuptse, Everest, and Pumori. Upon arrival, the expedition team sets up camp, and climbers settle in for the upcoming high-altitude challenge.</p>', 9, '2026-03-10 02:56:27', '2026-03-10 03:00:51'),
(3567, 300, '10 to 39', NULL, 'Climbing Period – Nuptse Summit', '7861', 'Camp', 'B, L, & D', '<p>This extended period is reserved for acclimatization rotations, route fixing, and summit attempts. Climbers move between Base Camp and higher camps, gradually adapting to altitude. The Nuptse Peak climb involves steep ice walls, mixed terrain, and technical rope sections. Summit attempts are made only during optimal weather windows, following strict safety protocols. After a successful Nuptse Summit, climbers descend carefully back to Base Camp</p>', 10, '2026-03-10 02:56:27', '2026-03-10 03:00:51'),
(3568, 300, '40', NULL, 'Base Camp Cleanup', '5364', 'Camp', 'B, L, & D', '<p>In line with ethical climbing practices, this day is dedicated to cleaning Base Camp and surrounding areas. Waste is properly packed and prepared for removal, ensuring minimal environmental impact on the fragile Himalayan ecosystem.</p>', 11, '2026-03-10 02:56:27', '2026-03-10 03:00:51'),
(3569, 300, '41', NULL, 'Trek from Base Camp to Pheriche', '4371', 'Tea House', 'B, L, & D', '<p>Leaving Base Camp, the trek descends gradually to Pheriche, allowing your body to recover after weeks at extreme altitude. The lower elevation provides noticeable relief and improved energy levels.</p>', 12, '2026-03-10 02:56:27', '2026-03-10 03:00:51'),
(3570, 300, '42', NULL, 'Trek from Pheriche to Namche Bazaar', '3440', 'Tea House', 'B, L, & D', '<p>The return trek follows familiar trails back through Pangboche and Tengboche. Descending altitude, warmer temperatures, and greener landscapes mark the transition back to lower elevations.</p>', 13, '2026-03-10 02:56:27', '2026-03-10 03:00:51'),
(3571, 300, '43', NULL, 'Trek from Namche Bazaar to Lukla', '2860', 'Tea House', 'B, L, & D', '<p>Your final trekking day retraces the route to Lukla. In the evening, the team gathers for a farewell dinner to celebrate the successful Nuptse Adventure.</p>', 14, '2026-03-10 02:56:27', '2026-03-10 03:00:51'),
(3572, 300, '44', NULL, 'Fly from Lukla to Kathmandu & Transfer to Hotel', '1400', '4 Star Hotel', 'Breakfast', '<p>An early morning flight returns you to Kathmandu. After hotel check-in, the rest of the day is free to relax, shop, or enjoy the city.</p>', 15, '2026-03-10 02:56:27', '2026-03-10 03:00:51'),
(3573, 300, '45', NULL, 'Leisure Day in Kathmandu', NULL, '4 Star Hotel', 'Breakfast', '<p>This day is reserved for rest, sightseeing, or optional cultural tours around Kathmandu Valley. It also serves as a buffer day in case of flight delays from Lukla.</p>', 16, '2026-03-10 02:56:27', '2026-03-10 03:00:51'),
(3574, 300, '46', NULL, 'Final Departure', NULL, NULL, NULL, '<p>Our team will transfer you to the international airport for your onward journey, marking the end of your Nuptse Peak Expedition in Nepal 2026/2027.</p>', 17, '2026-03-10 02:56:27', '2026-03-10 03:00:51'),
(3575, 301, '1', NULL, 'Arrival in Kathmandu & Transfer to Hotel', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Upon arrival at Tribhuvan International Airport, Kathmandu, you will be welcomed by our team and transferred to your hotel. This day is for settling in, resting after your flight, and adjusting to the altitude. You can enjoy the comforts of your hotel and soak in the vibrant culture of Nepal’s capital. Breakfast will be provided at the hotel, and the evening is free to prepare for the adventure ahead.</p>', 1, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3576, 301, '2', NULL, 'Rest in Kathmandu, Expedition Briefing & Preparation', '1400', '4 Star Hotel', 'Breakfast', '<p>Today is dedicated to acclimatization and preparation for the expedition. You will attend a detailed briefing on Pumori Peak climbing, including safety protocols, gear checks, and route planning. This is also the perfect opportunity to finalize any last-minute equipment or supplies. Spend the rest of the day relaxing and enjoying the city’s atmosphere. Dinner will be served at the hotel.</p>', 2, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3577, 301, '3', NULL, 'Fly from Kathmandu to Lukla & Trek to Phakding', '2800', 'Tea House', 'B, L, & D', '<p>After an early breakfast, take a scenic flight to Lukla, the gateway to the Everest region. From Lukla, begin your trek along the Dudh Koshi River to Phakding, passing small villages and suspension bridges. The trail is dotted with traditional teahouses and prayer flags, providing a gentle introduction to Himalayan trekking. Overnight stay will be in a lodge with a warm meal to recover from the day’s journey.</p>', 3, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3578, 301, '4', NULL, 'Trek from Phakding to Namche Bazaar', '3440', 'Tea House', 'B, L, & D', '<p>The trek today gradually ascends through pine forests, Mani walls, and villages with local Sherpa culture. Cross famous suspension bridges and enjoy panoramic views of the mountains as you approach Namche Bazaar, the bustling Sherpa capital. This is an ideal spot to acclimatize and experience local markets, cafes, and trekking culture. Overnight will be at a comfortable lodge with breakfast, lunch, and dinner provided.</p>', 4, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3579, 301, '5', NULL, 'Acclimatization at Namche Bazaar (Rest Day))', '3440', 'Tea House', 'B, L, & D', '<p>Spend a rest day at Namche Bazaar to acclimatize to the higher altitude. You can explore the town, visit the Sherpa Culture Museum, or take a short hike to nearby viewpoints for stunning views of Everest and Ama Dablam. Gentle walks and light activity help your body adjust before ascending further. Meals will be provided at the lodge throughout the day.</p>', 5, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3580, 301, '6', NULL, 'Trek from Namche Bazaar to Tyangboche Monastery', '3860', 'Tea House', 'B, L, & D', '<p>The trek today offers spectacular views of Ama Dablam and the surrounding peaks. You will pass through forests of rhododendron and reach Tyangboche Monastery, one of the most revered monasteries in the Khumbu region. The area provides a serene environment and a great vantage point for photography. Overnight stay will be in a lodge with full board.</p>', 6, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3581, 301, '7', NULL, 'Trek from Tyangboche to Dingboche', '4243', 'Tea House', 'B, L, & D', '<p>Ascending further, you trek through open valleys and moraine landscapes to reach Dingboche, a high-altitude village nestled among towering peaks. The trail offers panoramic mountain vistas and opportunities to see yak caravans. Overnight stay will be in a lodge, allowing for proper rest and acclimatization before higher altitude trekking.</p>', 7, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3582, 301, '8', NULL, 'Trek from Dingboche to Lobuche', '4930', 'Tea House', 'B, L, & D', '<p>Today, the terrain becomes more rugged as you trek past glacial valleys and moraine hills to Lobuche, a small settlement used as a base for high-altitude climbs. The dramatic views of the surrounding peaks make this stretch both challenging and rewarding. Staying in a lodge here allows for gradual acclimatization before reaching the base camp.</p>', 8, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3583, 301, '9', NULL, 'Trek from Lobuche to Gorak Shep', '5140', 'Tea House', 'B, L, & D', '<p>The trail ascends gently through rocky terrain and glacial streams to Gorak Shep, the last settlement before Everest Base Camp. This area is famous for its panoramic views of Pumori, Kala Patthar, and surrounding Himalayan giants. The altitude here requires careful acclimatization and hydration. Overnight stay will be in a lodge, preparing for the approach to Pumori Base Camp.</p>', 9, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3584, 301, '10', NULL, 'Trek from Gorak Shep to Pumori Base Camp', '5220', 'Tea House', 'B, L, & D', '<p>From Gorak Shep, you begin the trek to Pumori Base Camp, entering a remote and rugged Himalayan landscape. The trail crosses moraines, ice fields, and dramatic ridges, providing an early taste of the challenges ahead. Setting up at base camp, you will prepare for the technical climb with your team. Overnight stay will be in tents with meals provided by the expedition team.</p>', 10, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3585, 301, '11 to 28', NULL, 'Climbing Period (Base Camp – Pumori Summit 7,145m – Base Camp)', '7145', 'Camp', 'B, L, & D', '<p>These days are dedicated to the Pumori peak climbing expedition, involving acclimatization rotations, establishing higher camps, and summit attempts. Climbers will navigate technical ice and snow slopes, fixed ropes, and challenging ridges under expert guidance. Each day balances climbing, rest, and safety to ensure successful acclimatization and summit preparation. Meals and overnight stays will be at base camp or higher camps in tents provided by the expedition.</p>', 11, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3586, 301, '29', NULL, 'Trek from Base Camp to Pangboche', '3930', 'Tea House', 'B, L, & D', '<p>After a successful climb, you descend to Pangboche, retracing your steps through high-altitude trails. The descent allows you to enjoy the changing scenery while recovering from the climb. Overnight stay will be in a lodge with full board.</p>', 12, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3587, 301, '30', NULL, 'Trek from Pangboche to Namche Bazaar', '3440', 'Tea House', 'B, L, & D', '<p>Continue descending through rhododendron forests and small villages to Namche Bazaar, where you can celebrate the completion of your summit climb. Overnight stay will be in a lodge, enjoying hot meals and comfort.</p>', 13, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3588, 301, '31', NULL, 'Trek from Namche Bazaar to Lukla', '2860', 'Tea House', 'B, L, & D', '<p>The trail gradually descends through picturesque villages and river valleys to Lukla, completing the trekking section of the expedition. This day is a mix of reflection and celebration as you approach the starting point of your journey. Overnight stay will be in a lodge.</p>', 14, '2026-03-10 03:23:08', '2026-03-10 03:25:26'),
(3589, 301, '32', NULL, 'Fly from Lukla to Kathmandu & Transfer to Hotel', '1400', '4 Star Hotel', '1400', '<p>Take a scenic flight back to Kathmandu, enjoying aerial views of the Himalayas and the Everest region. Upon arrival, you will be transferred to your hotel for rest and relaxation. This is a perfect day to recover from trekking and enjoy the comforts of the city. Breakfast will be provided at the hotel.</p>', 15, '2026-03-10 03:23:09', '2026-03-10 03:25:26'),
(3590, 301, '33', NULL, 'Leisure Day in Kathmandu City', '1400', '4 Star Hotel', 'Breakfast', '<p>Spend a free day exploring Kathmandu at your own pace. You can visit Boudhanath Stupa, Pashupatinath Temple, or shop for souvenirs at Thamel. This day allows for cultural immersion and relaxation after your long expedition. Overnight stay will be at the hotel with breakfast provided.</p>', 16, '2026-03-10 03:23:09', '2026-03-10 03:25:26'),
(3591, 301, '34', NULL, 'Transfer to International Airport for Departure', NULL, NULL, NULL, '<p>On the final day, you will be transferred to Tribhuvan International Airport for your departure flight. This marks the end of your unforgettable Pumori expedition, leaving you with lifelong memories of the Himalayas.</p>', 17, '2026-03-10 03:23:09', '2026-03-10 03:25:26'),
(3592, 302, '1', NULL, 'Arrival in Kathmandu Valley', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Namaste and we welcome you to the land of high passes and sherpas Nepal. You will be arriving at Tribhuvan International Airport where one of our team mates will welcome you with your name banner. Upon meeting me will drive to Thamel and rest.</p>', 1, '2026-03-10 03:49:44', '2026-03-10 19:15:20'),
(3593, 302, '2', NULL, 'Kathmandu to Nepalgunj (Flight)', '150', 'Lodge', 'Breakfast', '<p>Early in the morning, after the hearty breakfast we will drive to the Tribhuvan International Airport. After that you will take a flight from Kathmandu to Nepalgunj. The flight time will be of the 50 minutes. Upon reaching you will stay at the Nepalgunj and our guide will provide you all the permits and trekking gears lists and equipment which you can get from the trekking shops. You will have the brief day and visit around the places.</p>', 2, '2026-03-10 03:49:44', '2026-03-10 19:15:20'),
(3594, 302, '3', NULL, 'Nepalgunj to Jhupal (Flight) and Drive to Dunai', '200', 'Lodge', 'B, L, & D', '<p>Early in the morning you will have a scenic flight from Nepalgunj to Jhupal which will be followed by a picturesque drive to Dunai, nestled among terraced fields and forested hills. Here, meet your climbing team and review the trail itinerary, safety measures, and high-altitude protocols. Overnight stay in Dunai allows for rest and preparation before the trek begins.</p>', 3, '2026-03-10 03:49:44', '2026-03-10 19:15:20'),
(3595, 302, '4', NULL, 'Trek from Dunai to Tarakot', '2280', 'Tea House', 'B, L, & D', '<p>Today marks the beginning of our trekking journey into the remote Dolpo region. The trail follows the Thuli Bheri River northward, winding through pine and cedar forests with occasional glimpses of snow-capped peaks in the distance. The path alternates between riverside trails and sections that climb above the gorge, offering panoramic views of the surrounding valleys. You\'ll pass through small settlements where the local Dolpo-pa people maintain their traditional way of life, largely unchanged for centuries. Tarakot (2,537m) is a historic village with an ancient dzong (fort) overlooking the settlement. This strategic location once controlled trade routes between Tibet and the Indian subcontinent. The village exhibits distinctive Tibetan Buddhist architecture, with whitewashed houses and prayer flags adorning the landscape.</p>', 4, '2026-03-10 03:49:44', '2026-03-10 19:15:20');
INSERT INTO `cl_trip_itinerary` (`id`, `trip_detail_id`, `days`, `meals`, `title`, `max_altitude`, `distance`, `duration`, `content`, `ordering`, `created_at`, `updated_at`) VALUES
(3596, 302, '5', NULL, 'Trek from Tarakot to Mushi Khola', '2875', 'Tea House', 'B, L, & D', '<p>Departing Tarakot, the trail continues following the Barbung Khola upstream. The landscape becomes increasingly dramatic as we venture deeper into the Dolpo wilderness. The path climbs gradually through narrow gorges where the river has carved impressive formations into the rock. You\'ll traverse mixed terrain, including forested sections, open scrubland, and areas of exposed rock. The vegetation gradually becomes sparser as we gain elevation, reflecting the rain shadow effect of the Himalayan barrier. Mushi Khola (2,820m) is a small settlement beside a tributary stream. The area offers good camping facilities and serves as a strategic stopping point for expeditions heading toward the inner Dolpo region. The steady altitude gain continues your acclimatization process. You may begin to notice the effects of thinner air, making it important to maintain proper hydration and a comfortable pace.</p>', 5, '2026-03-10 03:49:44', '2026-03-10 19:15:20'),
(3597, 302, '6', NULL, 'Trek from Mushi Khola to Kagkot', '2875', 'Tea House', 'B, L, & D', '<p>Today\'s journey takes us deeper into the high mountain environment. The trail climbs more steeply now, ascending through alpine meadows that transform into high desert terrain characteristic of the trans-Himalayan region. The path crosses several streams and traverses hillsides where blue sheep (bharal) and Himalayan griffon vultures may be spotted. The vegetation becomes increasingly sparse, with hardy shrubs and grasses adapted to the harsh climate. Kagkot (3,500m) serves as a crucial acclimatization point in our itinerary. This remote location offers expansive views of the surrounding peaks and valleys. The settlement consists of traditional stone houses and seasonal herder shelters. The significant altitude gain today makes proper rest essential. Our team will monitor all members for signs of altitude-related issues, though the gradual ascent profile is designed to minimize such risks.</p>', 6, '2026-03-10 03:49:44', '2026-03-10 19:15:20'),
(3598, 302, '7', NULL, 'Acclimatization Day in Kagkot', '2875', 'Tea House', 'B, L, & D', '<p>This strategically planned rest day is essential for proper high-altitude adaptation. While termed a \"rest day,\" the schedule includes an active acclimatization hike to a higher elevation before returning to Kagkot for the night following the mountaineering principle of \"climb high, sleep low.\" Your guide will lead a 3-4 hour hike to approximately 4,000m, allowing your body to experience higher altitude while returning to sleep at lower elevation. This significantly improves oxygen saturation and reduces the risk of altitude-related illness</p>', 7, '2026-03-10 03:49:44', '2026-03-10 19:15:20'),
(3599, 302, '8', NULL, 'Trek from Kagkot to Panjing', '4000', 'Tea House', 'B, L, & D', '<p>After our acclimatization day, we continue ascending toward Panjing. The trail traverses high alpine terrain with increasingly spectacular mountain views. The landscape here is stark and beautiful, with minimal vegetation and dramatic rock formations. The route may cross seasonal streams and glacial moraines. As we approach Panjing, the massive presence of Putha Hiunchuli and surrounding peaks becomes more prominent on the horizon. Panjing (4,000m) is a high-altitude settlement that serves as the last inhabited area before entering the wild mountain zones. The village maintains yak pastures during summer months, and you may encounter herders tending their livestock.</p>', 8, '2026-03-10 19:15:20', '2026-03-10 19:18:18'),
(3606, 302, '9', NULL, 'Acclimatization Day in Panjing', '4000', 'Tea House', 'B, L, & D', '<p>Our second dedicated acclimatization day occurs at Panjing, positioned at 4,000m. This rest day is critical for proper physiological adaptation before proceeding to the base camp areas above 4,500m. Today\'s activities include an acclimatization rotation to approximately 4,500m, spending several hours at elevation before descending back to Panjing. This exposure stimulates red blood cell production and improves your body\'s oxygen-carrying capacity.</p>', 9, '2026-03-10 19:15:20', '2026-03-10 19:18:19'),
(3609, 302, '10', NULL, 'Trek from Panjing to German Base Camp', '4500', 'Tea House', 'B, L, & D', '<p>Today, we depart civilization and enter the high mountain wilderness. The trail climbs steadily toward German Base Camp, traversing glacial valleys and moraine fields. The term \"German Base Camp\" refers to a historical expedition site used by German mountaineering teams in earlier explorations of this region. The route follows ancient glacial valleys, crossing lateral moraines and boulder fields. Navigation becomes more challenging, and your experienced guides will lead the way through this terrain. The landscape is raw and magnificent, towering ice peaks, hanging glaciers, and vast expanses of rock and ice. German Base Camp (4,500m) sits in a strategic location that provides access to both Putha Hiunchuli and other surrounding peaks. The site offers some shelter from prevailing winds and access to water sources from nearby glacial streams</p>', 10, '2026-03-10 19:15:20', '2026-03-10 19:18:19'),
(3613, 302, '11', NULL, 'Trek from German Base Camp to Putha Hiunchuli Base Camp', '5200', 'Camp', 'B, L, & D', '<p>The final approach to Putha Hiunchuli Base Camp represents our transition from trekking to expedition mode. The route crosses complex glacial terrain, requiring careful navigation through crevasse zones and unstable moraine fields. Depending on seasonal conditions, the route may traverse snow-covered glaciers, requiring the use of crampons and roped team travel. Your guides will assess conditions and implement appropriate safety measures. Putha Hiunchuli Base Camp (5,200m) serves as our home for the coming weeks. The afternoon includes a puja ceremony (Buddhist blessing ritual) conducted by our Sherpa team. This sacred ceremony seeks blessings from the mountain deities for safe passage and successful climbing. All team members are welcome to participate in this meaningful cultural tradition.</p>', 11, '2026-03-10 19:15:20', '2026-03-10 19:18:19'),
(3618, 302, '12 to 28', NULL, 'Climbing Period', '7246', 'Camp', 'B, L, & D', '<p>The next seventeen days constitute the core climbing period for Putha Hiunchuli (7,246m). This timeframe allows for establishing high camps, acclimatization rotations, weather waiting, and the summit push. The exact schedule remains flexible based on weather patterns, snow conditions, and team performance.</p>', 12, '2026-03-10 19:15:20', '2026-03-10 19:18:19'),
(3623, 302, '29', NULL, 'Descend from Putha Hiunchuli Base Camp to Kagkot', '1700', 'Tea House', 'B, L, & D', '<p>After the intensive climbing period, we begin our return journey. Following the successful expedition (or in the event of earlier descent due to weather or other factors), we break down Base Camp, carefully packing all equipment and ensuring Leave No Trace principles are followed. The descent from Base Camp retraces our approach route, dropping approximately 1,700m in elevation to Kagkot. While descending is generally easier on the cardiovascular system, it can be challenging for the knees and requires careful foot placement on loose terrain. Most climbers experience a sense of relief and accomplishment mixed with fatigue from the intense weeks at altitude. The descent passes through German Base Camp before continuing down valley to Kagkot, where we\'ll stay overnight in more comfortable conditions than Base Camp offered.</p>', 13, '2026-03-10 19:15:20', '2026-03-10 19:18:20'),
(3628, 302, '30', NULL, 'Trek from Kagkot to Lashicap', '2775', 'Tea House', 'B, L, & D', '<p>Continuing our descent, today\'s trek takes us from Kagkot toward Lashicap, following river valleys and traversing hillsides covered in gradually increasing vegetation as we lose elevation. The return journey offers different perspectives on the landscape we passed during our approach. With the expedition behind you, there\'s often a more relaxed atmosphere and opportunity to appreciate the cultural and natural beauty of the Dolpo region with fresh eyes. Lashicap sits at a lower elevation where agricultural terraces reappear, and the local population lives year-round rather than seasonally. You may notice warmer temperatures and the return of bird species and plant life absent in the higher zones.</p>', 18, '2026-03-10 19:15:20', '2026-03-10 19:18:20'),
(3633, 302, '31', NULL, 'Trek from Lashicap to Dunai', '2000', 'Tea House', 'B, L, & D', '<p>Our penultimate trekking day brings us back to Dunai, the district headquarters where our trek effectively began. The trail descends through increasingly populated areas, passing through villages and agricultural lands. Returning to Dunai feels like returning to civilization after weeks in the wilderness. The town offers basic amenities that will seem luxurious after the spartan conditions of high camp running water, varied food options, and communication capabilities. This evening often includes a celebration dinner with the trekking crew, offering an opportunity to thank the porters, kitchen staff, and support team who made the expedition possible. Stories are shared, photographs exchanged, and bonds formed during the challenging weeks are celebrated.</p>', 19, '2026-03-10 19:15:20', '2026-03-10 19:18:20'),
(3637, 302, '32', NULL, 'Trek from Dunai to Jhupal', '2280', 'Tea House', 'B, L, & D', '<p>The final day of trekking retraces our steps to Jhupal, the mountain airstrip where we first set foot in Dolpo. This relatively short trek follows the Thuli Bheri River, crossing suspension bridges and passing through terraced farmland. Arriving in Jhupal marks the end of our mountain journey. The small settlement here feels busy compared to the isolated campsites of the past month. Tomorrow\'s flight depends on weather conditions, so we\'ll arrive with an adequate time buffer.</p>', 20, '2026-03-10 19:15:20', '2026-03-10 19:18:20'),
(3642, 302, '33', NULL, 'Flight from Jhupal to Nepalgunj, then to Kathmandu', '1400', 'Tea House', 'Breakfast', '<p>Weather permitting, we\'ll take the morning flight from Jhupal to Nepalgunj. Mountain flights operate on visual flight rules, meaning they require clear weather. Delays are possible and should be anticipated this is why we build buffer days into the itinerary. The flight offers one last opportunity to view the magnificent Himalayan landscape from above. Upon landing in Nepalgunj, we\'ll connect to the flight back to Kathmandu (same day or next day depending on flight schedules). Arriving in Kathmandu marks your return to urban civilization. The sights, sounds, and smells of the city may feel overwhelming after weeks in the mountains. Transfer to your hotel in Thamel allows time to shower, rest, and begin processing the incredible journey you\'ve completed.</p>', 21, '2026-03-10 19:15:20', '2026-03-10 20:32:25'),
(3644, 302, '34', NULL, 'Departure', NULL, NULL, NULL, '<p>Your Putha Hiunchuli expedition concludes today. Depending on your international flight schedule, you may have time for last-minute shopping in Thamel, visiting cultural sites in Kathmandu Valley, or simply relaxing at your hotel. Our team will arrange your airport transfer according to your flight departure time. We recommend arriving at Tribhuvan International Airport at least three hours before international flights. As you depart Nepal, you carry with you the memories of an extraordinary adventure standing on a 7,000-meter Himalayan summit, experiencing the remote Dolpo region, and pushing your physical and mental limits in one of Earth\'s most spectacular mountain environments.</p>', 22, '2026-03-10 19:15:21', '2026-03-10 20:32:25'),
(3757, 305, '1', NULL, 'Arrival in Kathmandu and Transfer to Hotel', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Welcome to Nepal! Upon arrival at Tribhuvan International Airport, our team will greet you and transfer you to your hotel in Kathmandu. Today is for rest and recovery from your journey. In the evening, we will hold a pre-expedition briefing covering itinerary details, essential gear, safety protocols, and tips for high-altitude trekking and climbing. This is also a great time to check your equipment, meet your guides, and get excited for the adventure ahead.</p>', 1, '2026-03-11 02:56:09', '2026-03-11 02:58:11'),
(3758, 305, '2', NULL, 'Half-Day Kathmandu Valley Sightseeing and Expedition Preparation', '1400', '4 Star Hotel', 'Breakfast', '<p>Spend the morning exploring the cultural treasures of Kathmandu Valley, including the iconic Swayambhunath (Monkey Temple) and Durbar Square. Witness ancient temples, bustling markets, and vibrant local life. In the afternoon, we will focus on preparing your climbing and trekking gear for the Tilicho Peak expedition. You will also attend a session on high-altitude safety, acclimatization techniques, and what to expect during your ascent and descent.</p>', 2, '2026-03-11 02:56:09', '2026-03-11 02:58:11'),
(3759, 305, '3', NULL, 'Drive to Besisahar', '823', 'Tea House', 'Breakfast and Dinner', '<p>Begin the journey to the Annapurna region with a scenic drive along the Marshyangdi River. Besisahar, the starting point of the Annapurna Circuit trek, is surrounded by lush green hills and terraced fields. Overnight in Besisahar offers a gentle introduction to the trekking journey ahead. You’ll have time to enjoy the valley views, interact with local villagers, and prepare mentally for your adventure.</p>', 3, '2026-03-11 02:56:09', '2026-03-11 02:58:11'),
(3760, 305, '4', NULL, 'Drive to Dharapani', '1860', 'Tea House', 'B, L, & D', '<p>The road climbs steadily, following the Marsyangdi River through forests, waterfalls, and traditional villages. Dharapani is the gateway to the high Himalayan region and the trailhead for your trekking journey. Take this evening to relax, check your trekking pack, and enjoy the peaceful Himalayan environment.</p>', 4, '2026-03-11 02:56:09', '2026-03-11 02:58:11'),
(3761, 305, '5', NULL, 'Trek to Chame', '2670', 'Tea House', 'B, L, & D', '<p>Start your trekking adventure with a gradual ascent to Chame. The trail winds through pine and rhododendron forests, crossing small streams and pastures. Chame, the district headquarters of Manang, offers cozy lodges and the first glimpses of snow-capped peaks. This trek is an excellent introduction to high-altitude hiking, allowing you to enjoy the natural beauty while gently increasing your elevation.</p>', 5, '2026-03-11 02:56:09', '2026-03-11 02:58:11'),
(3762, 305, '6', NULL, 'Trek to Pisang', '3100', 'Tea House', 'B, L, & D', '<p>Today’s trek is slightly more challenging as the path ascends along cliffs and rivers, offering panoramic views of Annapurna II, Pisang Peak, and Gangapurna. You will pass traditional villages with stone houses, monasteries, and yak pastures. The combination of trekking, hiking through alpine terrain, and witnessing the majestic peaks makes this a highlight of the journey. Overnight in Pisang provides a chance to rest and enjoy the mountain atmosphere.</p>', 6, '2026-03-11 02:56:09', '2026-03-11 02:58:11'),
(3763, 305, '7', NULL, 'Trek to Manang', '3440', 'Tea House', 'B, L, & D', '<p>Continue trekking through the Marsyangdi Valley toward Manang, passing high-altitude desert landscapes, small villages, and moraine fields. The ascent is gradual, allowing your body to acclimatize to the altitude. Manang is a picturesque village that serves as a hub for climbers. Take time to explore, meet local residents, and enjoy the first real sense of high Himalayan adventure.</p>', 7, '2026-03-11 02:56:09', '2026-03-11 02:58:11'),
(3764, 305, '8', NULL, 'Rest Day in Manang for Acclimatization', '3440', 'Tea House', 'B, L, & D', '<p>This day is dedicated to rest and acclimatization, which is critical before ascending higher. Optional short hikes to nearby viewpoints, such as the Ice Lake or Gangapurna Glacier, help your body adjust to the altitude. You will also attend a detailed briefing on base camp procedures, climbing strategies, and safety measures, preparing for the upcoming Tilicho Peak climbing expedition.</p>', 8, '2026-03-11 02:56:10', '2026-03-11 02:58:11'),
(3765, 305, '9', NULL, 'Trek to Khangsar', '3734', 'Tea House', 'B, L, & D', '<p>The trail to Khangsar passes through alpine meadows and rocky ridges, offering stunning views of surrounding peaks. You will hike past yak herders and small monasteries, experiencing the Himalayan culture and environment. Khangsar is a small village that provides comfortable lodges for overnight stay and a chance to rest before approaching higher altitudes.</p>', 9, '2026-03-11 02:56:10', '2026-03-11 02:58:11'),
(3766, 305, '10', NULL, 'Trek from Khangsar to Besi Khola', '3995', 'Tea House', 'B, L, & D', '<p>Trek through rugged high-altitude terrain, crossing streams and moraine ridges. Besi Khola is a remote stop that allows you to gradually ascend, enjoying spectacular panoramic views of the Annapurna and Tilicho ranges. The landscape becomes more barren and alpine, giving you a sense of the adventure and challenge ahead.</p>', 10, '2026-03-11 02:56:10', '2026-03-11 02:58:11'),
(3767, 305, '11', NULL, 'Trek from Besi Khola to Tilicho Peak Base Camp', '4150', 'Tea House', 'B, L, & D', '<p>Reach the Tilicho Peak Base Camp after a rewarding trek through rocky valleys and glacial streams. Set up camp and rest in preparation for the climbing phase. This is your first night close to the summit, where you can enjoy the pristine Himalayan environment and mentally prepare for the ascent. Guides will review climbing plans, safety procedures, and camp organization.</p>', 11, '2026-03-11 02:56:10', '2026-03-11 02:58:11'),
(3768, 305, '12 to 28', NULL, 'Climbing Period – Tilicho Summit', '7134', 'Tea House', 'Camp', '<p>Over the next 17 days, you will embark on the main climbing expedition. The schedule includes gradual rotations to higher camps for acclimatization, practicing snow and ice climbing skills, and monitoring weather conditions. Your guides will lead you through ascending and descending glaciers, ridges, and snow slopes. The summit push is carefully planned for optimal weather conditions. Reaching the Tilicho Peak summit at 7,134 meters is the highlight of the expedition, offering unparalleled panoramic views of the Annapurna and Dhaulagiri ranges. After celebrating your achievement, you will safely descend back to base camp, where you can rest and recover before starting the return trek.</p>', 12, '2026-03-11 02:56:10', '2026-03-11 02:58:11'),
(3769, 305, '29', NULL, 'Pack Up and Preparation for Return', '4150', 'Tea House', 'B, L, & D', '<p>After a successful summit, pack your gear and prepare for the return journey. Tonight, reflect on the adventure and enjoy one last night amidst the breathtaking alpine scenery of Tilicho Base Camp.</p>', 13, '2026-03-11 03:01:16', '2026-03-11 03:04:22'),
(3770, 305, '30', NULL, 'Trek to Khangsar', '3750', 'Tea House', 'B, L, & D', '<p>Begin your descent to Khangsar. The trekking route retraces your steps through alpine meadows, rocky ridges, and glacial streams. Enjoy the easier pace of descent while taking in the stunning Himalayan vistas one more time. Overnight in Khangsar provides a chance to rest and reconnect with the team.</p>', 14, '2026-03-11 03:01:16', '2026-03-11 03:04:22'),
(3771, 305, '31', NULL, 'Trek from Manang to Pisang', '3250', 'Tea House', 'B, L, & D', '<p>Continue descending to Pisang, enjoying the dramatic mountain views and alpine forests. The descent is steady, giving your body time to adjust after high-altitude climbing. Pisang offers lodges for overnight stay and a comfortable stop on the way back to lower altitudes.</p>', 15, '2026-03-11 03:04:22', '2026-03-11 03:06:44'),
(3772, 305, '32', NULL, 'Trek from Pisang to Chame', '2650', 'Tea House', 'B, L, & D', '<p>Descend further to Chame through rhododendron forests and along river valleys. The terrain gradually becomes greener and more hospitable. You can reflect on your climbing experience and enjoy the sense of accomplishment from ascending and descending Tilicho Peak.</p>', 16, '2026-03-11 03:04:22', '2026-03-11 03:06:44'),
(3773, 305, '33', NULL, 'Drive to Besisahar', '750', 'Tea House', 'Breakfast', '<p>Return to Besisahar by road, retracing the scenic river valley route. Enjoy terraced fields, small villages, and peaceful landscapes as you descend to lower altitudes. Overnight in Besisahar allows you to rest after the long trekking and climbing expedition.</p>', 17, '2026-03-11 03:04:22', '2026-03-11 03:06:44'),
(3774, 305, '34', NULL, 'Drive from Besisahar to Kathmandu', '1400', '4 Star Hotel', 'Breakfast', '<p>Drive back to Kathmandu, ending the trekking phase of the expedition. Check into your hotel and relax. This is the perfect time to celebrate your successful Tilicho Peak adventure, share stories with your team, and enjoy a warm meal in the city.</p>', 18, '2026-03-11 03:04:22', '2026-03-11 03:06:44'),
(3775, 305, '35', NULL, 'Leisure Day in Kathmandu', NULL, NULL, NULL, '<p>Spend a day at leisure exploring Kathmandu, shopping for souvenirs, or visiting cultural sites. Reflect on the expedition, enjoy local cuisine, and relax before your departure. This day allows for decompression after the intense trekking and climbing journey.</p>', 19, '2026-03-11 03:04:22', '2026-03-11 03:06:44'),
(3776, 305, '36', NULL, 'Final Departure', NULL, NULL, NULL, '<p>Transfer to Tribhuvan International Airport for your flight home. Depart with memories of an unforgettable Himalayan adventure, the thrill of the Tilicho Peak summit, and the scenic beauty of the Annapurna region.</p>', 20, '2026-03-11 03:04:22', '2026-03-11 03:06:44'),
(3777, 306, '1', NULL, 'Arrival in Kathmandu', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Namaste and welcome to Nepal! Upon your arrival at Tribhuvan International Airport, you will be transferred to your hotel in Thamel. In the evening, meet your guide and fellow climbers during a traditional Nepali welcome dinner at a local restaurant. Here, you will get an overview of the expedition, safety briefings, and discuss the journey ahead.</p>', 1, '2026-03-11 20:04:57', '2026-03-11 20:26:39'),
(3778, 306, '2', NULL, 'Drive from Kathmandu to Gonggar Khola via Charikot', '1440', 'Tea House', 'Breakfast', '<p>After breakfast, embark on a scenic drive eastwards toward the Rolwaling region. Passing through charming towns and lush valleys, you will reach Gonggar Khola, your trailhead for the Pachermo Peak expedition. Overnight stay in a local guesthouse, preparing for the trek ahead.</p>', 2, '2026-03-11 20:04:57', '2026-03-11 20:26:39'),
(3779, 306, '3', NULL, 'Trek from Gonggar Khola to Simigaon', '2000', 'Tea House', 'B, L, & D', '<p>Begin your trek through dense forests and suspension bridges. The trail gradually climbs, offering glimpses of snow-capped peaks in the distance. Overnight stay at a teahouse in Simigaon, where you will experience authentic village life.</p>', 3, '2026-03-11 20:04:57', '2026-03-11 20:26:39'),
(3780, 306, '4', NULL, 'Trek from Simigaon to Dongkang', '3010', 'Tea House', 'B, L, & D', '<p>The trek becomes more alpine as you ascend toward Dongkang. Along the trail, enjoy panoramic views of rugged ridges and cascading streams. Dongkang offers the perfect introduction to high-altitude trekking with its quiet, remote setting.</p>', 4, '2026-03-11 20:04:57', '2026-03-11 20:26:39'),
(3781, 306, '5', NULL, 'Trek from Dongkang to Beding', '3693', 'Tea House', 'B, L, & D', '<p>Entering the heart of the Rolwaling region, the trail passes traditional Sherpa settlements and terraced fields. Beding is a picturesque village, surrounded by towering peaks, glaciers, and pristine rivers. Overnight stay in local lodges and prepare for higher altitude trekking.</p>', 5, '2026-03-11 20:04:57', '2026-03-11 20:26:39'),
(3782, 306, '6', NULL, 'Trek from Beding to Nagaon', '4200', 'Tea House', 'B, L, & D', '<p>Today’s trek is steep and demanding, passing moraine trails and alpine meadows. The air becomes thinner, and the mountains grow larger with every step. Overnight stay in Nagaon, the gateway to the higher glacier region, allowing your body to adapt to altitude.</p>', 6, '2026-03-11 20:04:57', '2026-03-11 20:26:39'),
(3783, 306, '7', NULL, 'Acclimatization at Nagaon & Rest Day', '4200', 'Tea House', 'B, L, & D', '<p>Spend the day at Nagaon for acclimatization. You may take short hikes around the village, explore the surrounding terrain, and prepare your gear for the glacier trek ahead. Rest and hydration are essential for a safe climb.</p>', 7, '2026-03-11 20:04:57', '2026-03-11 20:26:39'),
(3784, 306, '8', NULL, 'Trek from Nagaon to Chugima', '4920', 'Tea House', 'B, L, & D', '<p>Ascending further, the landscape transforms into rocky ridges, glacial streams, and high alpine terrain. Chugima is a small high-altitude settlement, where you will spend the night in a tented camp, absorbing breathtaking mountain vistas.</p>', 8, '2026-03-11 20:04:57', '2026-03-11 20:26:39'),
(3785, 306, '9', NULL, 'Trek from Chugima to Jaboo Glacier', '5200', 'Tea House', 'B, L, & D', '<p>The trek takes you into the glacial zone, where crevasses, ice formations, and snowfields dominate the landscape. Under the guidance of expert Sherpa climbers, you will practice glacier navigation, ensuring safety for the coming summit push. Overnight at Jaboo Glacier Camp.</p>', 9, '2026-03-11 20:04:57', '2026-03-11 20:26:39'),
(3786, 306, '10', NULL, 'Trek from Jaboo Glacier to Pachermo High Camp', '5200', 'Camp', 'B, L, & D', '<p>The final trek to High Camp is challenging but rewarding. Trekking on snow and rocky moraine, you will arrive at Pachermo High Camp, set against the backdrop of towering peaks. Overnight stay in tents, preparing for the summit attempt.</p>', 10, '2026-03-11 20:04:57', '2026-03-11 20:26:39'),
(3787, 306, '11', NULL, 'Summit Pachermo Peak and  Return to High Camp', '6237', 'Camp', 'B, L, & D', '<p>At dawn, begin the ascent to Pachermo Peak. Navigate snow slopes, icy sections, and exposed ridgelines under expert guidance. The summit rewards you with awe-inspiring 360-degree Himalayan vistas. After celebrating this incredible achievement, descend safely to Pachermo High Camp for rest.</p>', 11, '2026-03-11 20:04:57', '2026-03-11 20:26:39'),
(3788, 306, '12', NULL, 'Trek from Pachermo High Camp via Tashi Lapcha Pass to Thengma', '3800', 'Tea House', 'B, L, & D', '<p>Descend through the high alpine terrain via the Tashi Lapcha Pass. Enjoy the shifting landscapes of glaciers, rock formations, and valleys. Overnight stay at Thengma, reflecting on the journey and the summit experience.</p>', 12, '2026-03-11 20:26:39', '2026-03-11 20:29:20'),
(3789, 306, '13', NULL, 'Trek from Thengma to Namche Bazaar', '3440', 'Tea House', 'B, L, & D', '<p>Continue descending through forests, rivers, and Sherpa villages. Namche Bazaar, the bustling hub of the Khumbu region, offers markets, cafes, and cultural experiences. Overnight stay at a comfortable lodge.</p>', 13, '2026-03-11 20:26:39', '2026-03-11 20:29:20'),
(3790, 306, '14', NULL, 'Trek from Namche Bazaar to Lukla', '2860', 'Tea House', 'B, L, & D', '<p>The trek concludes with a descent through pine forests and scenic trails, arriving in Lukla. Prepare for your flight back to Kathmandu. Overnight stay in Lukla guesthouse.</p>', 14, '2026-03-11 20:26:39', '2026-03-11 20:29:20'),
(3791, 306, '15', NULL, 'Fly from Lukla to Kathmandu', '1400', '4 Star Hotel', 'Farewell Dinner', '<p>Enjoy a scenic morning flight over the Himalayas back to Kathmandu. Upon arrival, transfer to your hotel in Thamel for rest and relaxation. Spend the evening shopping for souvenirs or exploring the cultural sights of Kathmandu.</p>', 15, '2026-03-11 20:26:39', '2026-03-11 20:29:20'),
(3792, 306, '16', NULL, 'Transfer to Tribhuvan International Airport', NULL, NULL, NULL, '<p>After breakfast, you will be transferred to Tribhuvan International Airport for your onward flight. Bid farewell to Nepal with unforgettable memories of Pachermo Peak and the serene Rolwaling region.</p>', 16, '2026-03-11 20:26:39', '2026-03-11 20:29:20'),
(3793, 307, '1', NULL, 'Arrival in Kathmandu', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Welcome to Nepal! Upon landing at Tribhuvan International Airport, you will be warmly greeted by a Summit 8000 representative and transferred to your hotel in the heart of Kathmandu. After freshening up, the remainder of the day is free to explore the vibrant streets of Thamel the lively tourist hub lined with trekking shops, local restaurants, and colorful bazaars. You may also visit a nearby temple or stupa. Your expedition leader will conduct a pre-trip briefing in the evening to review the itinerary, distribute permits, confirm climbing gear, and answer any questions. A welcome dinner with the team rounds off the evening.</p>', 1, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3794, 307, '2', NULL, 'Drive to Pokhara', '820', '4 Star Hotel', 'Breakfast', '<p>After an early breakfast, board the tourist bus for the scenic overland journey from Kathmandu to Pokhara, Nepal\'s adventure capital. The route winds through the mid-hills, offering rolling green landscapes, terraced fields, and glimpses of distant snow-capped peaks on a clear day. Arrive in Pokhara by early evening and check in to your lakeside hotel. Spend the evening strolling along Phewa Lake, savoring fresh Nepali cuisine, or browsing the lively Lakeside bazaar. Pokhara serves as the perfect gateway to the Annapurna region and offers one of the most spectacular mountain panoramas in Nepal look out for the distinctive fishtail silhouette of Machapuchare (6,993 m) dominating the skyline.</p>', 2, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3795, 307, '3', NULL, 'Drive to Tikhedunga & Trek to Ulleri', '2070', 'Tea House', 'Breakfast', '<p>An early morning departure from Pokhara by private vehicle takes you east along the Pokhara–Baglung Highway and then off-road toward the village of Tikhedunga. The drive itself is a scenic adventure, passing through Nayapul and local Gurung villages before reaching the official trailhead. The afternoon trek from Tikhedunga to Ulleri is short but characterful the highlight is a famous stone staircase of approximately 3,000 steps that winds steeply uphill through dense forest and past cascading streams. Though demanding, this ascent offers a rewarding warm-up for the days ahead and stunning views behind you across the Modi Khola valley. Ulleri is a traditional Magar village perched on a hillside with sweeping views of Annapurna South and Hiunchuli on a clear evening.</p>', 3, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3796, 307, '4', NULL, 'Trek to Ghorepani', '2840', 'Tea House', 'B, L, & D', '<p>Today\'s trail leads through one of the most beautiful sections of the Annapurna trekking route. The path climbs steadily through magnificent rhododendron and oak forests in spring (March–April), these forests explode in brilliant reds and pinks, creating a mesmerizing natural tunnel overhead. Pass through the villages of Banthanti and Nangethanti, where you can pause at local tea houses to sip warm masala tea and enjoy valley views. The gradient is consistent but manageable, offering a solid conditioning day for the legs. Ghorepani is a popular overnight stop perched at the edge of the ridge, offering stunning views of the Dhaulagiri and Annapurna ranges. On arrival, enjoy a hot meal and early rest tomorrow requires a pre-dawn start.</p>', 4, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3797, 307, '5', NULL, 'Poon Hill Sunrise & Trek to Tadapani', '3210', 'Tea House', 'B, L, & D', '<p>Rise before dawn (around 4:30–5:00 AM) and make the 45-minute ascent to Poon Hill viewpoint one of the most celebrated sunrise spots in the Himalayas. As the first golden light touches the peaks, you\'ll be rewarded with a breathtaking 180-degree panorama of Dhaulagiri (8,167 m), Annapurna I (8,091 m), Annapurna South, Hiunchuli, Nilgiri, and the iconic Machapuchare (Fishtail Peak). This is a truly unmissable Himalayan moment. Return to Ghorepani for breakfast, then descend into the Banthanti valley and re-climb through forest toward Tadapani. This section of trail is less-traveled and rewards walkers with solitude, bird song, and occasional views of Annapurna South towering ahead. Tadapani is a small ridge-top hamlet known for its dramatic sunset views of the Annapurna massif.</p>', 5, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3798, 307, '6', NULL, 'Trek to Chomrong', '2140', 'Tea House', 'B, L, & D', '<p>The trail descends steeply from Tadapani through dense forest before crossing the Kimrong Khola river at the valley bottom. A sharp re-ascent on the opposite bank leads up to Chomrong, the last major village before entering the restricted Annapurna Sanctuary. Chomrong is a large, well-established Gurung village with fantastic views of Annapurna South and Hiunchuli. The village marks an important milestone in the trek permits are checked here before trekkers proceed further into the sanctuary. Use the afternoon to rest, launder gear, stock up on any last supplies, and enjoy a cold drink with Himalayan views. A good night\'s sleep here is valuable before the remoter sections ahead.</p>', 6, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3799, 307, '7', NULL, 'Trek to Dovan', '2600', 'Tea House', 'B, L, & D', '<p>Today\'s trail descends from Chomrong to the Chhomrong Khola river via a long stone staircase, then climbs again through the forest villages of Sinuwa and Bamboo before reaching Dovan. The route begins to feel increasingly dramatic as the valley narrows and the walls of the Modi Khola gorge rise steeply on both sides. Bamboo (2,335 m) is a key rest point mid-route stop here for lunch among the giant bamboo groves. Beyond Bamboo, the trail enters the inner gorge and the vegetation becomes lusher and more exotic, with towering rhododendron trees and moss-covered boulders. Dovan sits deep within the gorge and feels wonderfully remote. Accommodation here is simple but comfortable, and the sound of the Modi Khola river provides a natural soundtrack for the night. Note: The path may be slippery in wet conditions; trekking poles are recommended.</p>', 7, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3800, 307, '8', NULL, 'Trek to Deurali', '3230', 'Tea House', 'B, L, & D', '<p>From Dovan, the trail continues deeper into the gorge, gaining altitude steadily through Himalayan and Machhapuchhre Base Camp (MBC) at 3,700 m. MBC is a popular lunch stop and offers the first truly dramatic views of the Annapurna Sanctuary peaks Machapuchare\'s iconic twin summits loom directly overhead. The final stretch to Deurali involves a short but steep climb. As you gain altitude, you begin to leave the treeline behind and enter an alpine world of rock, ice, and sky. On clear days, the encircling walls of the sanctuary become visible in their entirety. Altitude awareness begins here. Monitor yourself for symptoms of Acute Mountain Sickness (AMS): headache, nausea, dizziness, or disturbed sleep. Stay well hydrated and inform your guide immediately if you feel unwell.</p>', 8, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3801, 307, '9', NULL, 'Trek to Annapurna Base Camp', '4130', 'Tea House', 'B, L, & D', '<p>Today is one of the most memorable days of the entire expedition. From Deurali, the trail emerges from the gorge into the legendary Annapurna Sanctuary a high glacial amphitheater completely encircled by 7,000 and 8,000-metre peaks. The scale is overwhelming and humbling. The final 3–4 hours of trail cross open moraine slopes with unobstructed, 360-degree views of Annapurna I (8,091 m), Annapurna South (7,219 m), Annapurna III (7,555 m), Gangapurna (7,455 m), Hiunchuli (6,441 m), and the unmistakable twin peaks of Machapuchare (6,993 m). Annapurna Base Camp (ABC) sits at the heart of this natural amphitheater. This is the highest point of the classic ABC trek take time to absorb the atmosphere, photograph the surroundings, and acclimatize before tomorrow\'s move to Tent Peak Base Camp.</p>', 9, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3802, 307, '10', NULL, 'Trek to Tent Peak Base Camp', '4400', 'Tea House', 'B, L, & D', '<p>Leaving the guesthouses of ABC behind, today marks your transition from trekker to climber. The route from ABC to Tent Peak Base Camp leads across glacial moraines and rocky terrain, gradually ascending to the base of the mountain. Upon arrival, the expedition team will set up your tented camp and deliver a full equipment briefing. Your guide will check and distribute all climbing gear: crampons, harness, helmet, ice axe, ropes, gaiters, and high-altitude clothing layers. Practice fitting and adjusting all equipment under guidance. The afternoon provides time to acclimatize, rest, and mentally prepare for the climb ahead. A detailed summit briefing will cover the route, safety protocols, turnaround times, and weather forecasting. Good acclimatization at this altitude is critical to your summit success.</p>', 10, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3803, 307, '11', NULL, 'Trek to High Camp', '5000', 'Camp', 'B, L, & D', '<p>A shorter but demanding day climbing steeply from Base Camp to High Camp. The trail gains approximately 600 metres of altitude over 3–4 hours, crossing snow slopes and rocky ridges. Crampons and rope may be required depending on snow conditions your guide will advise on the day. High Camp is a small, exposed ledge cut into the upper mountainside. The views from here are extraordinary the entire Annapurna Sanctuary spreads out far below, and the summit of Tent Peak is clearly visible above. The scale of the surroundings provides powerful motivation. The afternoon is reserved for complete rest. Eat well, drink at least 3–4 litres of water, and limit physical activity. Your guide will deliver a final summit briefing including the wake-up time (typically midnight to 1:00 AM), route description, and contingency plans.</p>', 11, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3804, 307, '12', NULL, 'Summit Day — Tent Peak', '5663', 'Camp', 'B, L, & D', '<p>SUMMIT DAY. Wake up at midnight to 1:00 AM for final gear checks, a hot breakfast, and pre-climb preparations. Depart High Camp under headlamp in the pre-dawn darkness, roped up and equipped. The summit route climbs steeply through snow and ice on the upper face of Tent Peak. Climbers will use crampons, ice axe, and fixed ropes where required, ascending with the full support of your experienced climbing guide. The pace is steady and controlled this is not a race, but a disciplined, safe ascent. The summit of Tharpu Chuli (5,695 m) offers one of the most dramatic panoramas in the Annapurna region. On a clear morning, the dawn light illuminates Annapurna I, Annapurna South, Gangapurna, Machapuchare, and dozens of other peaks in an awe-inspiring spectacle. Savor this hard-earned moment. Descend carefully using the same route, returning to High Camp by mid-morning and continuing all the way down to Base Camp for lunch and a well-deserved rest. The descent from High Camp to Base Camp takes approximately 3–4 hours.</p>', 12, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3805, 307, '13', NULL, 'Trek to Deurali', '3230', 'Tea House', 'B, L, & D', '<p>After the exertions of summit day, today begins a long and satisfying descent back through the Annapurna Sanctuary toward Deurali. The route reverses the approach trail, passing back through ABC, across the moraine, and down through the Modi Khola gorge. Despite tired legs, the descent is deeply rewarding. The peaks that loomed ahead on the way up now flank your retreat, and the views remain spectacular until you drop back below the treeline at Deurali. Altitude loss brings a notable increase in oxygen and energy. Many climbers find the descent exhilarating, experiencing a tangible sense of relief and achievement after the summit push.</p>', 13, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3806, 307, '14', NULL, 'Trek to Chomrong', '2140', 'Tea House', 'B, L, & D', '<p>Continue the descent from Deurali through the inner gorge, passing back through the bamboo forest and the riverside village of Bamboo before re-climbing to Chomrong via the Sinuwa ridge. The return journey through this section feels familiar, but the perspective is different you are now a summit climber returning from the mountain. Chomrong\'s guesthouses offer welcome hot showers, cold drinks, and the comforts of civilization. Celebrate your summit success with fellow trekkers, share stories over dinner, and reflect on the achievement. This is also a good opportunity to sort equipment, pack away climbing gear, and transfer unnecessary weight to porter loads for the final days of trekking.</p>', 14, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3807, 307, '15', NULL, 'Trek to Ghandruk', '1940', 'Tea House', 'B, L, & D', '<p>The final full day of trekking leads from Chomrong to Ghandruk, one of the most beautiful and culturally rich villages in the Annapurna region. The trail crosses the Chomrong Khola river, climbs back to the Kimrong ridge, and then makes a long, gradual descent through rhododendron and oak forests. Ghandruk is a large, traditional Gurung village famous for its stone-paved paths, traditional architecture, and vibrant local culture. The Gurung people are among Nepal\'s most celebrated high-altitude ethnic groups and many Gurkha soldiers hail from this region. Visit the Gurung Museum and Cultural Centre if time permits, explore the village\'s traditional alleyways, and enjoy a panoramic dinner view of Annapurna South, Hiunchuli, and Machapuchare a fitting farewell to the Annapurna giants.</p>', 15, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3808, 307, '16', NULL, 'Drive to Pokhara', '820', '4 Star Hotel', 'Breakfast', '<p>A private vehicle awaits at Siwai (Lower Ghandruk) for the scenic drive back to Pokhara. The road winds through the lower Annapurna foothills, crossing river valleys and passing through small market towns before arriving at the lakeside city. Check into your hotel, freshen up with a long-awaited hot shower, and spend the afternoon at leisure. Pokhara offers excellent options for a celebratory evening: rooftop restaurants overlooking Phewa Lake, live music venues, and the lively Lakeside strip. A summit celebration dinner is arranged for the team to mark the successful completion of the Tent Peak expedition. This is a great opportunity to share memories, review photos, and toast the achievement.</p>', 16, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3809, 307, '17', NULL, 'Drive to Kathmandu', '1400', '4 Star Hotel', 'B, L, & D', '<p>A morning departure from Pokhara by tourist bus for the return journey to Kathmandu. The drive follows the Prithvi Highway through the scenic river valleys and forested hills of the mid-hills region. Arrive in Kathmandu by early evening. Transfer to your hotel in Thamel for a final night in Nepal\'s capital. Use the evening to explore Thamel\'s lively shops and restaurants, purchase any last-minute souvenirs, or simply relax after the expedition. If time permits, a visit to the iconic Boudhanath Stupa a UNESCO World Heritage Site is highly recommended for a serene evening experience.</p>', 17, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3810, 307, '18', NULL, 'Final Departure', NULL, 'Breakfast', NULL, '<p>Your Tent Peak expedition comes to a close. After breakfast, pack your bags and check out of the hotel. A Summit 8000 representative will transfer you to Tribhuvan International Airport in plenty of time for your international flight. We hope the memories of the Annapurna Sanctuary, the camaraderie of the team, and the extraordinary achievement of standing on the summit of Tharpu Chuli stay with you for a lifetime. Safe travels, and we hope to welcome you back to Nepal for your next Himalayan adventure. Namaste!</p>', 18, '2026-03-12 01:26:49', '2026-03-12 01:45:30'),
(3811, 308, '1', NULL, 'Arrival in Kathmandu', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Your Himalayan adventure begins the moment you land at Tribhuvan International Airport. After clearing customs and collecting your bags, your guide or a representative from your trekking company will meet you and transfer you to your hotel in the heart of Kathmandu. The rest of the day is yours to settle in, freshen up, and soak in the sights and sounds of this vibrant city. Take an evening stroll through the lively streets of Thamel, sample some Nepali dal bhat, and get to bed early as the journey ahead is a big one.</p>', 1, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3812, 308, '2', NULL, 'Kathmandu Sightseeing and Permit Preparation', '1400', '4 Star Hotel', 'Breakfast', '<p>Today is a wonderful mix of culture and logistics. In the morning, your guide will assist you with obtaining your Naya Kanga peak climbing permit, Langtang National Park entry permit, and TIMS card. Once the paperwork is sorted, the rest of the day opens up for sightseeing around Kathmandu\'s UNESCO-listed heritage sites. Wander through the golden temples of Pashupatinath, spin the prayer wheels at Boudhanath Stupa, or lose yourself in the ancient courtyards of Swayambhunath. It is a perfect way to ease into the rhythm of Nepal before hitting the trail.</p>', 2, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3813, 308, '3', NULL, 'Drive from Kathmandu to Syabrubes', '1450', 'Tea House', 'B, L, & D', '<p>After breakfast, you hit the road for the scenic overland journey to Syabrubesi, the charming gateway village to the Langtang region. The drive takes roughly seven to eight hours through winding mountain roads, terraced hillsides, and occasional glimpses of snow-capped ridges peeking above the treeline. It is a long day in the vehicle, but the scenery keeps things entertaining. Arrive in Syabrubesi in the late afternoon, check into your teahouse, enjoy a warm meal, and rest up for your first proper day on the trail tomorrow.</p>', 3, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3814, 308, '4', NULL, 'Trek from Syabrubesi to Lama Hotel', '1450', 'Tea House', 'B, L, & D', '<p>Boots on, pack up, and step onto the trail. Today\'s walk follows the Langtang Khola river upstream through lush subtropical forest, crossing suspension bridges and passing through small settlements along the way. The trail gains elevation gradually and the surrounding greenery is a lovely introduction to the Langtang wilderness. After around five to six hours of trekking, you arrive at Lama Hotel, a cluster of friendly teahouses nestled in dense forest. Celebrate your first day on the trail with a hot tea and a well-earned rest.</p>', 4, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3815, 308, '5', NULL, 'Trek from Lama Hotel to Langtang Village', '3330', 'Tea House', 'B, L, & D', '<p>Today the landscape begins to open up beautifully as you leave the forest behind and enter the wider valley. The trail climbs steadily past yak pastures, cascading waterfalls, and colourful mani stones carved with Buddhist prayers. Langtang Village, rebuilt after the 2015 earthquake with heartfelt community effort, welcomes you with warm hospitality and its first proper Himalayan views. Spend the evening exploring the village, chatting with locals, and getting your first real taste of the high alpine world that lies ahead.</p>', 5, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3816, 308, '6', NULL, 'Trek from Langtang Village to Kyanjin Gompa', '3870', 'Tea House', 'B, L, & D', '<p>A relatively short but scenic day brings you to Kyanjin Gompa, one of the most beloved stops on any Langtang itinerary. The trail winds through open meadows dotted with grazing yaks, and the surrounding peaks grow more dramatic with every step. Kyanjin Gompa itself is a small but spirited settlement home to a centuries-old monastery and a famous yak cheese factory, both worth a visit on arrival. The mountain views from here are simply stunning, and on a clear evening, Langtang Lirung glows golden in the fading light.</p>', 6, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3817, 308, '7', NULL, 'Acclimatisation Day at Kyanjin Gompa', '3870', 'Tea House', 'B, L, & D', '<p>Rest days at altitude are never really rest days, and today is a great example of that. To help your body adapt to the thinner air, you will make a rewarding day hike up to either Kyanjin Ri (4,773m) or Tserko Ri (4,984m), both offering sweeping panoramic views across the Langtang Himalaya. The golden rule of high-altitude trekking applies perfectly here: climb high, sleep low. Return to Kyanjin Gompa for a hearty dinner, a visit to the monastery if you have not already, and an early night as higher camps await.</p>', 7, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3818, 308, '8', NULL, 'Trek from Kyanjin Gompa to Naya Kanga Base Camp', '4400', 'Camp', 'B, L, & D', '<p>Leaving the comforts of Kyanjin Gompa behind, today you make your way toward the mountain proper. The trail heads northeast across rocky moraines and open terrain, with the glacial world of Naya Kanga coming into sharp focus ahead of you. Base camp at around 4,400 metres is a raw and beautiful place, with big skies, total silence, and a real sense of being at the edge of something extraordinary. Your climbing guide will brief you on the route ahead, check gear, and help you prepare mentally and physically for the days to come.</p>', 8, '2026-03-12 03:20:37', '2026-03-12 03:25:08');
INSERT INTO `cl_trip_itinerary` (`id`, `trip_detail_id`, `days`, `meals`, `title`, `max_altitude`, `distance`, `duration`, `content`, `ordering`, `created_at`, `updated_at`) VALUES
(3819, 308, '9', NULL, 'Trek from Base Camp to High Camp', '5000', 'Camp', 'B, L, & D', '<p>A shorter but meaningful push today takes you up to high camp at 5,000 metres. The terrain becomes more technical as you gain elevation, moving across boulder fields and the lower reaches of the glacier. High camp is a small, exposed perch on the m</p>', 9, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3820, 308, '10', NULL, 'Summit Day and Descent to Base Camp', '5844', 'Camp', 'B, L, & D', '<p>This is the day everything has been building toward. Your team rises in the dark, layers up against the cold, and sets off across the glacier by headtorch. The ascent involves crampons and ice axe work on increasingly steep snow and ice slopes, and every step upward brings a growing sense of achievement. The summit ridge of Naya Kanga at 5,844 metres delivers one of the finest panoramas in the central Himalaya, with Langtang Lirung, Dorje Lakpa, Ganesh Himal, and countless other giants stretching across the horizon. Savour the moment, take your photos, then make a careful descent all the way back to base camp for a well-deserved rest.</p>', 10, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3821, 308, '11', NULL, 'Trek from Base Camp to Langtang Village via Kyanjin Gompa', '3330', 'Tea House', 'B, L, & D', '<p>With the summit behind you and a lightness in your step, today is a long but satisfying descent back through familiar terrain. You pass through Kyanjin Gompa, where a quick stop for yak cheese or butter tea feels like a fitting reward, before continuing down the valley to Langtang Village. The lower elevation brings warmer air, and the body begins to unwind after the intensity of the summit push. It is a great day to reflect on everything you have experienced and share stories with fellow trekkers over dinner.</p>', 11, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3822, 308, '12', NULL, 'Trek from Langtang Village to Lama Hotel', '2470', 'Tea House', 'B, L, & D', '<p>Back into the forest you go, descending steadily through the familiar trail that brought you up just over a week ago. The rhododendrons, the river crossings, and the birdsong all feel like old friends now. Lama Hotel greets you once again with its simple teahouse warmth, and the contrast between where you slept two nights ago and where you are sleeping tonight is a quietly satisfying reminder of just how much ground you have covered.</p>', 12, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3823, 308, '13', NULL, 'Trek from Lama Hotel to Syabrubesi', '1450', 'Tea House', 'B, L, & D', '<p>The final day on the trail winds back down through the lower valley to Syabrubesi, completing the full loop. The descent is gentle and the mood tends to be celebratory, with the hard work firmly behind you. Arrive in Syabrubesi in the early afternoon, treat yourself to a cold drink and a big meal, and spend the evening swapping stories and unwinding before the road journey back to the capital tomorrow.</p>', 13, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3824, 308, '14', NULL, 'Drive from Syabrubesi to Kathmandu', '1400', '4 Star Hotel', 'Breakfast', '<p>The scenic mountain road brings you back to Kathmandu after roughly seven to eight hours on the road. It is a long drive, but it gives you plenty of time to decompress, watch the landscape shift from high mountain country back to valley and city, and start thinking about what comes next. Arrive back in Kathmandu in the evening, check into your hotel, and give yourself a proper pat on the back. You climbed a Himalayan peak. That deserves a celebration dinner.</p>', 14, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3825, 308, '15', NULL, 'Final Departure or Onward Journey', NULL, NULL, NULL, '<p>Your Naya Kanga adventure comes to a close today. Depending on your onward plans, your team will arrange a transfer to the airport for your flight home, or help you prepare for your next program if you are continuing on to further trekking or climbing in Nepal. Whatever comes next, you leave with the summit of Naya Kanga in your memories, stronger legs, a bigger perspective, and almost certainly the beginnings of a plan to come back.</p>', 15, '2026-03-12 03:20:37', '2026-03-12 03:25:08'),
(3826, 309, '1', NULL, 'Arrival in Kathmandu', '1350', '4 Star Hotel', 'Welcome Dinner', '<p>Arrive at Tribhuvan International Airport, Kathmandu, where you’ll be welcomed by our Summit 8000 team and transferred to your 4 or 5 star hotel. Take the day to rest, recover from your flight, and prepare for the Himalayan journey ahead. Depending on your arrival time, you can explore the vibrant streets of Thamel, enjoy local cuisine, or attend an expedition briefing covering safety, equipment, and itinerary details.</p>', 1, '2026-03-13 02:53:52', '2026-03-13 02:55:29'),
(3827, 309, '2', NULL, 'Drive from Kathmandu to Chame', '2715', 'Tea House', 'Breakfast', '<p>Begin your adventure with a scenic drive to Chame, the gateway to the Annapurna region. The distance between Kathmandu and Chame is around 249 km. The route follows rivers, terraced farmland, and forested hills, offering spectacular views of snow-capped peaks along the way. Upon arrival, settle into a teahouse and enjoy the peaceful mountain surroundings while acclimatizing for the trek ahead.</p>', 2, '2026-03-13 02:53:52', '2026-03-13 02:55:29'),
(3828, 309, '3', NULL, 'Trek from Chame to Pisang', '3250', 'Tea House', 'B, L, & D', '<p>The trek starts with the mountain guide\'s brief of the day and then walks through the gentle trails of pine forests and traditional villages. Enjoy panoramic views of Pisang Peak and the northern face of Annapurna II. This day helps your body adjust to the altitude while immersing you in local culture, prayer flags, and Himalayan landscapes. Evening is perfect for rest and photography.</p>', 3, '2026-03-13 02:53:52', '2026-03-13 02:55:29'),
(3829, 309, '4', NULL, 'Trek from Pisang to NgawaL', '3860', 'Tea House', 'B, L, & D', '<p>After your breakfast in the tea house, you will start your walk to the Nagawal, where the trail climbs gradually through terraced fields and small villages, leading to Ngawal, a village known for its Tibetan Buddhist culture. Explore local monasteries, enjoy stunning mountain vistas, and spend the evening acclimatizing before higher altitude trekking begins.</p>', 4, '2026-03-13 02:53:52', '2026-03-13 02:55:29'),
(3830, 309, '5', NULL, 'Acclimatization & Rest Day at Ngawal', '3860', 'Tea House', 'B, L, & D', '<p>The fifth day of your journey is a very crucial day for acclimatization. You will take short hikes near ridges to help your body adjust to higher altitudes. Our experienced mountain guides may also provide training on crampons, ice axes, and climbing techniques, preparing you for the summit push.</p>', 5, '2026-03-13 02:53:52', '2026-03-13 02:55:29'),
(3831, 309, '6', NULL, 'Trek from Ngawal to Yak Kharka', '4050', 'Tea House', 'B, L, & D', '<p>Trekking today takes you higher into alpine landscapes, with grazing fields and glacial streams along the way. Yak Kharka offers simple teahouse accommodation and a serene environment, allowing your body to adapt to the growing altitude while you enjoy panoramic views of the surrounding peaks.</p>', 6, '2026-03-13 02:53:52', '2026-03-13 02:55:29'),
(3832, 309, '7', NULL, 'Trek from Yak Kharka to High Camp', '5600', 'Camp', 'B, L, & D', '<p>The ascent to High Camp at an altitude of 5600 meters is challenging but rewarding. Snow-covered slopes, rocky ridges, and glacier views dominate the landscape. High Camp serves as your base for the summit attempt, and here you’ll finalize your climbing preparations with the guidance of our experienced Himalayan climbing team.</p>', 7, '2026-03-13 02:53:52', '2026-03-13 02:55:29'),
(3833, 309, '8', NULL, 'Summit Chulu East Peak & Return to Ngawal', '6584', 'Camp', 'B, L, & D', '<p>Summit day is the highlight of the expedition. Start early before sunrise, navigating snow slopes with crampons and ice axes under expert supervision. Reach the summit of Chulu East Peak to enjoy breathtaking views of Annapurna II, Tilicho Peak, Gangapurna, and the Manaslu range. After celebrating your achievement, descend to Ngawal for rest and reflection on this unforgettable Himalayan experience.</p>', 8, '2026-03-13 02:53:52', '2026-03-13 02:55:29'),
(3834, 309, '9', NULL, 'Reserve Day (Weather Backup)', '5600', 'Camp', 'B, L, & D', '<p>The ninth day is reserved in case of adverse weather or for additional acclimatization. Safety is our top priority, and having a buffer day increases the chances of a successful summit. Optional short hikes around Ngawal provide extra exploration and photography opportunities.</p>', 9, '2026-03-13 02:53:52', '2026-03-13 02:55:29'),
(3835, 309, '10', NULL, 'Trek to Humde and Drive to Besisahar', '760', 'Tea House', 'B, L, & D', '<p>Descend through picturesque valleys, alpine landscapes, and local villages toward Humde. From here, board a vehicle to Besisahar, enjoying views of terraced fields and rivers along the way. This day allows your body to recover while experiencing the diverse terrain of the Annapurna region.</p>', 10, '2026-03-13 02:53:52', '2026-03-13 02:55:29'),
(3836, 309, '11', NULL, 'Drive from Besisahar to Kathmandu', '1350', '4 Star Hotel', 'Breakfast', '<p>Return to Kathmandu by road, witnessing the transition from high mountains to the bustling city. In the evening, explore Thamel for souvenirs, enjoy local cuisine, or celebrate the completion of your Chulu East Peak expedition with your team.</p>', 11, '2026-03-13 02:53:52', '2026-03-13 02:55:29'),
(3837, 309, '12', NULL, 'Departure from Kathmandu', NULL, NULL, NULL, '<p>After breakfast, transfer to Tribhuvan International Airport for your departure flight. Take home memories of a lifetime summiting a Himalayan peak, experiencing Nepalese culture, and trekking through some of the most scenic landscapes in the world. Please don’t forget to give us a review on the Trip Advisor or google to help other trekkers and climbers to experience their memories with us.</p>', 12, '2026-03-13 02:53:52', '2026-03-13 02:55:29'),
(3838, 310, '1', NULL, 'Arrival in Kathmandu', '1350', '4 Star Hotel', 'Welcome Dinner', '<p>Welcome to Nepal, we will be waiting for you at Tribhuvan International Airport, where one our of our team members from Summit 8000 will greet you and transfer you to your hotel in Thamel. The rest of the day is yours to settle in, recover from travel, and soak in the vibrant energy of Kathmandu. Welcome dinner with the team in the evening.</p>', 1, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3839, 310, '2', NULL, 'Preparation Day in Kathmandu', '1350', '4 Star Hotel', 'Breakfast', '<p>A full day dedicated to expedition groundwork. Attend the official climbing permit briefing, meet your lead guide and Sherpa team, and complete any last-minute gear purchases in Thamel\'s well-stocked mountaineering shops. Equipment checks and packing are completed before an early rest.</p>', 2, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3840, 310, '3', NULL, 'Fly Kathmandu to Lukla', '2800', 'Tea House', 'B, L, & D', '<p>An early morning transfer to the domestic terminal for the legendary 35-minute mountain flight to Lukla. Landing at Tenzing-Hillary Airport, one of the world\'s most dramatic airstrips, marks the true start of the expedition. Settle into a teahouse and rest for the trek ahead.</p>', 3, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3841, 310, '4', NULL, 'Lukla to Chutanga', '3050', 'Tea House', 'B, L, & D', '<p>The trail descends from Lukla before climbing steadily through pine and rhododendron forest toward Chutanga. This quieter route diverges from the busy Everest Base Camp trail, offering immediate solitude and a genuine sense of entering remote terrain. An easy opening day to warm the legs.</p>', 4, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3842, 310, '5', NULL, 'Chutanga to Thuli Kharka via Zatrawa La Pass', '4610', 'Tea House', 'B, L, & D', '<p>The most demanding trekking day of the approach. The trail ascends sharply to the Zatrawa La Pass, rewarding the effort with sweeping panoramas of Kusum Kanguru, Numbur, and the Khumbu peaks. A long descent follows into the pastoral grazing settlement of Thuli Kharka. Take the pass slowly. Altitude awareness begins here.</p>', 5, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3843, 310, '6', NULL, 'Thuli Kharka to Kothe', '3580', 'Tea House', 'B, L, & D', '<p>A pleasant descent through the upper Hinku Valley, following the river downstream through increasingly dramatic gorge scenery. Kothe is a small seasonal settlement that serves as a key resupply and rest point for expeditions heading deeper into the valley. Arrive early and rest.</p>', 6, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3844, 310, '7', NULL, 'Kothe to Thangnak', '4350', 'Tea House', 'B, L, & D', '<p>The valley narrows, and the landscape turns alpine as the trail climbs steadily alongside the Hinku Khola river. Glacial debris, hanging seracs, and high ridgelines come into full view. Thangnak is a sparse high-altitude camp with front-row views of the surrounding peaks. Hydrate well and move slowly.</p>', 7, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3845, 310, '8', NULL, 'Acclimatization Day at Thangnak', '4350', 'Tea House', 'B, L, & D', '<p>A rest day is non-negotiable at this elevation. Take a short hike to higher ground to stimulate acclimatization before returning to sleep low. Use the time to inspect equipment, review the climbing plan with your guide, and allow the body to adapt. This day directly influences summit performance.</p>', 8, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3846, 310, '9', NULL, 'Thangnak to Kusum Kanguru Base Camp', '4900', 'Camp', 'B, L, & D', '<p>A shorter but meaningful day as the expedition moves to Base Camp beneath Kusum Kanguru\'s imposing flanks. The mountain reveals its true scale from here steep, technical, and commanding. Camp is established, loads are organized, and the climbing team conducts a full route assessment.</p>', 9, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3847, 310, '10', NULL, 'Base Camp to High Camp I', '5100', 'Camp', 'B, L, & D', '<p>The first genuine climbing day. The team moves through the lower glacier, navigating crevassed terrain and establishing the route toward High Camp I. Fixed ropes are set on technical sections. Progress is deliberate the focus is on positioning the team well for the higher camps ahead.</p>', 10, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3848, 310, '11', NULL, 'High Camp I to High Camp II', '5600', 'Camp', 'B, L, & D', '<p>Exposure increases significantly on this section. Steep ice and mixed ground lead to High Camp II, positioned on a narrow shelf with dramatic views in every direction. Climbing at this altitude demands efficiency and calm. Arrive, melt snow for water, eat well, and rest ahead of summit day.</p>', 11, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3849, 310, '12', NULL, 'Summit Day Kusum Kanguru and Descent to Base Camp', '6367', 'Camp', 'B, L, & D', '<p>An alpine start, typically between midnight and 2am, puts the team on the upper mountain in darkness. The final push to the summit involves the most technical terrain of the expedition, steep mixed ground requiring focused movement and precise rope management. On a clear day, the summit view encompasses Everest, Lhotse, Makalu, and Ama Dablam. Descend carefully to Base Camp and celebrate a hard-earned achievement.</p>', 12, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3850, 310, '13', NULL, 'Base Camp to Kothe', '3600', 'Tea House', 'B, L, & D', '<p>Breaking camp and beginning the long walk out. The descent retraces the Hinku Valley route, and the drop in altitude brings immediate physical relief. Kothe offers a warm meal and the first true rest after summit exertion.</p>', 13, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3851, 310, '14', NULL, 'Kothe to Thuli Kharka', '3900', 'Tea House', 'B, L, & D', '<p>A gradual climb back up the valley to Thuli Kharka, a familiar camp from the approach. The mood is lighter on the return, the hard work is done. Enjoy the landscape with a fresh perspective and rest for the long pass crossing ahead.</p>', 14, '2026-03-15 20:42:39', '2026-03-15 20:47:49'),
(3852, 310, '15', NULL, 'Thuli Kharka to Lukla via Zatrawa La Pass', '4610', 'Tea House', 'B, L, & D', '<p>The longest trekking day of the expedition. The trail climbs back over the Zatrawa La before a long descent into Lukla. Start early and pace steadily. Reaching Lukla marks the end of the mountain journey a fitting final trek after three weeks in the field.</p>', 15, '2026-03-15 20:42:40', '2026-03-15 20:47:49'),
(3853, 310, '16', NULL, 'Fly Lukla to Ramechhap, Drive to Kathmandu', '1350', '4 Star Hotel', 'Farewell Dinner', '<p>An early flight from Lukla to Ramechhap airport, followed by a scenic drive back to Kathmandu through the mid-hills of Nepal. Arrive in the capital by afternoon, check into the hotel, and enjoy the simple pleasures of a hot shower and city food.</p>', 16, '2026-03-15 20:42:40', '2026-03-15 20:47:49'),
(3854, 310, '17', NULL, 'Free Day in Kathmandu and Farewell Dinner', '1400', '4 Star Hotel', 'Breakfast', '<p>A full day at leisure to explore Thamel, visit Boudhanath Stupa or Pashupatinath Temple, or simply rest. In the evening, We will host a farewell dinner to celebrate the team\'s achievement and close the expedition in good spirit.</p>', 17, '2026-03-15 20:42:40', '2026-03-15 20:47:49'),
(3855, 310, '18', NULL, 'Final Departure', NULL, NULL, NULL, '<p>Transfer to Tribhuvan International Airport for your onward flight. The expedition concludes, but the memory of Kusum Kanguru\'s summit stays considerably longer. We hope you liked our service, and once again, we wish to welcome you to Nepal.</p>', 18, '2026-03-15 20:42:40', '2026-03-15 20:47:49'),
(3856, 311, '1', NULL, 'Arrival in Kathmandu', '1350', '4 Star Hotel', 'Welcome Dinner', 'Namaste and we welcome you to Kathmandu. You will arrive in bustling Kathmandu, where the streets are alive with honking taxis, colorful shops, and the scent of incense. You will explore Thamel, grab a warm dal bhat, and watch city life unfold around you. In the evening, you will meet your guides, discuss the expedition plan, and have all your questions answered.', 1, '2026-03-15 21:52:59', '2026-03-15 21:52:59'),
(3857, 311, '2', NULL, 'Kathmandu to Lukla and Trek to Phakding', '2610', 'Tea House', 'B, L, & D', 'Early in the morning, after breakfast, a thrilling flight to Lukla awaits soaring over deep valleys and snow-capped peaks. The trail winds through pine forests, crosses swinging suspension bridges, and passes through the first Himalayan villages. By the time Phakding comes into view, the excitement of the mountains is already unmistakable.', 2, '2026-03-15 21:52:59', '2026-03-15 21:52:59'),
(3858, 311, '3', NULL, 'Phakding to Namche Bazaar', '3440', 'Tea House', 'B, L, & D', 'The route follows the Dudh Koshi River, climbing steadily through rhododendron and birch forests. Crossing the famous Hillary Suspension Bridge, the views below are enough to make the heart race. Namche Bazaar welcomes with friendly locals, cozy shops, and the first tantalizing glimpse of Everest peeking through the valley.', 3, '2026-03-15 21:52:59', '2026-03-15 21:52:59'),
(3859, 311, '4', NULL, 'Acclimatization Day in Namche Bazaar', '3440', 'Tea House', 'B, L, & D', 'A short morning hike helps the body adjust to altitude while opening up panoramic mountain views. The Sherpa Culture Museum is worth exploring, or simply wandering the market and chatting with locals. The afternoon calls for a coffee and a quiet moment surrounded by the mountains.', 4, '2026-03-15 21:52:59', '2026-03-15 21:52:59'),
(3860, 311, '5', NULL, 'Namche Bazaar to Dole', '4038', 'Tea House', 'B, L, & D', 'Leaving the busier trails behind, the path moves through juniper forests and open ridges with sweeping Himalayan panoramas and views of Khumbila peak. Dole is a quiet, unhurried village — perfect for resting in a teahouse and swapping stories with fellow trekkers.', 5, '2026-03-15 21:52:59', '2026-03-15 21:52:59'),
(3861, 311, '6', NULL, 'Dole to Machhermo', '4470', 'Tea House', 'B, L, & D', 'A short but altitude-gaining trail today, with Cho Oyu dominating the skyline. Glaciers and wide-open valleys unfold along the way before arriving at Machhermo’s peaceful ridge-top teahouses. The evening calls for hydration, rest, and a front-row seat to the sunset behind snow-capped peaks.', 6, '2026-03-15 21:52:59', '2026-03-15 21:52:59'),
(3862, 311, '7', NULL, 'Machhermo to Gokyo', '4750', 'Tea House', 'B, L, & D', 'The trek follows the edge of the Ngozumpa Glacier toward the sacred, turquoise Gokyo Lakes. Remote and breathtaking, this stretch feels like stepping into another world a feeling confirmed on arrival when the extraordinary views finally settle in.', 7, '2026-03-15 21:52:59', '2026-03-15 21:52:59'),
(3863, 311, '8', NULL, 'Acclimatization Day Gokyo Ri (5,357m) & Thangnak', '4500', 'Tea House', 'B, L, & D', 'An early climb up Gokyo Ri rewards with thin air and a sweeping panorama of Everest, Lhotse, Makalu, and Cho Oyu. The descent passes through Thangnak, with time to mingle with fellow trekkers before returning to Gokyo to rest and let the mountains truly sink in.', 8, '2026-03-15 21:52:59', '2026-03-15 21:52:59'),
(3864, 311, '9', NULL, 'Gokyo to Thangnak', '4650', 'Tea House', 'B, L, & D', 'The glacier edge leads through rugged terrain moraine ridges, narrowing valleys, and mountains that feel closer with every step. Conversations with the guides about the route ahead build anticipation as Thangnak comes into view.', 9, '2026-03-15 21:52:59', '2026-03-15 21:52:59'),
(3865, 311, '10', NULL, 'Thangnak to Cholaste Base Camp', NULL, NULL, NULL, NULL, 10, '2026-03-15 21:52:59', '2026-03-15 21:52:59'),
(3866, 278, '26', NULL, 'Trek from Baruntse Base Camp to Kongma Dingma', '4850', 'Tea House', 'B, L, & D', '<p>After the emotional and physically demanding days on Baruntse, you will leave the base camp and begin your descent toward Kongma Dingma. The trail takes you across glacial moraines, rocky alpine landscapes, and wide open valleys where the dramatic Himalayan scenery still surrounds you. As you descend, you will feel the air becoming slightly richer and the terrain gradually changing from harsh glacier zones to more stable trekking paths. By the time you reach Kongma Dingma, you will finally have a moment to relax and reflect on the incredible achievement of climbing a 7,000-meter Himalayan peak.</p>', 13, '2026-03-16 16:47:17', '2026-04-05 12:00:49'),
(3867, 278, '27', NULL, 'Trek from Kongma Dingma to Thanknak', '4350', 'Tea House', 'B, L, & D', '<p>Today you will continue trekking through the remote high-altitude landscapes of the Hinku Valley toward Thanknak. The trail passes along glacial rivers and rugged moraine fields while offering incredible views of surrounding peaks and icy ridgelines. As you walk, you will witness the raw beauty of the Himalayas where very few trekkers travel compared to the more crowded trekking regions of Nepal. Reaching Thanknak, you will settle into a quiet mountain lodge and enjoy the peaceful atmosphere of this isolated alpine settlement.</p>', 14, '2026-03-16 16:47:17', '2026-04-05 12:00:49'),
(3868, 278, '28', NULL, 'Trek from Thanknak to Thuli Kharka', '4200', 'Tea House', 'B, L, & D', '<p>Leaving the glacial valley behind, you will begin the gradual climb toward Thuli Kharka, crossing scenic ridges and alpine meadows along the way. The trail offers spectacular views of the surrounding mountains and deep valleys as you move closer toward the lower Khumbu region. As the altitude decreases, you will notice the return of vegetation and greener landscapes after many days in the high alpine terrain. Arriving at Thuli Kharka, you will enjoy a comfortable evening while preparing for the final trekking days of your expedition.</p>', 15, '2026-03-16 16:47:17', '2026-04-05 12:00:49'),
(3869, 278, '29', NULL, 'Trek from Thuli Kharka to Lukla', '2860', 'Tea House', 'B, L, & D', '<p>Your final trekking day will take you from Thuli Kharka down to Lukla, the gateway to the Everest region. The descent passes through beautiful forests, small Sherpa villages, suspension bridges, and lively mountain trails that reconnect you with civilization after weeks in remote wilderness. As you walk through these vibrant mountain communities, you will feel the contrast between expedition life and village life in the Himalayas. Upon reaching Lukla, your team will celebrate the successful completion of both the Baruntse expedition and the incredible journey through the remote valleys of eastern Nepal.</p>', 16, '2026-03-16 16:47:17', '2026-04-05 12:00:49'),
(3870, 278, '30', NULL, 'Fly from Lukla to Kathmandu', '1400', '4 Star Hotel', 'B, L, & D', '<p>Early in the morning, you will take a scenic mountain flight from Lukla back to Kathmandu. During the short but breathtaking flight, you will witness the spectacular Himalayan ranges stretching across the horizon one last time. Once you land in Kathmandu, you will transfer to your hotel where you can finally enjoy a hot shower, comfortable rest, and a relaxed city atmosphere. The rest of the day is free for you to explore the vibrant streets of Kathmandu or simply celebrate your expedition success.</p>', 17, '2026-03-16 16:47:17', '2026-04-05 12:00:49'),
(3871, 278, '31', NULL, 'Expedition Debriefing at the Department of Tourism', '1400', '4 Star Hotel', 'Breakfast', '<p>Today you will visit the Department of Tourism for the official expedition debriefing process. This is an important step for all Himalayan expeditions where climbing details, summit confirmations, and expedition reports are formally submitted. It also gives you the opportunity to reflect on the journey and officially close the expedition with your team and guides. After the formalities, you will have the rest of the day free to explore Kathmandu, visit cultural sites, or shop for souvenirs.</p>', 18, '2026-03-16 16:47:17', '2026-04-05 12:00:50'),
(3872, 278, '32', NULL, 'Final Departure', '1400', NULL, 'Breakfast', '<p>Your incredible Himalayan journey now comes to an end. Depending on your flight schedule, you will be transferred to Tribhuvan International Airport for your international departure. As you leave Nepal, you will carry unforgettable memories of the Baruntse expedition, the remote Barun Valley, and the remarkable experience of climbing above 7,000 meters in the Himalayas. The adventure may end here, but the inspiration to return to the mountains will stay with you forever.</p>', 19, '2026-03-16 16:47:17', '2026-04-05 12:00:50'),
(3873, 290, '3', NULL, 'Drive to Koto', '2600', 'Tea House', 'B, L, & D', '<p>Today you will leave Kathmandu early in the morning and begin the scenic drive toward Koto, a small village located along the famous Annapurna trekking route. The journey takes you through beautiful river valleys, terraced farmlands, traditional villages, and winding mountain roads with incredible views of the surrounding hills. As you travel deeper into the Himalayan region, you will witness the changing landscapes and the rural lifestyle of Nepal’s mountain communities. After several hours of driving, you will arrive at Koto where you will rest and prepare for the trekking portion of your expedition.</p>', 3, '2026-03-16 17:18:08', '2026-04-06 11:35:34'),
(3874, 290, '4', NULL, 'Trek to Meta', '3550', 'Tea House', 'B, L, & D', '<p>Your trekking journey officially begins today as you leave Koto and follow a remote trail toward Meta. The path leads you through dense pine and rhododendron forests, crossing wooden bridges and narrow mountain trails along the valley. As you gradually gain altitude, the scenery becomes more rugged and wild, offering your first real taste of the remote Himalayan wilderness. After a steady day of trekking, you will arrive at Meta, a peaceful high-altitude settlement surrounded by dramatic mountain landscapes.</p>', 4, '2026-03-16 17:18:08', '2026-04-06 11:35:34'),
(3875, 290, '5', NULL, 'Trek to Kyang', '3840', 'Tea House', 'B, L, & D', '<p>Today you will continue your trek deeper into the remote valleys as you head toward Kyang. The trail climbs gradually along alpine ridges and open meadows while offering spectacular views of distant snow-covered peaks. Along the way, you will walk through untouched mountain terrain where the silence and natural beauty of the Himalayas become truly noticeable. After several hours of trekking through this stunning landscape, you will reach Kyang where you will spend the night surrounded by incredible mountain scenery.</p>', 5, '2026-03-16 17:18:08', '2026-04-06 11:35:34'),
(3876, 290, '6', NULL, 'Trek to Phu Gaun', '4180', 'Tea House', 'B, L, & D', '<p>Leaving Kyang behind, you will continue trekking toward the remote village of Phu Gaun. The trail passes through rugged terrain, narrow mountain paths, and scenic valleys that highlight the raw beauty of this lesser-explored region of Nepal. As you move higher into the mountains, you will experience the peaceful atmosphere of remote Himalayan landscapes far from busy trekking routes. By the afternoon, you will arrive at Phu Gaun where you will rest and enjoy the quiet surroundings of this isolated mountain village.</p>', 6, '2026-03-16 17:18:08', '2026-04-06 14:08:59'),
(3877, 290, '7', NULL, 'Rest Day and Acclimatization', '4180', 'Tea House', 'B, L, & D', '<p>Today is scheduled as a rest and acclimatization day to help your body adjust to the increasing altitude. You will spend the day relaxing around the village while allowing your body to adapt to the thinner mountain air. Short acclimatization walks around the area may be recommended to help improve your adjustment to the altitude. This rest day plays an important role in preparing you for the higher elevations that lie ahead in the expedition.</p>', 7, '2026-03-16 17:18:09', '2026-04-06 11:35:34'),
(3878, 290, '8', NULL, 'Trek to Base Camp', '4900', 'Camp', 'B, L, & D', '<p>Today you will continue trekking toward the Base Camp, the main staging point for the climbing phase of your expedition. The trail leads through rugged alpine landscapes, glacial valleys, and rocky moraines as you approach the towering Himalayan peaks. With every step, the scenery becomes more dramatic as the massive mountains rise above you. Upon reaching base camp, you will settle into the expedition camp where the climbing preparations will begin.</p>', 8, '2026-03-16 17:18:09', '2026-04-06 11:35:34'),
(3879, 290, '9 to 25', NULL, 'Climbing Period', '7129', 'Camp', 'B, L, & D', '<p>These days are reserved for the climbing period, which includes acclimatization rotations, technical training, and the final summit push depending on weather conditions. During this time, you will gradually move between higher camps, practicing mountaineering skills such as rope techniques, glacier travel, and high-altitude climbing. The exact summit day will depend on favorable weather and the team\'s acclimatization progress. Reaching the summit will be the highlight of the expedition before descending safely back to base camp.</p>', 9, '2026-03-16 17:18:09', '2026-04-06 11:35:34'),
(3880, 290, '26', NULL, 'Trek Back to Meta', '2600', 'Tea House', 'B, L, & D', '<p>After successfully completing the climbing phase, you will begin your descent from the high mountains and trek back toward Meta. The return journey allows you to enjoy the landscapes once again, this time with the satisfaction of completing the expedition. As the altitude decreases, you will start to feel stronger and more relaxed after the demanding days in the high Himalayas. Upon reaching Meta, you will spend the evening celebrating the success of your adventure with the team.</p>', 10, '2026-03-16 17:18:09', '2026-04-06 11:35:34'),
(3881, 290, '27', NULL, 'Trek to Koto', '2600', 'Tea House', 'B, L, & D', '<p>Today you will continue descending along the familiar trail back to Koto. The trek takes you through forests, valleys, and mountain paths that gradually bring you back toward the lower regions of the Himalayas. Along the way, you will pass through beautiful landscapes and small settlements that reflect the traditional lifestyle of the mountain communities. After reaching Koto, you will rest and prepare for the drive back to Kathmandu.</p>', 11, '2026-03-16 17:18:09', '2026-04-06 11:35:34'),
(3882, 290, '28', NULL, 'Drive Back to Kathmandu', '1400', '4 Star Hotel', 'Breakfast', '<p>Today you will leave Koto and begin the long but scenic drive back to Kathmandu. The road follows winding mountain highways, river valleys, and traditional villages as you travel back toward the capital city. After days in the remote wilderness, returning to Kathmandu will feel like a completely different world. Upon arrival, you will check into your hotel and enjoy a well-deserved rest.</p>', 12, '2026-03-16 17:18:09', '2026-04-06 11:35:34'),
(3883, 290, '29', NULL, 'Free Day in Kathmandu', '1400', NULL, NULL, '<p>Today you will have a free day in Kathmandu to relax and recover after the expedition. You may choose to explore cultural landmarks, visit temples and heritage sites, or simply enjoy the lively streets of the city. Many climbers also use this time to shop for souvenirs or celebrate the successful completion of the expedition. It is a perfect opportunity to reflect on the incredible Himalayan journey you have just completed.</p>', 14, '2026-03-16 17:18:09', '2026-04-06 14:53:27'),
(3884, 290, '30', NULL, 'Departure', '1400', NULL, NULL, '<p>Your Himalayan adventure now comes to an end. Depending on your flight schedule, you will be transferred to Tribhuvan International Airport for your international departure. As you leave Nepal, you will carry unforgettable memories of your expedition, the remote mountain landscapes, and the remarkable experience of climbing in the Himalayas.</p>', 15, '2026-03-16 17:18:09', '2026-04-06 14:53:27'),
(3885, 312, '1', NULL, 'Arrive in Kathmandu', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Land in Kathmandu, meet your guide, and settle into your hotel in Thamel. The evening is yours to explore the vibrant streets, try your first dal bhat, and run final gear checks before the adventure begins.</p>', 1, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3886, 312, '2', NULL, 'Permits & Preparation Day', '1400', '4 Star Hotel', 'Breakfast', '<p>Collect your Sagarmatha National Park permit and Khumbu Pasang Lhamu Rural Municipality card. Your guide will brief you on the route, altitude safety, and what to expect at teahouses along the trail.</p>', 2, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3887, 312, '3', NULL, 'Fly from Kathmandu to Lukla, trek to Phakding', '2610', 'Tea House', 'B, L, & D', '<p>Board the iconic mountain flight into Lukla, one of the world\'s most thrilling landings, then hit the trail immediately, descending through pine forest to the riverside village of Phakding (2,610 m).</p>', 3, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3888, 312, '4', NULL, 'Walk from Phakding to Namche Bazaar', '3440', 'Tea House', 'B, L, & D', '<p>Cross suspension bridges over the roaring Dudh Koshi river, enter Sagarmatha National Park at Monjo, and tackle the steep two-hour climb up to Namche the bustling gateway to the Khumbu. Your first views of Everest may appear on the ascent.</p>', 4, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3889, 312, '5', NULL, 'Acclimatization day at Namche Bazaar', '3440', 'Tea House', 'B, L, & D', '<p>A mandatory rest day to help your body adjust to altitude. Hike up to the Everest View Hotel for your first panoramic look at Everest, Lhotse, and Ama Dablam, then spend the afternoon exploring Namche\'s cafes, bakeries, and gear shops.</p>', 5, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3890, 312, '6', NULL, 'Trek from Namche Bazaar to Tengboche', '3860', 'Tea House', 'B, L, & D', '<p>The trail rolls through rhododendron forests with Ama Dablam towering overhead at every turn. Arrive at Tengboche monastery, the spiritual heart of the Khumbu, perched on a ridge with staggering views of Everest and Nuptse.</p>', 6, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3891, 312, '7', NULL, 'Hike from Tengboche to Dingboche', '4410', 'Tea House', 'B, L, & D', '<p>Descend to Pangboche village, home to the valley\'s oldest monastery, before climbing steadily up into the open, windswept terrain of the upper Khumbu. Dingboche sits in a wide bowl surrounded by giant peaks on three sides.</p>', 7, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3892, 312, '8', NULL, 'Acclimatization day at Dingboche', '4410', 'Tea House', 'B, L, & D', '<p>Second critical acclimatization day. Hike up to the Nangkartshang ridge (5,000+ m) for sweeping views of Makalu, Cho Oyu, and Island Peak, then descend and rest. Your appetite and sleep quality here are key indicators of how your body is adapting.</p>', 8, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3893, 312, '9', NULL, 'Trek from Dingboche to Lobuche', '4940', 'Tea House', 'B, L, & D', '<p>The landscape turns raw and glacial as you pass the Thukla memorial cairns a sobering tribute to Everest climbers lost on the mountain. Lobuche is a small, exposed cluster of teahouses where the cold bites hard after dark.</p>', 9, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3894, 312, '10', NULL, 'Lobuche from Gorakshep, visit EBC', '5364', 'Tea House', 'B, L, & D', '<p>Push on to Gorakshep the last stop before Base Camp then continue the final 3 km across the rocky Khumbu glacier moraine to reach Everest Base Camp at 5,364 m. Stand at the foot of the world\'s highest mountain and take it all in before returning to Gorakshep for the night.</p>', 10, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3895, 312, '11', NULL, 'Kala Patthar sunrise, descend to Pheriche', '5545', 'Tea House', 'B, L, & D', '<p>Rise before dawn and summit Kala Patthar (5,545 m) for the most iconic direct view of Everest available to trekkers the summit glows gold at sunrise. Descend all the way to Pheriche (4,288 m) to aid recovery at lower altitude.</p>', 11, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3896, 312, '12', NULL, 'Walk from Pheriche to Tengboche', '3860', 'Tea House', 'B, L, & D', '<p>The descent always feels faster and lighter your legs are strong, your lungs are full, and the views hit differently now that you know what\'s behind you. Return to Tengboche and enjoy a well-earned rest in the shadow of the monastery.</p>', 12, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3897, 312, '13', NULL, 'Tengboche to Namche Bazaar', '3440', 'Tea House', 'B, L, & D', '<p>Retrace the trail back through the rhododendron forest and across the high ridgeline, returning to Namche for a final night in the Khumbu\'s most lively settlement. Celebrate with a hot shower, a good meal, and stories with fellow trekkers.</p>', 13, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3898, 312, '14', NULL, 'Namche Bazaar  to Lukla', '2860', 'Tea House', 'B, L, & D', '<p>One long, satisfying day back through Phakding and the lower Khumbu valleys to Lukla. The altitude drops with every step and the air grows noticeably thicker a welcome reward after two weeks at height.</p>', 14, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3899, 312, '15', NULL, 'Fly from Lukla tp Kathmandu', '1400', '4 Star Hotel', 'Farewell Dinner', '<p>Morning flight back to Kathmandu, weather permitting, with the entire Himalayan range spread below you one final time. The afternoon is free for shopping in Thamel, a massage, or a celebratory dinner with your team.</p>', 15, '2026-03-19 17:21:12', '2026-03-19 17:22:01'),
(3900, 312, '16', NULL, 'Departure', '1400', 'Breakfast', NULL, '<p>Your Everest Base Camp adventure comes to a close. Transfer to Tribhuvan International Airport for your onward flight leaving with sore legs, a full memory card, and a story you\'ll tell for the rest of your life.</p>', 16, '2026-03-19 17:21:12', '2026-03-19 17:22:46'),
(3901, 313, '1', NULL, 'Arrival in Kathmandu', '1400', '4 Star Hotel', 'Welcome Dinner', '<div><span>Namaste and a warm welcome to Kathmandu Valley, the gateway to the Himalayas. Upon your arrival at Tribhuvan International Airport, after completing your visa formalities, you will be greeted by our representative with a traditional khada at the arrival gate. You will then be comfortably transferred to your premium 4-star hotel in the heart of the city. In the evening, relax and unwind, enjoying the vibrant yet peaceful atmosphere of Kathmandu.</span></div>', 1, '2026-03-24 02:13:38', '2026-03-24 02:28:58'),
(3902, 313, '2', NULL, 'Kathmandu to Pokhara', '820', '4 Star Hotel', 'B, L, & D', '<p>After a delightful breakfast, you will travel to Pokhara either by a scenic flight or a comfortable private vehicle. The distance between Kathmandu and Pokhara is around 200 km, which would take around 4 to 6 hours to travel. As you arrive, the tranquil beauty of Phewa Lake and the stunning backdrop of Machapuchare will welcome you. Check into your luxury hotel and spend the evening enjoying lakeside dining and relaxing views. This is your perfect introduction to the Himalayan journey ahead.</p>', 2, '2026-03-24 02:28:58', '2026-03-24 02:32:40'),
(3903, 313, '3', NULL, 'Drive to Nayapul and Trek to Tikhedhunga', '1540', 'Luxury Tea House', 'B, L, & D', '<p>Today, your adventure begins with a private drive to Nayapul, followed by a gentle trek along rivers and charming villages. The trail is easy and scenic, allowing you to fully enjoy the natural surroundings. Your overnight stay will be in a comfortable, well-selected teahouse with upgraded services.</p>', 3, '2026-03-24 02:28:58', '2026-03-24 02:32:40'),
(3904, 313, '4', NULL, 'Trek to Ghorepani', '2850', 'Luxury Tea House', 'B, L, & D', '<p>Your day starts with a steady climb through beautiful rhododendron forests and traditional settlements. The famous Ulleri stone steps will challenge you, but the rewarding views make it worthwhile. Upon reaching Ghorepani, enjoy warm hospitality and comfortable lodging with stunning mountain scenery.</p>', 4, '2026-03-24 02:28:58', '2026-03-24 02:32:40'),
(3905, 313, '5', NULL, 'Poon Hill Sunrise and Trek to Tadapani', '2630', 'Luxury Tea House', 'B, L, & D', '<p>Early morning, hike to Poon Hill for a breathtaking sunrise over the Annapurna and Dhaulagiri ranges. After capturing unforgettable views, return for breakfast and continue trekking through peaceful forests to Tadapani. The trail offers a perfect mix of nature, tranquility, and scenic beauty.</p>', 5, '2026-03-24 02:28:58', '2026-03-24 02:32:40'),
(3906, 313, '6', NULL, 'Trek to Chomrong', '2170', 'Luxury Tea House', 'B, L, & D', '<p>Descend through lush forests and cross scenic suspension bridges before reaching Chomrong village. This beautiful Gurung settlement offers incredible mountain views and a glimpse into local culture. Enjoy a comfortable stay with warm hospitality and delicious meals.</p>', 6, '2026-03-24 02:28:58', '2026-03-24 02:32:40'),
(3907, 313, '7', NULL, 'Trek to Bamboo', '2310', 'Luxury Tea House', 'B, L, & D', '<p>Leaving Chomrong, you will descend and then gradually ascend through dense bamboo and rhododendron forests. The peaceful trail, filled with natural sounds, creates a calming trekking experience. Overnight stay in a well-managed teahouse with comfortable amenities.</p>', 7, '2026-03-24 02:28:58', '2026-03-24 02:32:40'),
(3908, 313, '8', NULL, 'Trek to Dovan / Deurali', '2600', 'Luxury Tea House', 'B, L, & D', '<p>Today’s trek takes you deeper into the Annapurna Sanctuary, where the landscape becomes more alpine and dramatic. You will pass waterfalls, narrow valleys, and quiet trails. Your accommodation will be carefully chosen to ensure maximum comfort in the mountains.</p>', 8, '2026-03-24 02:28:58', '2026-03-24 02:32:40'),
(3909, 313, '9', NULL, 'Trek to Machapuchare Base Camp', '3700', 'Luxury Tea House', 'B, L, & D', '<p>As you move higher, the surroundings open into breathtaking Himalayan landscapes. Walking alongside glacial rivers and rocky terrain, you’ll reach Machapuchare Base Camp. Enjoy premium mountain lodge comfort while surrounded by towering peaks.</p>', 9, '2026-03-24 02:28:58', '2026-03-24 02:32:40'),
(3910, 313, '10', NULL, 'Trek to Annapurna Base Camp', '4130', 'Luxury Tea House', 'B, L, & D', '<p>Today is the highlight of your journey as you reach Annapurna Base Camp. Surrounded by a natural amphitheater of snow-capped mountains, the experience is both peaceful and awe-inspiring. Enjoy the luxury of time, space, and unforgettable panoramic views in the heart of the Himalayas.</p>', 10, '2026-03-24 02:28:58', '2026-03-24 02:32:40'),
(3911, 313, '11', NULL, 'Trek Back to Bamboo', '2310', 'Luxury Tea House', 'B, L, & D', '<p>Wake up to a magical sunrise over the Annapurna range before beginning your descent. The return journey offers a new perspective of the landscapes you passed earlier. Relax in the comfort of your teahouse at Bamboo after a fulfilling day.</p>', 11, '2026-03-24 02:28:58', '2026-03-24 02:32:40'),
(3912, 313, '12', NULL, 'Trek to Jhinu Danda', '2170', 'Luxury Tea House', 'B, L, & D', '<p>Continue your descent through forests and villages. At Jhinu Danda, you have the option to enjoy a soothing dip in natural hot springs by the river. This relaxing experience is a perfect reward after days of trekking.</p>', 12, '2026-03-24 02:28:58', '2026-03-24 02:32:40'),
(3913, 313, '13', NULL, 'Trek to Nayapul and Drive to Pokhara', '820', '4 Star Hotel', 'B, L, & D', '<p>On your final trekking day, walk through beautiful villages and farmlands back to Nayapul. From here, enjoy a private drive back to Pokhara. Check into your luxury hotel and spend the evening celebrating your successful trek by the lakeside.</p>', 13, '2026-03-24 02:28:58', '2026-03-24 02:32:40'),
(3914, 313, '14', NULL, 'Drive from Pokhara to Kathmandu', '1400', '4 Star Hotel', 'B, L, & D', '<p>After breakfast, you will travel back to Kathmandu in a comfortable private vehicle or optional flight. Upon arrival, check into your premium hotel and enjoy your final evening in Nepal. You may explore the city, enjoy fine dining, or simply relax.</p>', 14, '2026-03-24 02:28:58', '2026-03-24 02:32:41'),
(3915, 313, '15', NULL, 'Final Departure', NULL, NULL, 'Breakfast', '<p>Your incredible journey in Nepal comes to an end today. After breakfast, our team will transfer you to Tribhuvan International Airport for your departure. You leave with unforgettable memories of the Annapurna Sanctuary and the majestic Himalayas.</p>', 15, '2026-03-24 02:28:58', '2026-03-24 02:32:41'),
(3916, 314, '1', NULL, 'Arrival in Kathmandu', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Upon arrival at Tribhuvan International Airport, you will be warmly welcomed by our experienced Sherpa team and transferred to your hotel in Kathmandu. Take this day to rest and acclimate, or stroll through Thamel’s bustling streets filled with shops, cafés, and trekking gear stores. Our team will provide a detailed briefing about the upcoming trek, ensuring that your journey starts with confidence and clarity.</p>', 1, '2026-03-24 21:33:29', '2026-03-24 21:34:19'),
(3917, 314, '2', NULL, 'Kathmandu Sightseeing and Trek Preparation', '1400', '4 Star Hotel', 'B, L, & D', '<p>Explore the spiritual and cultural treasures of Kathmandu, including Pashupatinath Temple and Boudhanath Stupa. You will also attend a trek preparation session with expert guides, who have decades of experience in the Himalayas. This day ensures that both your gear and your knowledge are ready, setting the foundation for a safe and enjoyable trekking adventure.</p>', 2, '2026-03-24 21:33:29', '2026-03-24 21:34:19'),
(3918, 314, '3', NULL, 'Drive to Besisahar and Trek to Bhulbhule', '840', 'Best Available Tea House', 'B, L, & D', '<p>Drive through scenic landscapes to Besisahar and begin your trek along the Marsyangdi River to Bhulbhule. Walking through charming villages, lush forests, and terraced farmlands, you will experience the rhythm of rural Himalayan life. Stay in a local teahouse, enjoying authentic meals prepared by local families, which adds to the cultural richness of your journey.</p>', 3, '2026-03-24 21:33:29', '2026-03-24 21:34:19'),
(3919, 314, '4', NULL, 'Bhulbhule to Jagat', '1300', 'Best Available Tea House', 'B, L, & D', '<p>Trekking from Bhulbhule to Jagat, you will cross rivers, stone bridges, and small villages, immersing yourself in the local culture. The trail gently ascends, allowing you to enjoy the scenic Himalayan backdrop while walking at a comfortable pace. Jagat is a quaint village where you will rest and prepare for the journey ahead.</p>', 4, '2026-03-24 21:33:29', '2026-03-24 21:34:19'),
(3920, 314, '5', NULL, 'Jagat to Dharapani', '1860', 'Best Available Tea House', 'B, L, & D', '<p>Continue trekking along terraced fields, pine forests, and traditional villages to reach Dharapani. The trail passes through local markets and community settlements, giving you a glimpse of daily Himalayan life. Your Sherpa guides ensure safe navigation while sharing expert knowledge about the region’s culture and natural history.</p>', 5, '2026-03-24 21:33:29', '2026-03-24 21:34:19'),
(3921, 314, '6', NULL, 'Dharapani to Chame', '2670', 'Best Available Tea House', 'B, L, & D', '<p>Trek through the dramatic landscapes of the Marsyangdi Valley, entering pine forests and passing cascading waterfalls. Chame, the district headquarters of Manang, offers breathtaking views of Annapurna II. Staying in local teahouses allows you to experience the warmth and hospitality of the Himalayan communities while keeping your journey environmentally sustainable.</p>', 6, '2026-03-24 21:33:29', '2026-03-24 21:34:19');
INSERT INTO `cl_trip_itinerary` (`id`, `trip_detail_id`, `days`, `meals`, `title`, `max_altitude`, `distance`, `duration`, `content`, `ordering`, `created_at`, `updated_at`) VALUES
(3922, 314, '7', NULL, 'Chame to Pisang', '3300', 'Best Available Tea House', 'B, L, & D', '<p>As you ascend, the trail leads through alpine terrain and offers panoramic views of Pisang Peak and Annapurna II. The villages along the way reflect centuries-old traditions, showcasing unique stone houses and Buddhist monasteries. Your guides ensure that the trek remains safe and that cultural respect is maintained at every step.</p>', 7, '2026-03-24 21:33:29', '2026-03-24 21:34:19'),
(3923, 314, '8', NULL, 'Pisang to Manang', '3500', 'Best Available Tea House', 'B, L, & D', '<p>The trek gradually rises toward Manang, passing through Braka and Ngawal villages. The route reveals spectacular mountain views, including Gangapurna and Annapurna III. Manang serves as the perfect location to rest and acclimatize, and local teahouses provide insight into traditional Tibetan-influenced culture.</p>', 8, '2026-03-24 21:33:29', '2026-03-24 21:34:19'),
(3924, 314, '9', NULL, 'Acclimatization Day in Manang', '3500', 'Best Available Tea House', 'B, L, & D', '<p>Spend the day acclimatizing with short hikes around Gangapurna Lake or Ice Lake. This day is crucial for adjusting to high altitudes and preventing altitude sickness. Your guides share knowledge about mountain ecology, local flora, and fauna, emphasizing safe and responsible trekking practices.</p>', 9, '2026-03-24 21:33:29', '2026-03-24 21:34:19'),
(3925, 314, '10', NULL, 'Manang to Yak Kharka', '400', 'Best Available Tea House', 'B, L, & D', '<p>The trek continues through alpine meadows and yak pastures. Yak Kharka is a serene settlement where you can experience traditional Himalayan herding life. Walking at this altitude offers a unique perspective of the Annapurna range and surrounding peaks.</p>', 10, '2026-03-24 21:33:29', '2026-03-24 21:34:19'),
(3926, 314, '11', NULL, 'Yak Kharka to Thorong Phedi', '4450', 'Best Available Tea House', 'B, L, & D', '<p>Ascend gradually toward Thorong Phedi, the base for the high pass. The trail becomes steeper, with glacial streams and rocky paths. Your guides ensure safe progress while monitoring altitude and weather conditions.</p>', 11, '2026-03-24 21:33:29', '2026-03-24 21:34:20'),
(3927, 314, '12', NULL, 'Thorong Phedi to Muktinath via Thorong La Pass', '5416', 'Best Available Tea House', 'B, L, & D', '<p>Start early to cross Thorong La Pass, the highest point of the trek at 5,416 m. Witness breathtaking 360-degree Himalayan panoramas. Descend carefully into the sacred Muktinath area, a unique site revered by both Hindus and Buddhists. This day combines physical challenge, spiritual significance, and awe-inspiring natural beauty.</p>', 12, '2026-03-24 21:33:29', '2026-03-24 21:34:20'),
(3928, 314, '13', NULL, 'Muktinath to Marpha', '2700', 'Best Available Tea House', 'B, L, & D', '<p>Descend through the Kali Gandaki Valley toward Marpha. The trail passes through apple orchards and charming villages, showcasing Mustang’s unique cultural and architectural heritage. Your guides highlight the local traditions, making the experience both educational and memorable.</p>', 13, '2026-03-24 21:33:29', '2026-03-24 21:34:20'),
(3929, 314, '14', NULL, 'Marpha to Tatopani', '1190', 'Best Available Tea House', 'B, L, & D', '<p>Trek downhill through terraced fields and riverside trails to reach Tatopani, famous for its natural hot springs. Take the opportunity to relax your muscles in the thermal waters, which have been cherished by local communities for generations.</p>', 14, '2026-03-24 21:33:29', '2026-03-24 21:34:20'),
(3930, 314, '15', NULL, 'Tatopani to Ghorepani', '2850', 'Best Available Tea House', 'B, L, & D', '<p>Climb through rhododendron forests and scenic villages to Ghorepani. The area is renowned for spectacular sunset and sunrise views of Annapurna and Dhaulagiri, offering photographers and trekkers alike unmatched natural beauty.</p>', 15, '2026-03-24 21:33:29', '2026-03-24 21:34:20'),
(3931, 314, '16', NULL, 'Ghorepani to Poon Hill, Trek to Nayapul, Drive to Pokhara', '3210', '4 Star Hotel', 'B, L, & D', '<p>Wake early for a short hike to Poon Hill to witness a breathtaking Himalayan sunrise. After descending to Nayapul, drive to Pokhara for relaxation by Phewa Lake. This day blends natural beauty, accomplishment, and comfort after the long trek.</p>', 16, '2026-03-24 21:33:29', '2026-03-24 21:34:20'),
(3932, 314, '17', NULL, 'Drive Back to Kathmandu and Departure', NULL, NULL, NULL, '<p>Drive or fly back to Kathmandu for final shopping, sightseeing, or rest. Depart from Tribhuvan International Airport with memories of the Annapurna Circuit etched forever in your mind.</p>', 17, '2026-03-24 21:33:29', '2026-03-24 21:34:20'),
(3933, 315, '1', NULL, 'Arrival in Kathmandu', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Namaste and welcome to Kathmandu. You arrive at Tribhuvan International Airport and transfer to your 4 star hotel. After settling in, you can explore the nearby streets of Thamel, check your gear, and meet your guide for a short trek briefing. This is a relaxed day to prepare for the adventure ahead.</p>', 1, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3934, 315, '2', NULL, 'Drive from Kathmandu to Syabrubesi', '1550', 'Best Available Tea House', 'B, L, & D', '<p>You begin your journey with a scenic drive out of Kathmandu Valley. The road follows rivers, terraced fields, and hills, offering glimpses of rural Nepal. As you approach Syabrubesi, the landscape becomes more rugged, signaling the start of your Himalayan adventure.</p>', 2, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3935, 315, '3', NULL, 'Trek to Lama Hotel', '2380', 'Best Available Tea House', 'B, L, & D', '<p>You start trekking along the Langtang River, crossing suspension bridges and walking through lush forests of bamboo and rhododendron. The trail gradually ascends, and if you\'re lucky, you might spot wildlife like langurs or red pandas.</p>', 3, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3936, 315, '4', NULL, 'Trek to Langtang Village', '3430', 'Best Available Tea House', 'B, L, & D', '<p>Today, the valley opens up as you climb higher. You pass small settlements and yak pastures before reaching Langtang Village. This area was rebuilt after the 2015 earthquake, and visiting here gives you a deeper connection to the resilience of local communities.</p>', 4, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3937, 315, '5', NULL, 'Trek to Kyanjin Gompa', '3870', 'Best Available Tea House', 'B, L, & D', '<p>The trail becomes more scenic as you move into alpine terrain. You walk past prayer wheels, mani walls, and mountain views before reaching Kyanjin Gompa. After lunch, you can explore the monastery or visit the local cheese factory.</p>', 5, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3938, 315, '6', NULL, 'Acclimatization Day – Explore Kyanjin Ri / Tserko Ri', '4985', 'Best Available Tea House', 'B, L, & D', '<p>You spend the day acclimatizing while exploring nearby viewpoints. A hike to Kyanjin Ri or Tserko Ri rewards you with panoramic views of Langtang Lirung and the surrounding peaks. This day helps your body adjust to altitude while offering some of the best views of the trek.</p>', 6, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3939, 315, '7', NULL, 'Trek back to Lama Hotel', '2470', 'Best Available Tea House', 'B, L, & D', '<p>You retrace your steps down the valley, enjoying a different perspective of the landscape. Descending helps your body recover as you prepare for the next phase toward Gosainkunda.</p>', 7, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3940, 315, '8', NULL, 'Trek to Thulo Syabru', '2230', 'Best Available Tea House', 'B, L, & D', '<p>You leave the main Langtang trail and head toward Thulo Syabru. The route involves a mix of descents and climbs through forests and traditional villages. This section introduces you to the Tamang culture and lifestyle.</p>', 8, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3941, 315, '9', NULL, 'Trek to Sing Gompa', '3330', 'Best Available Tea House', 'B, L, & D', '<p>You climb steadily through dense forests and reach Sing Gompa, a peaceful settlement known for its monastery and yak cheese production. The mountain views begin to open up again as you gain altitude.</p>', 9, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3942, 315, '10', NULL, 'Trek to Gosainkunda Lake', '4380', 'Best Available Tea House', 'B, L, & D', '<p>This is one of the most spiritual days of the trek. You ascend above the tree line and reach the sacred Gosainkunda Lake. Surrounded by mountains, the lake holds deep religious significance for both Hindus and Buddhists.</p>', 10, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3943, 315, '11', NULL, 'Cross Lauribina Pass and trek down to Ghopte', '4610', 'Best Available Tea House', 'B, L, & D', '<p>This is the most challenging day of the trek. You cross Lauribina Pass early in the morning to avoid strong winds. The views from the top are breathtaking. After crossing, you descend toward Ghopte through rugged terrain.</p>', 11, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3944, 315, '12', NULL, 'Trek to Kutumsang', '2470', 'Best Available Tea House', 'B, L, & D', '<p>You continue descending through forests and traditional villages. The trail becomes quieter as you enter the Helambu region, offering a peaceful trekking experience.</p>', 12, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3945, 315, '13', NULL, 'Trek to Sundarijal & Drive to Kathmandu', '1400', '4 Star Hotel', 'B, L, & D', '<p>You complete your trek by walking to Sundarijal, located on the outskirts of Kathmandu. From here, you drive back to the city and enjoy a well-deserved rest.</p>', 13, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3946, 315, '14', NULL, 'Final Departure', '1400', NULL, NULL, '<p>Your journey comes to an end. Depending on your flight schedule, you transfer to the airport or extend your stay in Nepal.</p>', 14, '2026-03-24 22:24:08', '2026-03-24 22:25:35'),
(3947, 316, '1', NULL, 'Arrival in Kathmandu', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Your adventure begins with your arrival in Kathmandu, Nepal’s vibrant capital. After landing at Tribhuvan International Airport, you will be welcomed by your trekking team. This day is dedicated to rest, permit arrangements, and preparation. Your guide will review the trek details, provide a packing checklist, and brief you on restricted area rules for the Manaslu region. The evening is ideal for exploring Thamel, enjoying local cuisine, and soaking in the unique Kathmandu valley atmosphere.</p>', 1, '2026-03-27 01:09:55', '2026-03-27 01:11:51'),
(3948, 316, '2', NULL, 'Kathmandu to Soti Khola (Drive)', '700', 'Best available tea House', 'B, L, & D', '<p>After breakfast, you embark on a scenic drive from Kathmandu to Soti Khola, passing through beautiful landscapes, terraced fields, and rivers. This is the starting point of your trek. Soti Khola, a small riverside village, offers your first taste of rural Nepalese life, surrounded by lush greenery and the distant Himalayas. The trail along the Budhi Gandaki River sets the tone for the adventure ahead.</p>', 2, '2026-03-27 01:09:55', '2026-03-27 01:11:51'),
(3949, 316, '3', NULL, 'Soti Khola to Machha Khola', '880', 'Best available tea House', 'B, L, & D', '<p>From Soti Khola, the trail gently ascends through forests and farmland, crossing suspension bridges over clear mountain streams. You’ll pass small villages and enjoy views of terraced fields carved into the hillsides. Machha Khola, meaning “Fish River,” is a peaceful village ideal for your first night on the trail, offering teahouse accommodation and home-cooked Nepali meals.</p>', 3, '2026-03-27 01:09:55', '2026-03-27 01:11:51'),
(3950, 316, '4', NULL, 'Machha Khola to Jagat', '1340', 'Best available tea House', 'B, L, & D', '<p>The trek continues along the Budhi Gandaki River, through lush forests and traditional villages. Jagat marks the entry point to the Manaslu Restricted Area, requiring a check of your permits. The village offers basic teahouses and is your introduction to the remote Himalayan culture, with stone houses and local markets.</p>', 4, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3951, 316, '5', NULL, 'Jagat to Deng', '1860', 'Best available tea House', 'B, L, & D', '<p>From Jagat, the trail climbs steadily through bamboo forests, rivers, and terraced fields, crossing suspension bridges and small streams. You pass through Chhekampar village before reaching Deng, a larger settlement with a mix of Tibetan-influenced and local Nepali culture. Deng is an important acclimatization point before higher altitudes, with warm teahouses and stunning views of the surrounding hills.</p>', 5, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3952, 316, '6', NULL, 'Deng to Namrung', '2630', 'Best available tea House', 'B, L, & D', '<p>Leaving Deng, you trek higher into the alpine landscape, with rhododendron forests giving way to barren slopes. Namrung is a picturesque village dominated by traditional stone houses and Buddhist monasteries. Here, you experience daily life of the Nubri people, with prayer flags fluttering in the wind and locals welcoming trekkers with their unique hospitality.</p>', 6, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3953, 316, '7', NULL, 'Namrung to Samagaun', '3530', 'Best available tea House', 'B, L, & D', '<p>The trail continues to Samagaun, the main gateway to the Manaslu base region. Along the way, you will notice the terrain becoming more rugged and the air thinner. Samagaun is a culturally rich village where you can visit monasteries, mani walls, and chortens. The village offers views of Manaslu, Himalchuli, and Ngadi Chuli, creating a perfect backdrop for photography and acclimatization.</p>', 7, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3954, 316, '8', NULL, 'Acclimatization Day in Samagaun', '3530', 'Best available tea House', 'B, L, & D', '<p>An acclimatization day is crucial at this altitude. You can take a short trek to Pungyen Gompa or nearby ridges, enjoying panoramic views of the Manaslu range. This day allows your body to adjust to high altitude while immersing yourself in the culture of the Nubri community, observing their unique customs, prayer ceremonies, and local lifestyle.</p>', 8, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3955, 316, '9', NULL, 'Samagaun to Samdo', '3860', 'Best available tea House', 'B, L, & D', '<p>From Samagaun, the trail gradually ascends into the high Himalayas, leading to Samdo. The landscape becomes increasingly alpine, with sparse vegetation and dramatic mountain views. Samdo is a remote Tibetan-influenced settlement, offering teahouses and a small monastery. This village serves as the final stop before crossing the Larkya La Pass, allowing trekkers to rest and acclimatize further.</p>', 9, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3956, 316, '10', NULL, 'Samdo to Dharmasala (Larkya Phedi)', '4460', 'Best available tea House', 'B, L, & D', '<p>The trek from Samdo to Dharmasala, also called Larkya Phedi, takes you higher into alpine terrain. You pass moraines, frozen streams, and snow-covered slopes as you approach the base of the pass. Dharmasala is a temporary campsite-style settlement with teahouses for trekkers preparing for the high-altitude crossing. The views of Manaslu and the surrounding peaks are spectacular, and this is your last night before the challenging pass.</p>', 10, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3957, 316, '11', NULL, 'Dharmasala to Bimtang via Larkya La Pass', '5160', 'Best available tea House', 'B, L, & D', '<p>This is the highlight of the trek. You start early, trekking to Larkya La Pass at 5,160 meters. The climb is steep and requires determination, but reaching the summit rewards you with panoramic views of the Manaslu range, Himlung Himal, and Ganesh Himal. After crossing the pass, the trail descends toward Bimtang, a charming village in the Marsyangdi valley region, where you can rest and celebrate the accomplishment of crossing one of the most scenic passes in Nepal.</p>', 11, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3958, 316, '12', NULL, 'Bimtang to Tilje', '1540', 'Best available tea House', 'B, L, & D', '<p>Descending from Bimtang, the trail passes through rhododendron forests, terraced fields, and rivers, gradually returning to lower altitudes. Tilje is a peaceful village with teahouses and a chance to observe local agriculture and village life after weeks in remote high-altitude settlements.</p>', 12, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3959, 316, '13', NULL, 'Tilje to Dharapani', '1340', 'Best available tea House', 'B, L, & D', '<p>The trek continues along gentle trails leading to Dharapani, crossing streams and small settlements along the way. You are now back in the lower Himalayan region, where the vegetation is lush and the villages are more populated. Dharapani offers comfortable lodges and a welcoming environment for trekkers after days of high-altitude trekking.</p>', 13, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3960, 316, '14', NULL, 'Dharapani to Jagat', '1340', 'Best available tea House', 'B, L, & D', '<p>From Dharapani, you descend further along the Budhi Gandaki River, passing through terraced fields and traditional villages until reaching Jagat. This marks the completion of the Manaslu Circuit loop. You can reflect on your journey through remote mountain villages, high passes, and culturally rich settlements while preparing for the return journey.</p>', 14, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3961, 316, '15', NULL, 'Jagat to Arughat', '610', 'Best available tea House', 'B, L, & D', '<p>The trek ends as you continue descending to Arughat, where the road connects back to Kathmandu. Along the way, enjoy the lush forests, rivers, and local communities, saying farewell to the serene landscapes that define the Manaslu region.</p>', 15, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3962, 316, '16', NULL, 'Arughat to Kathmandu (Drive)', '1400', '4 Star Hotel', 'Breakfast', '<p>You take a scenic drive from Arughat back to Kathmandu, crossing hills, rivers, and valleys along the route. Upon arrival, you can enjoy the comforts of the city, revisit cultural landmarks, or simply relax after an intense trekking adventure.</p>', 16, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3963, 316, '17', NULL, 'Free Day in Kathmandu', '1400', '4 Star Hotel', 'Breakfast', '<p>This day is reserved for rest, sightseeing, or shopping in Kathmandu. You can visit Pashupatinath Temple, Boudhanath Stupa, or Patan Durbar Square, experiencing Nepalese culture in the urban setting. It’s also a good opportunity to organize photos, share your trekking experiences, and enjoy local cuisine one last time.</p>', 17, '2026-03-27 01:09:56', '2026-03-27 01:11:51'),
(3964, 316, '18', NULL, 'Departure', '1400', NULL, NULL, '<p>On the final day, you will be transferred to Tribhuvan International Airport for your departure. Your 18-day journey through the Manaslu Circuit Trek concludes, leaving you with unforgettable memories of mountains, culture, and remote Himalayan adventures.</p>', 18, '2026-03-27 01:09:56', '2026-03-27 01:13:51'),
(3965, 317, '1', NULL, 'Arrival in Kathmandu', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Your journey begins with your arrival in Kathmandu, the vibrant capital of Nepal. Upon landing at Tribhuvan International Airport, you will be welcomed and transferred to your hotel. This day is mainly for rest and preparation. You’ll meet your trekking guide, review the itinerary, and arrange necessary permits for the restricted Kanchenjunga region. If time allows, you can explore the lively streets of Thamel for last-minute gear shopping.</p>', 1, '2026-03-27 01:53:31', '2026-03-27 01:58:18'),
(3966, 317, '2', NULL, 'Fly to Bhadrapur and Drive to Taplejung', '1820', 'Best available tea House', 'B, L, & D', '<p>After an early breakfast, you take a scenic flight to Bhadrapur in eastern Nepal. The flight offers views of the Himalayan range on a clear day. From Bhadrapur, you begin a long but rewarding drive to Taplejung, passing through beautiful Ilam tea gardens, rolling hills, and rural settlements. The journey gives you your first glimpse of eastern Nepal’s natural beauty and cultural diversity.</p>', 2, '2026-03-27 01:53:31', '2026-03-27 01:58:18'),
(3967, 317, '3', NULL, 'Trek from Taplejung to Mitlung', '921', 'Best available tea House', 'B, L, & D', '<p>Your trekking adventure officially begins today. The trail descends through terraced fields and traditional villages, giving you a feel of rural life. You follow the Tamor River, crossing suspension bridges and walking through lush forests. The day is relatively easy, allowing your body to adjust as you reach Mitlung.</p>', 3, '2026-03-27 01:53:31', '2026-03-27 01:58:18'),
(3968, 317, '4', NULL, 'Trek from Mitlung to Chirwa', '1270', 'Best available tea House', 'B, L, & D', '<p>You continue along the river valley, passing cardamom farms, small settlements, and dense subtropical forests. The trail involves gradual ascents and descents, with occasional river crossings. You’ll interact with local communities and experience their simple lifestyle before reaching Chirwa.</p>', 4, '2026-03-27 01:53:31', '2026-03-27 01:58:18'),
(3969, 317, '5', NULL, 'Trek from Chirwa to Sekathum', '1660', 'Best available tea House', 'B, L, & D', '<p>Today’s trek becomes slightly more challenging. You walk along narrow trails carved into hillsides, cross several suspension bridges, and navigate landslide-prone areas. The route passes through dense forests and remote villages before arriving at Sekathum, located at the junction of two rivers.</p>', 5, '2026-03-27 01:53:31', '2026-03-27 01:58:18'),
(3970, 317, '6', NULL, 'Trek from Sekathum to Amjilosa', '2510', 'Best available tea House', 'B, L, & D', '<p>You enter a more remote section of the trek. The trail climbs steadily through bamboo forests and steep rocky paths. Waterfalls, cliffs, and river views make the journey scenic yet adventurous. You’ll notice fewer settlements as you reach Amjilosa, a small Tibetan-influenced village.</p>', 6, '2026-03-27 01:53:31', '2026-03-27 01:58:18'),
(3971, 317, '7', NULL, 'Trek from Amjilosa to Gyabla', '2730', 'Best available tea House', 'B, L, & D', '<p>The trail ascends through dense forests filled with rhododendron, bamboo, and oak trees. This region is known for wildlife sightings, including red pandas if you’re lucky. As you gain altitude, the landscape becomes cooler and more alpine. You reach Gyabla, a peaceful village surrounded by forest.</p>', 7, '2026-03-27 01:53:31', '2026-03-27 01:58:18'),
(3972, 317, '8', NULL, 'Trek from Gyabla to Ghunsa', '3475', 'Best available tea House', 'B, L, & D', '<p>Today’s trek is one of the most beautiful sections. You walk through forests, cross rivers, and pass mani walls and chortens, reflecting Tibetan Buddhist culture. As you approach Ghunsa, the scenery opens up with stunning mountain views. Ghunsa is a large Sherpa village and an important acclimatization stop.</p>', 8, '2026-03-27 01:53:31', '2026-03-27 01:58:18'),
(3973, 317, '9', NULL, 'Acclimatization Day in Ghunsa', '3475', 'Best available tea House', 'B, L, & D', '<p>To adjust to the increasing altitude, you spend a rest day in Ghunsa. You can explore the village, visit monasteries, or take a short hike to nearby viewpoints. Proper acclimatization is crucial before heading to higher elevations.</p>', 9, '2026-03-27 01:53:31', '2026-03-27 01:58:18'),
(3974, 317, '10', NULL, 'Trek from Ghunsa to Kambachen', '4050', 'Best available tea House', 'B, L, & D', '<p>You continue north along a glacial valley with incredible mountain views. The trail passes through alpine meadows and rocky terrain. You’ll see towering peaks, including Mount Kanchenjunga, becoming more prominent as you gain altitude.</p>', 10, '2026-03-27 01:53:31', '2026-03-27 01:58:18'),
(3975, 317, '11', NULL, 'Trek from Kambachen to Lhonak', '4780', 'Best available tea House', 'B, L, & D', '<p>The landscape becomes more rugged and barren as you approach higher elevations. You walk along moraines and glacial rivers with panoramic Himalayan views. The air gets thinner, and the environment feels truly remote as you reach Lhonak.</p>', 11, '2026-03-27 01:53:31', '2026-03-27 01:58:18'),
(3976, 317, '12', NULL, 'Trek to Pangpema (North Base Camp) and Return to Lhonak', '5143', 'Best available tea House', 'B, L, & D', '<p>This is one of the highlight days of the trek. You hike to Pangpema, the North Base Camp of Mount Kanchenjunga. The views of the massive हिमालय range and glaciers are breathtaking. After spending time at the base camp, you return to Lhonak.</p>', 12, '2026-03-27 01:53:31', '2026-03-27 01:58:18'),
(3977, 317, '13', NULL, 'Trek from Lhonak to Ghunsa', '3475', 'Best available tea House', 'B, L, & D', '<p>You descend back through Kambachen to Ghunsa. The return journey feels easier as you lose altitude, and you can enjoy the landscapes from a different perspective.</p>', 13, '2026-03-27 01:53:32', '2026-03-27 01:58:18'),
(3978, 317, '14', NULL, 'Trek from Ghunsa to Sele La Camp', '4290', 'Best available tea House', 'B, L, & D', '<p>You take a different route toward the southern side of the circuit. The trail climbs steeply through forests and alpine terrain. You reach Sele La Camp, a remote high-altitude campsite.</p>', 14, '2026-03-27 01:53:32', '2026-03-27 01:58:18'),
(3979, 317, '15', NULL, 'Trek from Sele La to Cheram via High Passes', '3870', 'Best available tea House', 'B, L, & D', '<p>This is one of the most challenging days. You cross high passes like Sele La, Mirgin La, and Sinion La, each offering spectacular mountain views. After crossing these passes, you descend to Cheram.</p>', 15, '2026-03-27 01:53:32', '2026-03-27 01:58:18'),
(3980, 317, '16', NULL, 'Trek from Cheram to Ramche', '4580', 'Best available tea House', 'B, L, & D', '<p>The trail gradually ascends along a river valley with stunning views of peaks and glaciers. You reach Ramche, a high-altitude settlement near the South Base Camp.</p>', 16, '2026-03-27 01:53:32', '2026-03-27 01:58:18'),
(3981, 317, '17', NULL, 'Trek to Oktang (South Base Camp) and Return to Cheram', '4730', 'Best available tea House', 'B, L, & D', '<p>You hike to Oktang, the South Base Camp of Mount Kanchenjunga. The panoramic views of Kanchenjunga and the surrounding peaks are incredible. After exploring, you return to Cheram.</p>', 17, '2026-03-27 01:53:32', '2026-03-27 01:58:18'),
(3982, 317, '18', NULL, 'Trek from Cheram to Tortong', '2995', 'Best available tea House', 'B, L, & D', '<p>You descend through rhododendron forests and alpine landscapes. The trail becomes greener as you lose altitude, and the air feels warmer.</p>', 18, '2026-03-27 01:53:32', '2026-03-27 01:58:18'),
(3983, 317, '19', NULL, 'Trek from Tortong to Yamphudin', '2080', 'Best available tea House', 'B, L, & D', '<p>The trail continues through forests, rivers, and traditional villages. You experience a mix of cultural and natural beauty as you reach Yamphudin.</p>', 19, '2026-03-27 01:53:32', '2026-03-27 01:58:18'),
(3984, 317, '20', NULL, 'Drive to Bhadrapur and Fly back to Kathmandu', '1400', '4 Star Hotel', 'Breakfast', '<p>You take a long drive from the Yamphudin/Taplejung region to Bhadrapur and then fly back to Kathmandu. Upon arrival, you can relax or celebrate the successful completion of your incredible Kanchenjunga Circuit Trek.</p>', 20, '2026-03-27 01:53:32', '2026-03-27 01:58:18'),
(3985, 318, '1', NULL, 'Arrival in Kathmandu', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Arrive at Tribhuvan International Airport in Kathmandu. Meet your guide and team, transfer to your hotel, and attend a pre-trek briefing. Use this day to relax, check your gear, and prepare for the upcoming journey into the Langtang region.</p>', 1, '2026-04-01 02:05:48', '2026-04-01 02:09:12'),
(3986, 318, '2', NULL, 'Drive to Syabru Bensi', '1470', 'Guest House', 'B, L, & D', '<p>Embark on a scenic drive from Kathmandu to Syabru Bensi. The journey passes through terraced fields, rivers, and foothills, offering your first glimpses of the Himalayas. Overnight in a guesthouse and attend a briefing on trekking and acclimatization.</p>', 2, '2026-04-01 02:05:48', '2026-04-01 02:09:12'),
(3987, 318, '3', NULL, 'Trek to Lama Hotel', '2380', 'Guest House', 'B, L, & D', '<p>The trek begins gently along forested trails. Pass small villages, suspension bridges, and pine forests while enjoying views of Langtang valley peaks. Overnight at a guesthouse in Lama Hotel.</p>', 3, '2026-04-01 02:05:48', '2026-04-01 02:09:12'),
(3988, 318, '4', NULL, 'Trek to Langtang Village', '3430', 'Guest House', 'B, L, & D', '<p>Gradually ascend into Langtang valley, trekking through rhododendron and pine forests and crossing glacial streams. Arrive at Langtang village, where stunning views of Langtang Lirung (7,246 m) greet you. Explore local Tamang culture before overnighting at a guesthouse.</p>', 4, '2026-04-01 02:05:48', '2026-04-01 02:09:12'),
(3989, 318, '5', NULL, 'Trek to Kyanjin Gompa', '3870', 'Guest House', 'B, L, & D', '<p>The trail rises steadily to Kyanjin Gompa, a historic monastery settlement at the base of glaciers. Enjoy panoramic views of Langtang and Ganesh Himal ranges. Explore the monastery, interact with locals, and prepare for upcoming acclimatization hikes.</p>', 5, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(3990, 318, '6', NULL, 'Acclimatization Hike to Kyanjin Ri', '4773', 'Guest House', 'B, L, & D', '<p>Spend the day acclimatizing with a hike to Kyanjin Ri, offering breathtaking vistas of glaciers, Langtang Lirung, and Dorje Lakpa. Familiarize yourself with technical climbing techniques under the guidance of your Sherpa team.</p>', 6, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(3991, 318, '7', NULL, 'Rest and Preparation at Kyanjin Gompa', '4773', 'Guest House', 'B, L, & D', '<p>Rest day at Kyanjin Gompa to recover and adjust to altitude. Optional short hikes around the valley and glacier viewpoints help strengthen endurance and prepare you for higher elevations.</p>', 7, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(3992, 318, '8', NULL, 'Technical Skills and Rope Practice at Kyanjin Gompa', '3870', 'Guest House', 'B, L, & D', '<p>Dedicate this day to practicing rope techniques, ice climbing basics, and glacier travel skills. Your guide ensures everyone is ready for the technical sections of Langshisha Ri.</p>', 8, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(3993, 318, '9', NULL, 'Rest and Acclimatization at Kyanjin Gompa', '3870', 'Guest House', 'B, L, & D', '<p>Another acclimatization day to consolidate altitude adaptation. Optional hikes to nearby glaciers and viewpoints ensure you are well-prepared for the climb ahead.</p>', 9, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(3994, 318, '10', NULL, 'Trek to Langshisha Kharka', '4400', 'Tented Camp', 'B, L, & D', '<p>Depart Kyanjin Gompa and trek to Langshisha Kharka, a remote alpine meadow. The trail passes moraines, glacial streams, and rugged terrain. Camp overnight in tents under the shadow of Langshisha Ri.</p>', 10, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(3995, 318, '11', NULL, 'Trek to Langshisha Base Camp', '4800', 'Tented Camp', 'B, L, & D', '<p>Ascend further, navigating rocky paths and moraines to reach Base Camp. Settle into tents and prepare for technical climbing. Enjoy the stunning alpine scenery surrounding the peak.</p>', 11, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(3996, 318, '12', NULL, 'Rest and Acclimatization at Base Camp', '4800', 'Tented Camp', 'B, L, & D', '<p>Rest day at Base Camp to recover from the trek and adjust to higher altitude. Practice final climbing techniques and organize gear for the ascent.</p>', 12, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(3997, 318, '13', NULL, 'Ascent to Langshisha High Camp', '5300', 'Tented Camp', 'B, L, & D', '<p>Begin the technical climb to High Camp, navigating glaciers and snow slopes. This is a challenging section requiring crampons and ropes. Enjoy sunset views of the Himalayan giants from High Camp.</p>', 13, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(3998, 318, '14', NULL, 'Summit Langshisha Ri and Return to Base Camp', '6427', 'Tented Camp', 'B, L, & D', '<p>Summit day begins early. Tackle steep snow and ice slopes to reach the peak. Enjoy panoramic views of Langtang Lirung, Shishapangma, Dorje Lakpa, and Ganesh Himal. Descend safely to Base Camp for rest.</p>', 14, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(3999, 318, '15', NULL, 'Trek Back to Langshisha Kharka', '4400', 'Tented Camp', 'B, L, & D', '<p>Descend from Base Camp to Langshisha Kharka. Enjoy the alpine landscape one last time before returning to Kyanjin Gompa. Overnight in tents.</p>', 15, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(4000, 318, '16', NULL, 'Trek Back to Kyanjin Gompa', '3870', 'Guest House', 'B, L, & D', '<p>Continue the descent through the valley, retracing your steps to Kyanjin Gompa. Overnight at a guesthouse and celebrate the successful summit.</p>', 16, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(4001, 318, '17', NULL, 'Trek to Langtang Village', '3430', 'Guest House', 'B, L, & D', '<p>Descend further through forests and streams to Langtang village. Take time to appreciate the scenic valley and local villages. Overnight at a guesthouse.</p>', 17, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(4002, 318, '18', NULL, 'Trek to Lama Hotel (', '2380', 'Guest House', 'B, L, & D', '<p>Continue trekking down the valley to Lama Hotel. Enjoy the serene Himalayan environment and relax in a guesthouse for the night.</p>', 18, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(4003, 318, '19', NULL, 'Trek to Syabru Bensi', '1470', 'Guest House', NULL, NULL, 19, '2026-04-01 02:05:49', '2026-04-01 02:05:49'),
(4004, 318, '20', NULL, 'Drive Back to Kathmandu', '1400', NULL, NULL, '<p>Drive back to Kathmandu. Depending on your flight schedule, you can explore the city briefly before departing or transfer directly to the airport. Your Langshisha Ri adventure concludes with unforgettable memories of climbing, Himalayan landscapes, and cultural experiences.</p>', 20, '2026-04-01 02:05:49', '2026-04-01 02:09:12'),
(4005, 319, '1', NULL, 'Arrival in Kathmandu', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Welcome to Kathmandu, the vibrant gateway to the Himalayas. Upon arrival, our team greets you at the airport and transfers you to your hotel. You can relax after your journey or explore the lively streets of Thamel. In the evening, we brief you about the expedition, check your gear, and prepare for the adventure ahead.</p>', 1, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4006, 319, '2', NULL, 'Drive from Kathmandu to Soti Khola', '800', 'Tea House', 'B, L, & D', '<p>Your journey begins with a scenic drive from Kathmandu to Soti Khola. The road winds through hills, rivers, and terraced farmland, offering your first glimpse of rural Nepal. As you leave the city behind, the landscape becomes more rugged and remote, setting the tone for the trek.</p>', 2, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4007, 319, '3', NULL, 'Trek from Soti Khola to Machha Khola', '869', 'Tea House', 'B, L, & D', '<p>Today, you officially begin trekking along the Budhi Gandaki River. The trail passes through forests, small settlements, and suspension bridges. You experience a mix of gentle climbs and descents while enjoying the sound of the river flowing beside you.</p>', 3, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4008, 319, '4', NULL, 'Trek from Machha Khola to Jagat', '1340', 'Tea House', 'B, L, & D', '<p>The trail becomes more dramatic as you cross narrow paths, waterfalls, and traditional villages. You enter the restricted Manaslu Region at Jagat, where permits are checked. The cultural shift begins here, with stronger Tibetan influences visible in architecture and lifestyle.</p>', 4, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4009, 319, '5', NULL, 'Trek from Jagat to Deng', '2300', 'Tea House', 'B, L, & D', '<p>You continue through beautiful villages like Philim and Ekle Bhatti, surrounded by terraced fields and forests. The trail gradually climbs higher, and you begin to feel the change in altitude. The scenery becomes more alpine as you approach Deng.</p>', 5, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4010, 319, '6', NULL, 'Trek from Deng to Namrung', '2700', 'Tea House', 'B, L, & D', '<p>Today’s trek takes you deeper into the Himalayan wilderness. You cross several suspension bridges and walk through dense forests before reaching Namrung. From here, you start seeing stunning views of snow-capped peaks, including glimpses of Mount Manaslu.</p>', 6, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4011, 319, '7', NULL, 'Trek from Namrung to Samagaun (', '3520', 'Tea House', 'B, L, & D', '<p>This is one of the most scenic days of the trek. You pass through traditional villages like Lho and Shyala, with incredible mountain views all around. As you arrive in Samagaun, you find yourself at the foot of Mount Manaslu, surrounded by dramatic alpine landscapes.</p>', 7, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4012, 319, '8', NULL, 'Acclimatization Day at Samagaun – Hike to Manaslu Base Camp', '4900', 'Tea House', 'B, L, & D', '<p>To help your body adjust to the altitude, you take a day hike to Manaslu Base Camp. The trail offers breathtaking glacier views and a closer look at the towering peaks. This is a challenging but rewarding acclimatization hike that prepares you for higher elevations.</p>', 8, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4013, 319, '9', NULL, 'Trek from Samagaun to Samdo', '3875', 'Tea House', 'B, L, & D', '<p>A shorter trekking day allows for gradual acclimatization. You walk through open landscapes with fewer trees and more rugged terrain. Samdo is a small Tibetan-influenced village close to the border, offering a unique cultural experience.</p>', 9, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4014, 319, '10', NULL, 'Rest and Acclimatization Day at Samdo', '3875', 'Tea House', 'B, L, & D', '<p>Today, you rest and explore the surrounding area. You can take short hikes to viewpoints or simply relax and enjoy the peaceful mountain environment. Proper acclimatization here is key for a successful climb.</p>', 10, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4015, 319, '11', NULL, 'Trek from Samdo to Dharamsala / Larke Phedi', '4460', 'Tea House', 'B, L, & D', '<p>You gradually ascend toward Dharamsala, also known as Larke Phedi, the base for crossing Larkya La Pass. The terrain becomes more rugged and exposed, with stunning views of glaciers and surrounding peaks.</p>', 11, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4016, 319, '12', NULL, 'Trek from Dharamsala to Larke Peak Base Camp', '5135', 'Camp', 'B, L, & D', '<p>Today, you leave the main trekking trail and head toward Larke Peak Base Camp. The route involves glacier walking and rocky terrain, marking the beginning of your climbing journey. You set up camp and prepare for the summit push.</p>', 12, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4017, 319, '13 to 14', NULL, 'Climbing Period and Preparation', '6249', 'Camp', 'B, L, & D', '<p>These days are dedicated to climbing training and summit attempts. Your guides provide instruction on using ropes, crampons, and ice axes. Depending on weather conditions, you make your summit push and enjoy incredible Himalayan views from the top.</p>', 13, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4018, 319, '15', NULL, 'Reserve Day (Contingency for Weather)', '5135', 'Camp', 'B, L, & D', '<p>This extra day ensures flexibility in case of bad weather or delays during the climb. It increases your chances of a successful and safe summit.</p>', 14, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4019, 319, '16', NULL, 'Trek from Larke Peak Base Camp to Bimtang', '3800', 'Tea House', 'B, L, & D', '<p>After completing your climb, you descend toward Bimtang. The trail offers stunning views and a sense of accomplishment as you leave the high alpine zone behind.</p>', 15, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4020, 319, '17', NULL, 'Trek from Bimtang to Dharapani', '1963', 'Tea House', 'B, L, & D', '<p>You continue descending through forests and villages, rejoining greener landscapes. The air becomes thicker, and the journey feels more relaxed as you approach Dharapani.</p>', 16, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4021, 319, '18', NULL, 'Drive from Dharapani to Kathmandu', '1400', '4 Star Hotel', 'B, L, & D', '<p>You drive back to Kathmandu, enjoying the final views of the hills and rivers. In the evening, you can celebrate your successful adventure.</p>', 17, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4022, 319, '19', NULL, 'Departure', '1400', NULL, NULL, '<p>Your incredible Larke Peak climbing journey comes to an end. We transfer you to the airport for your departure, leaving you with unforgettable memories of the Himalayas.</p>', 18, '2026-04-01 02:49:10', '2026-04-01 02:51:22'),
(4023, 320, '1', NULL, 'Arrival in Kathmandu', '1300', '4 Star Hotel', 'Welcome Dinner', '<p>Your Himalayan adventure begins with your arrival in Kathmandu, the vibrant capital of Nepal. After clearing customs, you will be transferred to your hotel. Take the rest of the day to relax and recover from your journey. If time permits, explore the historic streets of Thamel, enjoy local cuisine, or visit nearby cultural landmarks to start immersing yourself in Nepalese culture.</p>', 1, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4024, 320, '2', NULL, 'Preparation Day in Kathmandu', '1300', '4 Star Hotel', 'Breakfast', '<p>This day is dedicated to expedition preparation. You will meet your climbing guide and team to review the detailed plan, check equipment, and organize necessary climbing permits. Guides will also provide safety briefings, explain altitude acclimatization strategies, and answer all your questions. This is an essential step to ensure a smooth and safe journey ahead.</p>', 2, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4025, 320, '3', NULL, 'Fly to Lukla and Trek to Phakding', '2610', 'Tea House', 'B, L, & D', '<p>After an early morning flight to Lukla, you’ll step onto one of the most scenic trails in the world. The trek to Phakding follows the Dudh Koshi River, weaving through pine forests, terraced fields, and small Sherpa villages. The trail is relatively gentle, allowing you to adjust to higher altitudes while enjoying views of surrounding peaks and suspension bridges over rushing rivers. Overnight stay in Phakding.</p>', 3, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4026, 320, '4', NULL, 'Trek to Namche Bazaar', '3441', 'Tea House', 'B, L, & D', '<p>Today, the trail becomes more challenging as you climb towards Namche Bazaar, the bustling Sherpa town and gateway to the Everest region. Cross multiple suspension bridges and navigate through steep sections, all while being rewarded with incredible views of peaks like Thamserku and Kusum Kanguru. Namche is also a great place to experience local markets, try Sherpa tea, and see traditional architecture.</p>', 4, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4027, 320, '5', NULL, 'Acclimatization Day – Hiking Around Khumjung', '3790', 'Tea House', 'B, L, & D', '<p>Acclimatization is key to a successful climb. Today, you hike to nearby villages such as Khumjung and Kunde. Visit monasteries, interact with local Sherpas, and enjoy breathtaking Himalayan vistas. Hiking at a slightly higher altitude and returning to Namche helps your body adapt to thinner air, reducing the risk of altitude sickness.</p>', 5, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4028, 320, '6', NULL, 'Trek to Thame', '3820', 'Tea House', 'B, L, & D', '<p>The trek continues to Thame, a quiet and traditional Sherpa village. The trail passes through dense forests, rocky ridges, and small rivers. Thame is culturally rich, home to the Thame Monastery and several ancient mani walls. This village has a tranquil atmosphere, making it an excellent spot to rest and absorb the serene Himalayan environment.</p>', 6, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4029, 320, '7', NULL, 'Trek to Lungdeng', '4500', 'Tea House', 'B, L, & D', '<p>Today’s trek takes you higher into alpine terrain, gaining significant altitude as you reach Lungdeng. The path becomes more rugged, with narrow trails and rocky sections. You will start seeing expansive glacier views and towering Himalayan peaks close up. An overnight stay at Lungdeng prepares you for the challenging passes ahead.</p>', 7, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4030, 320, '8', NULL, 'Cross Renjola Pass to Gokyo Lake', '4790', 'Tea House', 'B, L, & D', '<p>One of the most spectacular days of the trek. You will cross the Renjola Pass (5,415 m / 17,765 ft), a steep and exhilarating climb that offers panoramic views of Cho Oyu, Everest, and Makalu. After the pass, you descend to the beautiful Gokyo Lake, a turquoise gem surrounded by snow-capped peaks. This long day combines technical trekking with some of the region’s most iconic landscapes.</p>', 8, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4031, 320, '9', NULL, 'Rest Day or Hike to 5th Gokyo Lake', '4790', 'Tea House', 'B, L, & D', '<p>Spend a day resting at Gokyo Lake to acclimatize, or hike to the 5th Gokyo Lake. The optional hike provides unparalleled views of the surrounding Himalayan giants and the Ngozumpa Glacier, Nepal’s largest glacier. It’s also a perfect opportunity for photography and enjoying the serene alpine environment.</p>', 9, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4032, 320, '10', NULL, 'Morning Ascent to Gokyo Peak and Descent to Thagnag', '5360', 'Tea House', 'B, L, & D', '<p>Start early for the climb to Gokyo Peak. From the summit, marvel at 360-degree views of Everest, Cho Oyu, and surrounding peaks. After this incredible experience, descend to Thagnag, a small remote settlement that serves as a staging point for the Nirekha Peak Base Camp.</p>', 10, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4033, 320, '11', NULL, 'Trek to Nirekha Base Camp', '5340', 'Tea House', 'B, L, & D', '<p>Today, the trek leads to Nirekha Base Camp, the launch point for your summit attempt. The trail includes snowfields, glacial moraines, and increasingly rugged terrain. This is where the climbing truly begins, and the peak comes into view, allowing you to plan your route for the days ahead.</p>', 11, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4034, 320, '12', NULL, 'Rest Day at Nirekha Base Camp', '5340', 'Camp', 'B, L, & D', '<p>A vital day for acclimatization. Rest, hydrate, and allow your body to adjust to high altitude. Guides may organize short hikes near the base camp to help with acclimatization while familiarizing you with your climbing equipment.</p>', 12, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4035, 320, '13', NULL, 'Trek to High Camp', '5930', 'Camp', 'B, L, & D', '<p>Ascend to high camp, situated just below the summit ridge. The climb is steeper and more technical, with snow and ice slopes. Guides set up tents, fix ropes, and provide a briefing on summit strategy. Overnight stay at high camp prepares you for the summit push.</p>', 13, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4036, 320, '14', NULL, 'Summit Nirekha Peak and Return to Base Camp', '6159', 'Camp', 'B, L, & D', '<p>Summit day! Begin in the early hours to tackle the final ascent. Using crampons and ice axes, navigate glaciers, steep snow slopes, and rope-assisted sections to reach the top. From the summit, enjoy panoramic views of Everest, Lhotse, Cho Oyu, and Makalu. After the achievement, descend carefully to base camp for rest and celebration.</p>', 14, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4037, 320, '15', NULL, 'Reserve Day', '5930', 'Camp', 'B, L, & D', '<p>A buffer day for weather delays or unforeseen circumstances during the summit attempt. It ensures safety and allows flexibility in the expedition schedule.</p>', 15, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4038, 320, '16', NULL, 'Base Camp to Dzongla via Cho-La Pass', '5467', 'Tea House', 'B, L, & D', '<p>Trek through the challenging Cho-La Pass (5,467 m / 17,936 ft), a high and scenic route with breathtaking glacier views. Descend to Dzongla, enjoying the vast Himalayan landscapes and serene valleys along the way.</p>', 16, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4039, 320, '17', NULL, 'Trek to Tengboche', '3810', 'Tea House', 'B, L, & D', '<p>Descend through rhododendron forests and terraced slopes to reach Tengboche, home to the famous Tengboche Monastery. The spiritual atmosphere, prayer flags, and Himalayan vistas make this an unforgettable day of trekking.</p>', 17, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4040, 320, '18', NULL, 'Trek to Namche Bazaar', '3441', 'Tea House', 'B, L, & D', '<p>Retrace your path back to Namche Bazaar. Enjoy the vibrant town, shop for souvenirs, and celebrate the progress of your expedition. Overnight stay allows rest before the final leg of the trek.</p>', 18, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4041, 320, '19', NULL, 'Trek to Lukla', '2810', 'Tea House', 'B, L, & D', '<p>Final trekking day to Lukla. The descent offers a different perspective of the mountains and rivers you passed on the way up. Overnight in Lukla to relax and prepare for your flight back.</p>', 19, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4042, 320, '20', NULL, 'Fly to Kathmandu', '1400', '4 Star Hotel', 'Breakfast', '<p>Take a scenic mountain flight back to Kathmandu or Manthali. Enjoy aerial views of the Himalayas and reflect on the incredible journey.</p>', 20, '2026-04-02 01:48:42', '2026-04-02 01:50:36');
INSERT INTO `cl_trip_itinerary` (`id`, `trip_detail_id`, `days`, `meals`, `title`, `max_altitude`, `distance`, `duration`, `content`, `ordering`, `created_at`, `updated_at`) VALUES
(4043, 320, '21', NULL, 'Departure', '1400', NULL, NULL, '<p>After breakfast, you will be transferred to the airport for your onward journey, carrying unforgettable memories of your Nirekha Peak expedition. We hope your adventure was everything you dreamed of and more! If you enjoyed your experience, we would greatly appreciate it if you could share your feedback on TripAdvisor. Your reviews help fellow travelers plan their Himalayan adventures and allow us to continue providing exceptional climbing experiences. Thank you for being part of this unforgettable journey!</p>', 21, '2026-04-02 01:48:42', '2026-04-02 01:50:36'),
(4044, 321, '1', NULL, 'Arrival in Kathmandu', '1400', '4 Star Hotel', 'Welcome Dinner', '<p>Your adventure begins the moment you land at Tribhuvan International Airport in Kathmandu, where the Summit 8000 team warmly welcomes you. You will be transferred to a comfortable hotel in Thamel, the heart of Kathmandu’s vibrant streets. In the evening, your guides will conduct a detailed briefing, check your climbing gear, and walk you through the expedition plan. This is your first taste of Nepal’s rich Himalayan culture, full of bustling markets, colorful streets, and an energetic local vibe. It’s the perfect start to a journey that combines adventure with authentic cultural experiences.</p>', 1, '2026-04-02 03:12:33', '2026-04-02 03:14:05'),
(4045, 321, '2', NULL, 'Drive Kathmandu to Syabrubesi', '1550', 'Tea House', 'B, L, & D', '<p>After breakfast, we begin a scenic drive to Syabrubesi, a gateway to the Langtang region. The journey passes along the Trishuli River, with breathtaking Himalayan foothills on the horizon and terraced fields lining the valley. Syabrubesi is a small, authentic village where time feels slower and the local Tamang culture is visible in every corner. Upon arrival, you settle into a local teahouse and enjoy the serenity of this remote Himalayan valley, a quiet contrast to Kathmandu’s busy streets.</p>', 2, '2026-04-02 03:12:33', '2026-04-02 03:14:05'),
(4046, 321, '3', NULL, 'Trek Syabrubesi to Lama Hotel', '2380', 'Tea House', 'B, L, & D', '<p>The trek begins gently along the Langtang River, passing lush rhododendron and bamboo forests, dotted with sparkling streams and waterfalls. Every step brings new scenic views of the surrounding hills and distant snow-capped peaks. After about 5–6 hours of trekking over 13 km, you reach Lama Hotel, a peaceful stop surrounded by Himalayan forests. The combination of fresh mountain air and natural beauty makes this first trekking day both exhilarating and calming.</p>', 3, '2026-04-02 03:12:33', '2026-04-02 03:14:05'),
(4047, 321, '4', NULL, 'Trek Lama Hotel to Langtang Village', '3430', 'Tea House', 'B, L, & D', '<p>Today, the trail gradually ascends through yak pastures and small settlements, giving you your first taste of authentic Himalayan village life. Langtang Village is famous for its traditional stone houses, monasteries, and friendly locals who warmly welcome trekkers. You can explore the village monastery and interact with villagers, gaining insight into local customs and lifestyle. Surrounded by the serene beauty of Langtang’s snow-capped peaks, this day blends cultural immersion with scenic trekking.</p>', 4, '2026-04-02 03:12:33', '2026-04-02 03:14:05'),
(4048, 321, '5', NULL, 'Trek Langtang Village to Kyanjin Gompa', '3870', 'Tea House', 'B, L, & D', '<p>The trail becomes more alpine, passing rolling meadows, moraine landscapes, and small streams. Kyanjin Gompa sits in a remote and breathtaking valley, with panoramic views of towering peaks like Langtang Lirung. The village is serene and ideal for rest after the day’s climb. You can also take a short hike to nearby viewpoints to enjoy scenic vistas and immerse yourself in the surrounding Himalayan wilderness. This day combines adventure with peace, offering an unforgettable high-altitude experience.</p>', 5, '2026-04-02 03:12:34', '2026-04-02 03:14:05'),
(4049, 321, '6', NULL, 'Acclimatization Day at Kyanjin Gompa', '3870', 'Tea House', 'B, L, & D', '<p>To safely prepare for the higher ascent, today is an acclimatization day. You can hike to Kyanjin Ri (4,773m) or Tserko Ri, enjoying breathtaking views of the surrounding glaciers and peaks. Your guides will provide basic mountaineering training, introducing rope techniques and safety measures. This day is not just about physical preparation, it’s a chance to connect emotionally with the remote and raw beauty of the Himalayas.</p>', 6, '2026-04-02 03:12:34', '2026-04-02 03:14:05'),
(4050, 321, '7', NULL, 'Trek Kyanjin Gompa to Yubra Himal Base Camp', '4800', 'Camp', 'B, L, & D', '<p>The trail leads into increasingly remote alpine terrain, where fewer trekkers venture. The landscape becomes rugged yet beautiful, with glaciers and snow-capped peaks forming a majestic backdrop. After trekking approximately 8 km in 5–6 hours, you reach Yubra Himal Base Camp, nestled in a scenic valley. The Base Camp feels truly secluded, allowing you to experience the authentic wilderness of the high Himalayas. The sense of isolation and raw nature at this altitude is both humbling and inspiring.</p>', 7, '2026-04-02 03:12:34', '2026-04-02 03:14:05'),
(4051, 321, '8', NULL, 'Acclimatization & Training at Base Camp', '4800', 'Camp', 'B, L, & D', '<p>Today is a rest and preparation day. At Base Camp, Our guides teach essential climbing techniques, including crampon use, rope work, and ice axe handling. Equipment is checked and organized for the ascent to High Camp. Beyond training, you can relax and soak in the breathtaking views of the surrounding glaciers and peaks. This day balances safety, learning, and the emotional thrill of being deep in the remote Himalayas.</p>', 8, '2026-04-02 03:12:34', '2026-04-02 03:14:05'),
(4052, 321, '9', NULL, 'Trek Base Camp to High Camp', '5400', 'Camp', 'B, L, & D', '<p>The ascent to High Camp involves steeper terrain and sections of glacier walking, providing a true taste of high-altitude adventure. The trail winds through rugged, scenic alpine landscapes, with quiet valleys and striking peaks all around. After 4–5 hours of trekking over 5 km, you arrive at High Camp. Here, the serenity of the remote mountains and the crisp, thin air prepares you mentally and physically for the summit push. An early dinner and rest ensure you are ready for the big climb.</p>', 9, '2026-04-02 03:12:34', '2026-04-02 03:14:05'),
(4053, 321, '10', NULL, 'Summit Yubra Himal & Return to Base Camp', '6035', 'Camp', 'B, L, & D', '<p>The summit day begins in the early pre-dawn hours. The climb is non-technical but requires stamina, careful pacing, and determination. As you reach the summit at 6,035 meters, the surrounding breathtaking Himalayan panorama unfolds: Langtang Lirung, Ganesh Himal, and countless snow-capped peaks. The feeling of accomplishment, combined with the remote and scenic surroundings, is emotionally unforgettable. After celebrating the achievement, you carefully descend back to Base Camp, carrying the joy and pride of a life-changing adventure.</p>', 10, '2026-04-02 03:12:34', '2026-04-02 03:14:05'),
(4054, 321, '11', NULL, 'Contingency Day', '5400', 'Tea House', 'B, L, & D', '<p>This extra day is reserved for any weather delays or summit attempts that need to be rescheduled. Safety is the priority, and having this flexibility ensures a stress-free and secure expedition. The day also allows you to rest while enjoying the remote and peaceful alpine environment.</p>', 11, '2026-04-02 03:12:34', '2026-04-02 03:14:05'),
(4055, 321, '12', NULL, 'Trek Base Camp to Kyanjin Gompa', '3870', 'Tea House', 'B, L, & D', '<p>We descend through alpine meadows and moraine trails, retracing steps through scenic Himalayan terrain. Returning to Kyanjin Gompa gives time for reflection on the summit experience and the breathtaking landscapes you’ve crossed. The village is welcoming and peaceful, perfect for a night of rest.</p>', 12, '2026-04-02 03:12:34', '2026-04-02 03:14:06'),
(4056, 321, '13', NULL, 'Trek Kyanjin Gompa to Lama Hotel', '2380', 'Tea House', 'B, L, & D', '<p>The descent continues gently through forests and small settlements. Trekking along these trails allows you to enjoy the changing scenery as the mountains give way to green hills. Lama Hotel provides a comfortable stopover and a chance to relax in warmer surroundings after the high-altitude adventure.</p>', 13, '2026-04-02 03:12:34', '2026-04-02 03:14:06'),
(4057, 321, '14', NULL, 'Trek Lama Hotel to Syabrubesi', '1550', 'Tea House', 'B, L, & D', '<p>On the final trekking day, you follow riverside trails surrounded by forests and scenic landscapes. Celebrate the end of your trekking journey with local tea or snacks and enjoy the peaceful atmosphere of this remote Himalayan valley before returning to Kathmandu.</p>', 14, '2026-04-02 03:12:34', '2026-04-02 03:14:06'),
(4058, 321, '15', NULL, 'Drive Syabrubesi to Kathmandu', '1400', '4 Star Hotel', 'Farewell Dinner', '<p>The drive back to Kathmandu is filled with panoramic Himalayan views. In the evening, We will host a farewell dinner, celebrating your successful expedition. It’s a time to share stories, relive the climb, and reflect on the emotional and adventurous journey you’ve just completed.</p>', 15, '2026-04-02 03:12:34', '2026-04-02 03:14:06'),
(4059, 321, '16', NULL, 'Departure from Kathmandu', '1400', NULL, 'Breakfast', '<p>After breakfast, you are transferred to Tribhuvan International Airport for your onward flight. You leave with unforgettable memories of an authentic, remote, and breathtaking Himalayan adventure, carrying the satisfaction of having climbed Yubra Himal Peak with expert guidance and care.</p>', 16, '2026-04-02 03:12:34', '2026-04-02 03:14:06');
