INSERT INTO `trip_reviews` (`id`, `trip_id`, `trip_title`, `full_name`, `title`, `country`, `email`, `contact`, `rating`, `image`, `message`, `status`, `created_at`, `updated_at`) VALUES
(132, 285, 'Dhampus Peak Climbing', 'Know About Destinations', 'The Perfect Himalayan Adventure', NULL, 'dhirendrakumarrmukhiya@gmail.com', NULL, 5, NULL, 'Dhampus Peak Expeditions offers an unforgettable trekking experience in the Annapurna region. \r\n\r\nThe team is professional, friendly, and deeply knowledgeable about the mountains, making every step of the journey safe and enjoyable. The trek itself is spectacular, with panoramic views of Annapurna, Machhapuchhre, and Dhaulagiri, and a perfect mix of cultural encounters in local villages. Logistics from accommodation to meals and guides are handled smoothly, letting trekkers focus entirely on the adventure. Whether you’re a beginner or an experienced trekker, Dhampus Peak Expeditions makes climbing Dhampus Peak a memorable and rewarding experience.', 1, '2026-02-27 02:34:51', '2026-03-13 01:53:14'),
(133, 282, 'Mount Everest Expedition', 'Lars Thorne', 'Everest Magic!', NULL, 'Larsthorne@gmail.com', NULL, 5, NULL, 'Absolutely loved my Everest expedition! The guides were amazing, the views were unreal, and every step was an adventure. Safe, fun, and unforgettable highly recommend! ✨', 1, '2026-03-13 19:56:02', '2026-03-13 19:58:04'),
(134, 296, 'Mera Peak Climbing', 'Astrid Moore', 'The Ultimate Everest Expert', NULL, 'Astridmoore@gmail.com', NULL, 5, NULL, 'If you want a safe and unforgettable Everest expedition, Sherpas is the brand to follow! Every service they provide from guides to logistics is top-notch. Professional, caring, and reliable highly recommend them for your adventure of a lifetime!', 1, '2026-03-13 19:57:44', '2026-03-13 19:58:05'),
(135, 315, 'Langtang Gosainkunda Trek - 14 Days', 'James Blonde', 'Best Moment of my life', NULL, 'jamesblong@gmail.com', NULL, 5, NULL, 'The Langtang Gosaikunda trek was honestly amazing peaceful trails, stunning mountain views, and the lakes were just magical. Crossing Lauribina Pass was tough but totally worth it. Less crowded and full of raw beauty loved every bit of it.', 1, '2026-03-24 22:48:14', '2026-03-24 22:48:33'),
(136, 315, 'Langtang Gosainkunda Trek - 14 Days', 'Kate', 'Incredible Journey of my life', NULL, 'kate@gmail.com', NULL, 5, NULL, 'The trail was stunning, from green forests to alpine lakes, with Gosainkunda lake as a highlight. Our guide Pemba Sherpawas amazing knowledgeable, encouraging, and made the trek effortless and safe.', 1, '2026-03-24 22:50:14', '2026-03-24 22:50:22');
